'use client'

import { useState } from 'react'
import Link from 'next/link'
import { usePathname } from 'next/navigation'
import {
  Home, UserCheck, Users, Bell, FileText, MessageSquare,
  CalendarDays, MapPin, ClipboardList, Settings, Package,
  ChevronLeft, ChevronRight, ChevronDown, Menu, X, LogOut, Megaphone,
  AlertCircle, SlidersHorizontal, ArrowRight, BarChart3, Building2, Camera, ShoppingBag, Wallet, ShoppingCart, Store, Car, ClipboardCheck
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'

type NavItem = {
  label: string
  href: string
  icon: React.ReactNode
  children?: { label: string; href: string; icon: React.ReactNode }[]
}

type NavSectionTyped = {
  title: string
  items: NavItem[]
}

export default function AdminSidebar({
  condoName,
  userName,
  role,
  isSuperAdmin,
}: {
  condoName: string
  userName: string
  role: string
  isSuperAdmin: boolean
}) {
  const pathname = usePathname()
  const router = useRouter()
  const supabase = createClient()
  const [collapsed, setCollapsed] = useState(false)
  const [mobileOpen, setMobileOpen] = useState(false)
  const [expandedMenus, setExpandedMenus] = useState<Record<string, boolean>>({})

  const toggleSubmenu = (label: string) => {
    setExpandedMenus(prev => ({ ...prev, [label]: !prev[label] }))
  }

  const sections: NavSectionTyped[] = [
    {
      title: 'Geral',
      items: [
        { label: 'Dashboard',  href: '/admin',           icon: <Home size={18} /> },
        { label: 'Aprovações', href: '/admin/aprovacoes', icon: <UserCheck size={18} /> },
        { label: 'Moradores',  href: '/admin/moradores',  icon: <Users size={18} /> },
      ],
    },
    {
      title: 'Comunicação',
      items: [
        { label: 'Avisos',       href: '/admin/avisos',       icon: <Bell size={18} /> },
        { label: 'Fale Conosco', href: '/admin/fale-conosco', icon: <MessageSquare size={18} /> },
        { label: 'Ocorrências',  href: '/admin/ocorrencias',  icon: <AlertCircle size={18} /> },
        { label: 'Enquetes',     href: '/admin/enquetes',     icon: <BarChart3 size={18} /> },
        { label: 'Álbum de Fotos', href: '/admin/album-fotos', icon: <Camera size={18} /> },
      ],
    },
    {
      title: 'Gestão',
      items: [
        { label: 'Encomendas do Cond.', href: '/admin/encomendas', icon: <Package size={18} /> },
        { label: 'Autorização Visitante', href: '/condo/autorizar-visitante-portaria', icon: <UserCheck size={18} /> },
        { label: 'Documentos',      href: '/admin/documentos',      icon: <FileText size={18} /> },
        { label: 'Contratos',       href: '/admin/contratos',       icon: <FileText size={18} /> },
        { label: 'Áreas Comuns',    href: '/admin/areas-comuns',    icon: <MapPin size={18} /> },
        { label: 'Reservas',        href: '/admin/reservas',        icon: <CalendarDays size={18} /> },
        { label: 'Registro Turno',  href: '/admin/registro-turno',  icon: <ClipboardList size={18} /> },
        { label: 'Estrutura',       href: '/admin/estrutura',       icon: <Building2 size={18} /> },
        { label: 'Classificados',   href: '/admin/classificados',   icon: <ShoppingBag size={18} /> },
        { label: 'Vistorias',       href: '/admin/vistorias',       icon: <ClipboardCheck size={18} /> },
      ],
    },
    {
      title: 'Configuração',
      items: [
        { label: 'Configurar Acesso', href: '/admin/configurar-acesso', icon: <Settings size={18} /> },
        { label: 'Configurar Ordem',  href: '/admin/configurar-ordem',  icon: <SlidersHorizontal size={18} /> },
        ...(isSuperAdmin
          ? [
              { label: 'Push Universal', href: '/admin/push-universal', icon: <Megaphone size={18} /> },
            ]
          : []),
      ],
    },
    ...(isSuperAdmin
      ? [
          {
            title: 'Empresas Parceiras',
            items: [
              { label: 'Propaganda', href: '/admin/propaganda', icon: <ShoppingBag size={18} /> },
              { label: 'Meu Bolso', href: '/admin/dinglo', icon: <Wallet size={18} /> },
              {
                label: 'Lista Inteligente',
                href: '/admin/lista-inteligente',
                icon: <ShoppingCart size={18} />,
                children: [
                  { label: 'B2B Mercados', href: '/admin/lista-b2b', icon: <Store size={18} /> },
                  { label: 'Analytics', href: '/admin/lista-analytics', icon: <BarChart3 size={18} /> },
                ],
              },
              { label: 'Garagem', href: '/admin/garagem', icon: <Car size={18} /> },
              { label: 'Checklist', href: '/admin/checklist', icon: <ClipboardCheck size={18} /> },
            ] as NavItem[],
          },
        ]
      : []),
  ]

  async function handleLogout() {
    await supabase.auth.signOut()
    router.push('/login')
  }

  const sidebarContent = (
    <div className="flex flex-col h-full bg-[#111827] text-white">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-5 border-b border-white/10">
        <div className={`flex items-center gap-3 overflow-hidden transition-all duration-300 ${collapsed ? 'w-0 opacity-0' : 'w-full opacity-100'}`}>
          <div className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 overflow-hidden">
            <img src="/logo.png" alt="Condomeet" className="w-9 h-9 object-cover" />
          </div>
          <div className="min-w-0">
            <p className="font-bold text-sm truncate">{condoName}</p>
            <p className="text-xs text-white/40 truncate">Painel Admin</p>
          </div>
        </div>
        <button
          onClick={() => setCollapsed(!collapsed)}
          className="p-1.5 rounded-lg hover:bg-white/10 transition-colors flex-shrink-0 hidden lg:flex"
        >
          {collapsed ? <ChevronRight size={16} /> : <ChevronLeft size={16} />}
        </button>
      </div>

      {/* User info */}
      {!collapsed && (
        <div className="px-4 py-3 border-b border-white/5">
          <p className="text-sm font-medium text-white/80 truncate">{userName}</p>
          <span className="inline-block mt-1 text-[10px] uppercase tracking-wider font-bold bg-[#FC5931]/20 text-[#FC5931] px-2 py-0.5 rounded-full">
            {role}
          </span>
        </div>
      )}

      {/* Nav sections */}
      <nav className="flex-1 overflow-y-auto py-3 space-y-4">
        {sections.map(section => (
          <div key={section.title}>
            {!collapsed && (
              <p className="px-5 mb-1.5 text-[10px] uppercase tracking-[0.12em] font-bold text-white/30">
                {section.title}
              </p>
            )}
            <div className="space-y-0.5 px-2">
              {section.items.map(item => {
                const isActive = pathname === item.href
                const hasChildren = item.children && item.children.length > 0
                const isChildActive = hasChildren && item.children!.some(c => pathname === c.href)
                const isExpanded = expandedMenus[item.label] || isChildActive

                return (
                  <div key={item.href}>
                    {/* Parent item */}
                    <div className="flex items-center">
                      <Link
                        href={item.href}
                        onClick={() => setMobileOpen(false)}
                        title={collapsed ? item.label : undefined}
                        className={`flex-1 flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-150 ${
                          isActive
                            ? 'bg-[#FC5931] text-white shadow-lg shadow-[#FC5931]/20'
                            : 'text-white/60 hover:bg-white/[0.06] hover:text-white'
                        }`}
                      >
                        <span className="shrink-0">{item.icon}</span>
                        {!collapsed && <span className="truncate">{item.label}</span>}
                      </Link>
                      {hasChildren && !collapsed && (
                        <button
                          onClick={() => toggleSubmenu(item.label)}
                          className="p-1.5 rounded-lg hover:bg-white/10 text-white/40 hover:text-white transition-colors"
                          title={`Expandir ${item.label}`}
                        >
                          <ChevronDown
                            size={14}
                            className={`transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`}
                          />
                        </button>
                      )}
                    </div>

                    {/* Children sub-items */}
                    {hasChildren && isExpanded && !collapsed && (
                      <div className="ml-5 mt-0.5 space-y-0.5 border-l border-white/10 pl-2">
                        {item.children!.map(child => {
                          const isChildItemActive = pathname === child.href
                          return (
                            <Link
                              key={child.href}
                              href={child.href}
                              onClick={() => setMobileOpen(false)}
                              className={`flex items-center gap-2.5 px-3 py-2 rounded-lg text-xs font-medium transition-all duration-150 ${
                                isChildItemActive
                                  ? 'bg-[#FC5931]/80 text-white'
                                  : 'text-white/50 hover:bg-white/[0.06] hover:text-white'
                              }`}
                            >
                              <span className="shrink-0">{child.icon}</span>
                              <span className="truncate">{child.label}</span>
                            </Link>
                          )
                        })}
                      </div>
                    )}
                  </div>
                )
              })}
            </div>
          </div>
        ))}
      </nav>

      {/* Footer */}
      <div className="border-t border-white/10 px-2 py-2 space-y-0.5">
        <Link
          href="/condo"
          className="flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm text-white/50 hover:bg-white/[0.06] hover:text-white transition-all"
        >
          <ArrowRight size={18} className="flex-shrink-0" />
          {!collapsed && <span>Portal do Morador</span>}
        </Link>
        <button
          onClick={handleLogout}
          className="flex items-center gap-3 w-full px-3 py-2.5 rounded-xl text-sm text-white/40 hover:bg-white/[0.06] hover:text-white transition-all"
        >
          <LogOut size={18} className="flex-shrink-0" />
          {!collapsed && <span>Sair</span>}
        </button>
      </div>
    </div>
  )

  return (
    <>
      {/* Mobile menu button */}
      <button
        className="lg:hidden fixed top-4 left-4 z-50 p-2.5 bg-[#111827] text-white rounded-xl shadow-lg shadow-black/20"
        onClick={() => setMobileOpen(!mobileOpen)}
      >
        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
      </button>

      {/* Mobile overlay */}
      {mobileOpen && (
        <div className="lg:hidden fixed inset-0 bg-black/50 z-40 backdrop-blur-sm" onClick={() => setMobileOpen(false)} />
      )}

      {/* Mobile sidebar */}
      <div className={`lg:hidden fixed top-0 left-0 h-full w-64 z-50 transition-transform duration-300 ${mobileOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        {sidebarContent}
      </div>

      {/* Desktop sidebar */}
      <div className={`hidden lg:flex flex-col h-screen sticky top-0 transition-all duration-300 ${collapsed ? 'w-[68px]' : 'w-60'} flex-shrink-0`}>
        {sidebarContent}
      </div>
    </>
  )
}

'use client'

import { useState, useRef, useEffect } from 'react'
import { Camera, Trash2, Pencil, X, Send, Image, Heart, MessageCircle, Eye, ChevronLeft, ChevronRight } from 'lucide-react'

type TipoEvento = 'evento' | 'manutencao' | 'reuniao' | 'outros'

interface AlbumImage {
  id: string
  imagem_url: string
  ordem: number
}

interface Album {
  id: string
  titulo: string
  descricao: string
  tipo_evento: TipoEvento
  data_evento: string | null
  created_at: string
  imagens: AlbumImage[]
  reacoes_count: number
  comentarios_count: number
  visualizacoes_count: number
}

interface Props {
  condominioId: string
  albums: Album[]
}

const TIPO_LABELS: Record<TipoEvento, string> = {
  evento: 'Evento',
  manutencao: 'Manutenção',
  reuniao: 'Reunião',
  outros: 'Outros',
}

const TIPO_COLORS: Record<TipoEvento, string> = {
  evento: 'bg-blue-100 text-blue-700',
  manutencao: 'bg-amber-100 text-amber-700',
  reuniao: 'bg-purple-100 text-purple-700',
  outros: 'bg-gray-100 text-gray-700',
}

export default function AlbumFotosAdminClient({ condominioId, albums: initial }: Props) {
  const [albums, setAlbums] = useState<Album[]>(initial)
  const [titulo, setTitulo] = useState('')
  const [descricao, setDescricao] = useState('')
  const [tipoEvento, setTipoEvento] = useState<TipoEvento>('evento')
  const [dataEvento, setDataEvento] = useState('')
  const [files, setFiles] = useState<File[]>([])
  const [previews, setPreviews] = useState<string[]>([])
  const [sending, setSending] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)

  // Sync albums when server props change (after router.refresh)
  useEffect(() => {
    setAlbums(initial)
  }, [initial])

  // Edit state
  const [editingId, setEditingId] = useState<string | null>(null)
  const [editTitulo, setEditTitulo] = useState('')
  const [editDescricao, setEditDescricao] = useState('')
  const [editTipoEvento, setEditTipoEvento] = useState<TipoEvento>('evento')
  const [editDataEvento, setEditDataEvento] = useState('')
  const [editRemovedImageIds, setEditRemovedImageIds] = useState<string[]>([])
  const [editNewFiles, setEditNewFiles] = useState<File[]>([])
  const [editNewPreviews, setEditNewPreviews] = useState<string[]>([])
  const editFileInputRef = useRef<HTMLInputElement>(null)

  // Carousel state
  const [carouselIndex, setCarouselIndex] = useState<Record<string, number>>({})

  function handleFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    const selected = Array.from(e.target.files ?? [])
    if (files.length + selected.length > 5) {
      setError('Máximo de 5 fotos por álbum')
      return
    }
    setFiles(prev => [...prev, ...selected])
    const newPreviews = selected.map(f => URL.createObjectURL(f))
    setPreviews(prev => [...prev, ...newPreviews])
    setError(null)
  }

  function removeFile(index: number) {
    setFiles(prev => prev.filter((_, i) => i !== index))
    setPreviews(prev => {
      URL.revokeObjectURL(prev[index])
      return prev.filter((_, i) => i !== index)
    })
  }

  async function handleCreate() {
    if (!titulo.trim()) { setError('Informe o título do álbum'); return }
    if (files.length === 0) { setError('Adicione pelo menos uma foto'); return }

    setSending(true)
    setError(null)

    const formData = new FormData()
    formData.append('titulo', titulo.trim())
    formData.append('descricao', descricao.trim())
    formData.append('tipo_evento', tipoEvento)
    formData.append('data_evento', dataEvento)
    formData.append('condominio_id', condominioId)
    files.forEach(f => formData.append('fotos', f))

    const res = await fetch('/api/album-fotos', { method: 'POST', body: formData })
    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Erro ao criar álbum')
      setSending(false)
      return
    }

    // Reset form & refresh
    setTitulo('')
    setDescricao('')
    setTipoEvento('evento')
    setDataEvento('')
    setFiles([])
    previews.forEach(p => URL.revokeObjectURL(p))
    setPreviews([])
    setSending(false)

    // Force full page reload to get fresh data from server
    window.location.reload()
  }

  async function handleDelete(id: string) {
    if (!confirm('Excluir este álbum e todas as fotos?')) return
    const res = await fetch(`/api/album-fotos?id=${id}`, { method: 'DELETE' })
    if (res.ok) setAlbums(albums.filter(a => a.id !== id))
  }

  function startEdit(album: Album) {
    setEditingId(album.id)
    setEditTitulo(album.titulo)
    setEditDescricao(album.descricao)
    setEditTipoEvento(album.tipo_evento)
    setEditDataEvento(album.data_evento ?? '')
    setEditRemovedImageIds([])
    setEditNewFiles([])
    setEditNewPreviews([])
  }

  function cancelEdit() {
    setEditingId(null)
    editNewPreviews.forEach(p => URL.revokeObjectURL(p))
  }

  function handleEditFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    const selected = Array.from(e.target.files ?? [])
    const album = albums.find(a => a.id === editingId)
    const currentCount = (album?.imagens.length ?? 0) - editRemovedImageIds.length + editNewFiles.length
    if (currentCount + selected.length > 5) {
      setError('Máximo de 5 fotos por álbum')
      return
    }
    setEditNewFiles(prev => [...prev, ...selected])
    setEditNewPreviews(prev => [...prev, ...selected.map(f => URL.createObjectURL(f))])
    setError(null)
  }

  async function handleSaveEdit() {
    if (!editingId) return
    setSending(true)
    setError(null)

    const formData = new FormData()
    formData.append('album_id', editingId)
    formData.append('titulo', editTitulo.trim())
    formData.append('descricao', editDescricao.trim())
    formData.append('tipo_evento', editTipoEvento)
    formData.append('data_evento', editDataEvento)
    formData.append('condominio_id', condominioId)
    formData.append('removed_image_ids', JSON.stringify(editRemovedImageIds))
    editNewFiles.forEach(f => formData.append('fotos', f))

    const res = await fetch('/api/album-fotos', { method: 'PUT', body: formData })
    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Erro ao atualizar álbum')
      setSending(false)
      return
    }

    cancelEdit()
    setSending(false)

    // Force full page reload to get fresh data from server
    window.location.reload()
  }

  function getCarouselIdx(albumId: string) {
    return carouselIndex[albumId] ?? 0
  }

  function setCarouselIdx(albumId: string, idx: number) {
    setCarouselIndex(prev => ({ ...prev, [albumId]: idx }))
  }

  return (
    <div className="max-w-4xl">
      {/* Header */}
      <div className="mb-8">
        <div className="flex items-center gap-3 mb-1">
          <Camera size={22} className="text-[#FC5931]" />
          <h1 className="text-2xl font-bold text-gray-900">Álbum de Fotos</h1>
        </div>
        <p className="text-sm text-gray-500">Crie álbuns de fotos para compartilhar com os moradores do condomínio.</p>
      </div>

      {/* Create form */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6 mb-8">
        <p className="text-sm font-semibold text-gray-700 mb-4">Criar novo álbum</p>

        {/* Title */}
        <input
          type="text"
          maxLength={100}
          placeholder="Nome do Evento ou demanda"
          value={titulo}
          onChange={e => setTitulo(e.target.value)}
          className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm mb-3 focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931]"
        />

        {/* Type */}
        <div className="mb-3">
          <p className="text-xs text-gray-500 mb-2 font-medium">Tipo do Evento:</p>
          <div className="flex flex-wrap gap-3">
            {(Object.keys(TIPO_LABELS) as TipoEvento[]).map(tipo => (
              <label key={tipo} className="flex items-center gap-1.5 cursor-pointer">
                <input
                  type="radio"
                  name="tipo_evento"
                  value={tipo}
                  checked={tipoEvento === tipo}
                  onChange={() => setTipoEvento(tipo)}
                  className="accent-[#FC5931]"
                />
                <span className="text-sm text-gray-700">{TIPO_LABELS[tipo]}</span>
              </label>
            ))}
          </div>
        </div>

        {/* Description */}
        <textarea
          placeholder="Descrição sobre o Evento"
          value={descricao}
          onChange={e => setDescricao(e.target.value)}
          rows={3}
          className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm mb-3 focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931] resize-none"
        />

        {/* Date */}
        <input
          type="date"
          value={dataEvento}
          onChange={e => setDataEvento(e.target.value)}
          placeholder="Escolha a data aqui"
          className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm mb-4 focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931]"
        />

        {/* Photo upload */}
        <div className="mb-4">
          <div
            onClick={() => fileInputRef.current?.click()}
            className="border-2 border-dashed border-gray-200 rounded-xl p-6 text-center cursor-pointer hover:border-[#FC5931]/40 transition-colors"
          >
            <Camera size={32} className="mx-auto mb-2 text-[#FC5931]/60" />
            <p className="text-sm text-gray-500">Insira aqui as fotos do Álbum</p>
            <p className="text-xs text-gray-400 mt-1">Máximo de 5 imagens por Álbum</p>
          </div>
          <input
            ref={fileInputRef}
            type="file"
            accept="image/*"
            multiple
            onChange={handleFileChange}
            className="hidden"
          />
        </div>

        {/* Previews */}
        {previews.length > 0 && (
          <div className="flex gap-2 flex-wrap mb-4">
            {previews.map((p, i) => (
              <div key={i} className="relative group">
                <img src={p} alt="" className="w-20 h-20 object-cover rounded-xl border border-gray-200" />
                <button
                  onClick={() => removeFile(i)}
                  className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center text-xs opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <X size={12} />
                </button>
              </div>
            ))}
          </div>
        )}

        {error && <p className="text-red-500 text-xs mb-3">{error}</p>}

        <button
          onClick={handleCreate}
          disabled={sending}
          className="flex items-center gap-2 bg-[#FC5931] hover:bg-[#D42F1D] text-white px-6 py-2.5 rounded-full text-sm font-semibold transition-colors disabled:opacity-50"
        >
          <Send size={14} />
          {sending ? 'Enviando...' : 'Inserir Álbum'}
        </button>
      </div>

      {/* Albums list */}
      <div className="space-y-4">
        {albums.length === 0 && (
          <div className="text-center py-10 text-gray-400 bg-white rounded-2xl border border-gray-100">
            <Camera size={32} className="mx-auto mb-2 opacity-30" />
            <p className="text-sm">Nenhum álbum criado ainda</p>
          </div>
        )}

        {albums.map(album => {
          const isEditing = editingId === album.id
          const currentImages = isEditing
            ? album.imagens.filter(img => !editRemovedImageIds.includes(img.id))
            : album.imagens
          const idx = getCarouselIdx(album.id)

          return (
            <div key={album.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
              {isEditing ? (
                /* Edit mode */
                <div className="p-5 space-y-3">
                  <div className="flex items-center justify-between mb-2">
                    <p className="text-sm font-semibold text-gray-700">Editar Álbum</p>
                    <button onClick={cancelEdit} className="text-gray-400 hover:text-gray-600">
                      <X size={18} />
                    </button>
                  </div>

                  <input
                    type="text"
                    maxLength={100}
                    value={editTitulo}
                    onChange={e => setEditTitulo(e.target.value)}
                    className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30"
                  />

                  <div className="flex flex-wrap gap-3">
                    {(Object.keys(TIPO_LABELS) as TipoEvento[]).map(tipo => (
                      <label key={tipo} className="flex items-center gap-1.5 cursor-pointer">
                        <input
                          type="radio"
                          value={tipo}
                          checked={editTipoEvento === tipo}
                          onChange={() => setEditTipoEvento(tipo)}
                          className="accent-[#FC5931]"
                        />
                        <span className="text-sm text-gray-700">{TIPO_LABELS[tipo]}</span>
                      </label>
                    ))}
                  </div>

                  <textarea
                    value={editDescricao}
                    onChange={e => setEditDescricao(e.target.value)}
                    rows={2}
                    className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 resize-none"
                  />

                  <input
                    type="date"
                    value={editDataEvento}
                    onChange={e => setEditDataEvento(e.target.value)}
                    className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30"
                  />

                  {/* Current images */}
                  <div className="flex gap-2 flex-wrap">
                    {currentImages.map(img => (
                      <div key={img.id} className="relative group">
                        <img src={img.imagem_url} alt="" className="w-20 h-20 object-cover rounded-xl border" />
                        <button
                          onClick={() => setEditRemovedImageIds(prev => [...prev, img.id])}
                          className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center text-xs opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <X size={12} />
                        </button>
                      </div>
                    ))}
                    {editNewPreviews.map((p, i) => (
                      <div key={`new-${i}`} className="relative group">
                        <img src={p} alt="" className="w-20 h-20 object-cover rounded-xl border border-green-300" />
                        <button
                          onClick={() => {
                            URL.revokeObjectURL(p)
                            setEditNewFiles(prev => prev.filter((_, j) => j !== i))
                            setEditNewPreviews(prev => prev.filter((_, j) => j !== i))
                          }}
                          className="absolute -top-2 -right-2 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center text-xs opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <X size={12} />
                        </button>
                      </div>
                    ))}
                    {currentImages.length + editNewFiles.length < 5 && (
                      <button
                        onClick={() => editFileInputRef.current?.click()}
                        className="w-20 h-20 border-2 border-dashed border-gray-200 rounded-xl flex items-center justify-center text-gray-400 hover:border-[#FC5931]/40 hover:text-[#FC5931] transition-colors"
                      >
                        <Image size={20} />
                      </button>
                    )}
                  </div>
                  <input
                    ref={editFileInputRef}
                    type="file"
                    accept="image/*"
                    multiple
                    onChange={handleEditFileChange}
                    className="hidden"
                  />

                  <div className="flex gap-2 pt-2">
                    <button
                      onClick={handleSaveEdit}
                      disabled={sending}
                      className="bg-[#FC5931] hover:bg-[#D42F1D] text-white px-5 py-2 rounded-full text-sm font-semibold transition-colors disabled:opacity-50"
                    >
                      {sending ? 'Salvando...' : 'Salvar'}
                    </button>
                    <button
                      onClick={cancelEdit}
                      className="border border-gray-200 text-gray-600 px-5 py-2 rounded-full text-sm font-medium hover:bg-gray-50 transition-colors"
                    >
                      Cancelar
                    </button>
                  </div>
                </div>
              ) : (
                /* View mode */
                <>
                  <div className="px-5 pt-4 pb-2">
                    <div className="flex items-start justify-between gap-4">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1">
                          <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded-full ${TIPO_COLORS[album.tipo_evento]}`}>
                            {TIPO_LABELS[album.tipo_evento]}
                          </span>
                          {album.data_evento && (
                            <span className="text-xs text-gray-400">
                              {new Date(album.data_evento + 'T12:00:00').toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}
                            </span>
                          )}
                        </div>
                        <p className="font-semibold text-gray-900 text-sm">
                          Nome do Evento: {album.titulo}
                        </p>
                        {album.descricao && (
                          <p className="text-xs text-gray-500 mt-0.5">
                            Descrição do Evento: {album.descricao}
                          </p>
                        )}
                      </div>
                      <div className="flex items-center gap-1 shrink-0">
                        <button
                          onClick={() => startEdit(album)}
                          className="p-1.5 rounded-lg text-gray-400 hover:bg-gray-50 hover:text-gray-600 transition-colors"
                          title="Editar"
                        >
                          <Pencil size={16} />
                        </button>
                        <button
                          onClick={() => handleDelete(album.id)}
                          className="p-1.5 rounded-lg text-red-400 hover:bg-red-50 hover:text-red-600 transition-colors"
                          title="Excluir"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                  </div>

                  {/* Photo carousel */}
                  {album.imagens.length > 0 && (
                    <div className="relative mx-5 mb-3 rounded-xl overflow-hidden bg-gray-50">
                      <img
                        src={album.imagens[idx]?.imagem_url ?? album.imagens[0]?.imagem_url}
                        alt=""
                        className="w-full max-h-[500px] object-contain"
                      />
                      {album.imagens.length > 1 && (
                        <>
                          <button
                            onClick={() => setCarouselIdx(album.id, (idx - 1 + album.imagens.length) % album.imagens.length)}
                            className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 bg-black/40 text-white rounded-full flex items-center justify-center hover:bg-black/60 transition-colors"
                          >
                            <ChevronLeft size={16} />
                          </button>
                          <button
                            onClick={() => setCarouselIdx(album.id, (idx + 1) % album.imagens.length)}
                            className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 bg-black/40 text-white rounded-full flex items-center justify-center hover:bg-black/60 transition-colors"
                          >
                            <ChevronRight size={16} />
                          </button>
                          <div className="absolute bottom-2 left-1/2 -translate-x-1/2 flex gap-1">
                            {album.imagens.map((_, i) => (
                              <span
                                key={i}
                                className={`w-2 h-2 rounded-full transition-colors ${i === idx ? 'bg-white' : 'bg-white/40'}`}
                              />
                            ))}
                          </div>
                        </>
                      )}
                    </div>
                  )}

                  {/* Stats */}
                  <div className="px-5 pb-4 flex items-center gap-4 text-xs text-gray-500">
                    <span className="flex items-center gap-1">
                      <Heart size={14} className="text-red-400" />
                      {album.reacoes_count} reações
                    </span>
                    <span className="flex items-center gap-1">
                      <MessageCircle size={14} className="text-blue-400" />
                      {album.comentarios_count} comentários
                    </span>
                    <span className="flex items-center gap-1">
                      <Eye size={14} className="text-gray-400" />
                      {album.visualizacoes_count} visualizações
                    </span>
                    <span className="flex items-center gap-1 ml-auto">
                      <Image size={14} /> {album.imagens.length}/5 fotos
                    </span>
                  </div>
                </>
              )}
            </div>
          )
        })}
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { User, Clock, CheckCircle, XCircle, Lock } from 'lucide-react'
import ApproveButton from './approve-button'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

type Profile = {
  id: string
  nome_completo: string | null
  bloco_txt: string | null
  apto_txt: string | null
  status_aprovacao: string | null
  papel_sistema: string | null
  created_at: string
}

type Filter = 'pendente' | 'aprovado' | 'bloqueado' | 'rejeitado' | 'todos'

export default function AprovacoesClient({ profiles, tipoEstrutura }: { profiles: Profile[]; tipoEstrutura?: string }) {
  const [filter, setFilter] = useState<Filter>('pendente')
  const blocoLabel = getBlocoLabel(tipoEstrutura)
  const aptoLabel = getAptoLabel(tipoEstrutura)

  function isPending(p: Profile)  { return !p.status_aprovacao || p.status_aprovacao === 'pendente' }
  function isApproved(p: Profile) { return p.status_aprovacao === 'aprovado' }
  function isBlocked(p: Profile)  { return p.status_aprovacao === 'bloqueado' }
  function isRejected(p: Profile) { return p.status_aprovacao === 'rejeitado' }

  const counts = {
    todos:     profiles.length,
    pendente:  profiles.filter(isPending).length,
    aprovado:  profiles.filter(isApproved).length,
    bloqueado: profiles.filter(isBlocked).length,
    rejeitado: profiles.filter(isRejected).length,
  }

  const filtered = profiles.filter(p => {
    if (filter === 'todos')     return true
    if (filter === 'pendente')  return isPending(p)
    if (filter === 'aprovado')  return isApproved(p)
    if (filter === 'bloqueado') return isBlocked(p)
    if (filter === 'rejeitado') return isRejected(p)
    return true
  })

  const FILTERS: { key: Filter; label: string; color: string; activeColor: string }[] = [
    { key: 'pendente',  label: 'Pendentes',  color: 'text-amber-600 bg-amber-50',   activeColor: 'bg-amber-500 text-white'  },
    { key: 'aprovado',  label: 'Liberados',  color: 'text-green-600 bg-green-50',   activeColor: 'bg-green-500 text-white'  },
    { key: 'bloqueado', label: 'Bloqueados', color: 'text-red-600 bg-red-50',       activeColor: 'bg-red-500 text-white'    },
    { key: 'rejeitado', label: 'Rejeitados', color: 'text-gray-600 bg-gray-100',    activeColor: 'bg-gray-600 text-white'   },
    { key: 'todos',     label: 'Todos',      color: 'text-gray-500 bg-gray-50 border border-gray-200', activeColor: 'bg-gray-700 text-white' },
  ]

  return (
    <div>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Aprovações</h1>
        <p className="text-gray-500 text-sm mt-1">Gerencie os cadastros do condomínio.</p>
      </div>

      {/* Filter tabs */}
      <div className="flex gap-2 flex-wrap mb-5">
        {FILTERS.map(f => (
          <button
            key={f.key}
            onClick={() => setFilter(f.key)}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all ${
              filter === f.key ? f.activeColor : f.color
            }`}
          >
            {f.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full font-bold ${
              filter === f.key ? 'bg-white/30' : 'bg-white/60'
            }`}>
              {counts[f.key]}
            </span>
          </button>
        ))}
      </div>

      {/* List */}
      {filtered.length === 0 ? (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-12 text-center">
          <CheckCircle size={40} className="mx-auto text-green-400 mb-3" />
          <p className="font-semibold text-gray-700">Nenhum cadastro nesta categoria.</p>
        </div>
      ) : (
        <div className="grid gap-3">
          {filtered.map(p => {
            const status = p.status_aprovacao ?? 'pendente'
            const pending   = isPending(p)
            const approved  = isApproved(p)
            const blocked   = isBlocked(p)
            const rejected  = isRejected(p)

            return (
              <div key={p.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
                <div className="flex flex-col sm:flex-row sm:items-center gap-4">
                  {/* Avatar */}
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 ${
                    blocked ? 'bg-red-100' : 'bg-[#FC5931]/10'
                  }`}>
                    {blocked
                      ? <Lock size={20} className="text-red-500" />
                      : <User size={22} className="text-[#FC5931]" />}
                  </div>

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <p className={`font-semibold ${blocked ? 'text-gray-400 line-through' : 'text-gray-900'}`}>
                      {p.nome_completo ?? '—'}
                    </p>
                    <div className="flex flex-wrap gap-x-3 gap-y-1 mt-1.5">
                      {p.papel_sistema && (
                        <span className="text-xs px-2 py-0.5 bg-gray-100 text-gray-600 rounded-full">
                          {p.papel_sistema}
                        </span>
                      )}
                      {p.bloco_txt && (
                        <span className="text-xs text-gray-500">
                          🏠 {blocoLabel} {p.bloco_txt}{p.apto_txt ? ` / ${aptoLabel} ${p.apto_txt}` : ''}
                        </span>
                      )}
                      <span className="text-xs text-gray-400">
                        📅 {new Date(p.created_at).toLocaleDateString('pt-BR', {
                          day: '2-digit', month: '2-digit', year: 'numeric'
                        })}
                      </span>
                    </div>
                  </div>

                  {/* Status badge */}
                  <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold flex-shrink-0 ${
                    approved  ? 'bg-green-100 text-green-700'  :
                    blocked   ? 'bg-red-100 text-red-700'      :
                    rejected  ? 'bg-gray-100 text-gray-600'    :
                                'bg-amber-100 text-amber-700'
                  }`}>
                    {approved  ? <><CheckCircle size={12} /> Liberado</>  :
                     blocked   ? <><Lock size={12} /> Bloqueado</>        :
                     rejected  ? <><XCircle size={12} /> Rejeitado</>     :
                                 <><Clock size={12} /> Pendente</>}
                  </span>

                  {/* Action buttons — context sensitive */}
                  <div className="flex gap-2 flex-shrink-0 flex-wrap">
                    {pending && (
                      <>
                        <ApproveButton profileId={p.id} action="approve" />
                        <ApproveButton profileId={p.id} action="reject" />
                      </>
                    )}
                    {approved && (
                      <ApproveButton profileId={p.id} action="block" />
                    )}
                    {(blocked || rejected) && (
                      <ApproveButton profileId={p.id} action="unblock" />
                    )}
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

'use client'
import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import {
  CheckCircle, XCircle, Clock, Image as ImageIcon,
  ChevronDown, ChevronUp, ArrowLeft
} from 'lucide-react'
import Link from 'next/link'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

interface Perfil {
  nome_completo: string
  bloco_txt: string
  apto_txt: string
  whatsapp: string
}

interface Classificado {
  id: string
  titulo: string
  descricao: string
  categoria: string
  marca_modelo: string
  preco: number | null
  condicao: string
  mostrar_telefone: boolean
  foto_url: string | null
  status: string
  cod_interno: string
  created_at: string
  perfil: Perfil | null
}

const CATEGORIAS: Record<string, string> = {
  eletronicos: 'Eletrônicos',
  moveis: 'Móveis',
  roupas: 'Roupas',
  veiculos: 'Veículos',
  servicos: 'Serviços',
  imoveis: 'Imóveis',
  carros_e_pecas: 'Carros e Peças',
  outros: 'Outros',
}

export default function ClassificadosAdminClient({
  classificados: initialClassificados,
  condominioId,
  tipoEstrutura,
}: {
  classificados: Classificado[]
  condominioId: string
  tipoEstrutura: string
}) {
  const supabase = createClient()
  const router = useRouter()
  const [classificados, setClassificados] = useState(initialClassificados)
  const [loading, setLoading] = useState<Record<string, boolean>>({})
  const [expandedId, setExpandedId] = useState<string | null>(null)
  const [filter, setFilter] = useState<'todos' | 'pendente' | 'aprovado' | 'rejeitado'>('pendente')

  const blocoLabel = getBlocoLabel(tipoEstrutura)
  const aptoLabel = getAptoLabel(tipoEstrutura)

  const filtered = classificados.filter(c => filter === 'todos' ? true : c.status === filter)

  async function handleAction(id: string, newStatus: 'aprovado' | 'rejeitado') {
    setLoading(prev => ({ ...prev, [id]: true }))
    try {
      const { data: { user } } = await supabase.auth.getUser()

      const { error } = await supabase
        .from('classificados')
        .update({
          status: newStatus,
          aprovado_por: user?.id,
        })
        .eq('id', id)

      if (error) throw error

      // Trigger notification
      try {
        await supabase.functions.invoke('classificados-notify', {
          body: { condominio_id: condominioId, classificado_id: id, action: newStatus }
        })
      } catch (e) {
        console.warn('Notification failed:', e)
      }

      setClassificados(prev =>
        prev.map(c => c.id === id ? { ...c, status: newStatus } : c)
      )
      router.refresh()
    } catch (error) {
      console.error('Error updating classificado:', error)
      alert('Erro ao atualizar anúncio')
    } finally {
      setLoading(prev => ({ ...prev, [id]: false }))
    }
  }

  const statusBadge = (status: string) => {
    switch (status) {
      case 'aprovado': return <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold bg-green-100 text-green-700"><CheckCircle size={12} /> Aprovado</span>
      case 'rejeitado': return <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold bg-red-100 text-red-700"><XCircle size={12} /> Rejeitado</span>
      default: return <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold bg-yellow-100 text-yellow-700"><Clock size={12} /> Pendente</span>
    }
  }

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      {/* Header */}
      <div className="flex items-center gap-3 mb-6">
        <Link href="/admin" className="p-2 rounded-lg hover:bg-gray-100 transition-colors">
          <ArrowLeft size={20} />
        </Link>
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Aprovar Classificados</h1>
          <p className="text-sm text-gray-500">Gerencie os anúncios dos moradores</p>
        </div>
      </div>

      {/* Filter tabs */}
      <div className="flex gap-2 mb-6">
        {(['pendente', 'aprovado', 'rejeitado', 'todos'] as const).map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
              filter === f
                ? 'bg-[#FC5931] text-white shadow-md'
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
          >
            {f === 'todos' ? 'Todos' : f.charAt(0).toUpperCase() + f.slice(1)}
            {f !== 'todos' && (
              <span className="ml-1 text-xs">
                ({classificados.filter(c => c.status === f).length})
              </span>
            )}
          </button>
        ))}
      </div>

      {/* Cards */}
      {filtered.length === 0 ? (
        <div className="text-center py-16 text-gray-400">
          <Clock size={48} className="mx-auto mb-3 opacity-50" />
          <p className="text-lg font-medium">Nenhum anúncio {filter !== 'todos' ? filter : ''}</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filtered.map(c => (
            <div key={c.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
              <div
                className="p-5 cursor-pointer hover:bg-gray-50 transition-colors"
                onClick={() => setExpandedId(expandedId === c.id ? null : c.id)}
              >
                <div className="flex gap-4">
                  {/* Photo */}
                  <div className="w-20 h-20 rounded-xl bg-gray-100 flex-shrink-0 overflow-hidden flex items-center justify-center">
                    {c.foto_url ? (
                      <img src={c.foto_url} alt={c.titulo} className="w-full h-full object-cover" />
                    ) : (
                      <ImageIcon size={24} className="text-gray-300" />
                    )}
                  </div>

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-2">
                      <h3 className="font-bold text-gray-900 truncate">{c.titulo}</h3>
                      {statusBadge(c.status)}
                    </div>
                    <p className="text-sm text-gray-500 mt-1">
                      <strong>Dono:</strong> {c.perfil?.nome_completo ?? 'N/A'}
                    </p>
                    <p className="text-sm text-gray-500">
                      {blocoLabel}: {c.perfil?.bloco_txt ?? '?'} · {aptoLabel}: {c.perfil?.apto_txt ?? '?'}
                    </p>
                    <div className="flex items-center gap-3 mt-1">
                      {c.preco && (
                        <span className="text-sm font-bold text-green-600">
                          R$ {Number(c.preco).toFixed(2).replace('.', ',')}
                        </span>
                      )}
                      <span className="text-xs text-gray-400">
                        {new Date(c.created_at).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="text-xs text-gray-400">Cod: {c.cod_interno}</span>
                    </div>
                  </div>

                  <button className="self-center text-gray-400">
                    {expandedId === c.id ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                  </button>
                </div>
              </div>

              {/* Expanded details */}
              {expandedId === c.id && (
                <div className="px-5 pb-5 border-t border-gray-100 pt-4">
                  <div className="grid grid-cols-2 gap-3 text-sm mb-4">
                    <div><span className="text-gray-500">Categoria:</span> {CATEGORIAS[c.categoria] ?? c.categoria}</div>
                    <div><span className="text-gray-500">Condição:</span> {c.condicao === 'novo' ? 'Novo' : 'Usado'}</div>
                    {c.marca_modelo && <div><span className="text-gray-500">Marca/Modelo:</span> {c.marca_modelo}</div>}
                    <div><span className="text-gray-500">Telefone visível:</span> {c.mostrar_telefone ? 'Sim' : 'Não'}</div>
                    {c.mostrar_telefone && c.perfil?.whatsapp && (
                      <div><span className="text-gray-500">WhatsApp:</span> {c.perfil.whatsapp}</div>
                    )}
                  </div>
                  {c.descricao && (
                    <div className="mb-4">
                      <span className="text-sm text-gray-500">Descrição:</span>
                      <p className="text-sm text-gray-700 mt-1 whitespace-pre-wrap">{c.descricao}</p>
                    </div>
                  )}

                  {/* Action buttons */}
                  {c.status === 'pendente' && (
                    <div className="flex gap-3">
                      <button
                        onClick={() => handleAction(c.id, 'aprovado')}
                        disabled={loading[c.id]}
                        className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-green-500 hover:bg-green-600 text-white font-bold rounded-xl transition-colors disabled:opacity-50"
                      >
                        <CheckCircle size={18} />
                        {loading[c.id] ? 'Processando...' : 'Aprovar'}
                      </button>
                      <button
                        onClick={() => handleAction(c.id, 'rejeitado')}
                        disabled={loading[c.id]}
                        className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-red-500 hover:bg-red-600 text-white font-bold rounded-xl transition-colors disabled:opacity-50"
                      >
                        <XCircle size={18} />
                        {loading[c.id] ? 'Processando...' : 'Rejeitar'}
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useRef, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import {
  FolderOpen, FolderPlus, FilePlus, Download, Pencil, Trash2,
  Eye, Search, ChevronDown, ChevronRight, X, Upload, Loader2, FileText, Plus,
  ChevronLeft, Calendar
} from 'lucide-react'

// ─── Types ───────────────────────────────────────────────────────────────────

export type Pasta = {
  id: string
