      {/* Top 5 opportunities */}
      {comparisons.filter(c => c.position === 'expensive').length > 0 && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
          <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
            <TrendingDown size={18} /> Oportunidades de Desconto
          </h3>
          <p className="text-sm text-gray-400 mb-3">Produtos em que {marketName} está acima da média — baixar preço pode atrair clientes.</p>
          <div className="space-y-2">
            {comparisons.filter(c => c.position === 'expensive').slice(0, 5).map((c, i) => (
              <div key={i} className="flex items-center gap-3 p-3 bg-red-50/50 rounded-xl">
                <span className="text-lg">{c.emoji}</span>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-gray-700 truncate">{c.product_name} {c.variant_name}</p>
                  <p className="text-xs text-gray-400">Média: R$ {c.avg_market_price.toFixed(2)}</p>
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-red-600">R$ {c.my_price.toFixed(2)}</p>
                  <p className="text-xs text-red-500 flex items-center gap-0.5 justify-end">
                    <ArrowUpRight size={10} /> +{c.diff_percent.toFixed(1)}%
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

function PricesTab({ comparisons, marketName }: { comparisons: PriceComparison[]; marketName: string }) {
  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
      <div className="p-5 border-b border-gray-100">
        <h2 className="font-semibold text-gray-800 flex items-center gap-2">
          <DollarSign size={18} /> Preços de {marketName} ({comparisons.length} produtos)
        </h2>
      </div>
      <table className="w-full">
        <thead>
          <tr className="text-xs text-gray-400 uppercase tracking-wider">
            <th className="w-10"></th>
            <th className="text-left px-5 py-3">Produto</th>
            <th className="text-right px-5 py-3">Seu Preço</th>
            <th className="text-right px-5 py-3">Média Mercado</th>
            <th className="text-right px-5 py-3">Diferença</th>
            <th className="text-center px-5 py-3">Posição</th>
          </tr>
        </thead>
        <tbody>
          {comparisons.map((c, i) => (
            <tr key={i} className="border-t border-gray-50 hover:bg-gray-50/50">
              <td className="pl-5 text-lg">{c.emoji}</td>
              <td className="px-5 py-3 text-sm text-gray-700">{c.product_name} {c.variant_name}</td>
              <td className="px-5 py-3 text-right text-sm font-bold text-gray-800">R$ {c.my_price.toFixed(2)}</td>
              <td className="px-5 py-3 text-right text-sm text-gray-400">R$ {c.avg_market_price.toFixed(2)}</td>
              <td className="px-5 py-3 text-right text-sm">
                <span className={`flex items-center gap-0.5 justify-end font-medium ${
                  c.diff_percent < 0 ? 'text-green-600' : c.diff_percent > 0 ? 'text-red-500' : 'text-gray-500'
                }`}>
                  {c.diff_percent < 0 ? <ArrowDownRight size={12} /> : c.diff_percent > 0 ? <ArrowUpRight size={12} /> : <Minus size={12} />}
                  {Math.abs(c.diff_percent).toFixed(1)}%
                </span>
              </td>
              <td className="px-5 py-3 text-center">
                <span className={`text-xs font-medium px-2 py-0.5 rounded-full ${
                  c.position === 'cheapest' ? 'bg-green-100 text-green-700' :
                  c.position === 'expensive' ? 'bg-red-100 text-red-600' : 'bg-gray-100 text-gray-500'
                }`}>
                  {c.position === 'cheapest' ? '🏆 Mais Barato' : c.position === 'expensive' ? '⚠️ Caro' : '➖ Médio'}
                </span>
              </td>
            </tr>
          ))}
          {comparisons.length === 0 && (
            <tr><td colSpan={6} className="px-5 py-10 text-center text-gray-400 text-sm">Nenhum preço disponível para este mercado</td></tr>
          )}
        </tbody>
      </table>
    </div>
  )
}

function CompetitiveTab({ comparisons, marketName }: { comparisons: PriceComparison[]; marketName: string }) {
  const cheapest = comparisons.filter(c => c.position === 'cheapest')
  const competitive = comparisons.filter(c => c.position === 'competitive')
  const expensive = comparisons.filter(c => c.position === 'expensive')

  return (
    <div className="space-y-6">
      {/* Summary bar */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
        <h3 className="font-semibold text-gray-800 mb-4">Análise Competitiva de {marketName}</h3>
        {comparisons.length > 0 && (
          <div className="w-full h-8 rounded-full overflow-hidden flex">
            {cheapest.length > 0 && (
              <div className="bg-green-400 h-full flex items-center justify-center text-xs font-bold text-white"
                style={{ width: `${(cheapest.length / comparisons.length) * 100}%` }}>
                {cheapest.length}
              </div>
            )}
            {competitive.length > 0 && (
              <div className="bg-gray-300 h-full flex items-center justify-center text-xs font-bold text-gray-600"
                style={{ width: `${(competitive.length / comparisons.length) * 100}%` }}>
                {competitive.length}
              </div>
            )}
            {expensive.length > 0 && (
              <div className="bg-red-400 h-full flex items-center justify-center text-xs font-bold text-white"
                style={{ width: `${(expensive.length / comparisons.length) * 100}%` }}>
                {expensive.length}
              </div>
            )}
          </div>
        )}
        <div className="flex justify-between mt-2 text-xs text-gray-400">
          <span>🟢 Mais barato ({cheapest.length})</span>
          <span>⚪ Competitivo ({competitive.length})</span>
          <span>🔴 Mais caro ({expensive.length})</span>
        </div>
      </div>

      {/* Strengths */}
      {cheapest.length > 0 && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
          <h3 className="font-semibold text-green-700 mb-3 flex items-center gap-2"><TrendingDown size={18} /> Pontos Fortes</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
            {cheapest.map((c, i) => (
              <div key={i} className="flex items-center gap-3 p-3 bg-green-50/50 rounded-xl">
                <span className="text-lg">{c.emoji}</span>
                <span className="text-sm text-gray-700 flex-1 truncate">{c.product_name} {c.variant_name}</span>
                <span className="text-xs text-green-600 font-bold">{c.diff_percent.toFixed(1)}%</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Weaknesses */}
      {expensive.length > 0 && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
          <h3 className="font-semibold text-red-600 mb-3 flex items-center gap-2"><TrendingUp size={18} /> Oportunidades</h3>
          <p className="text-sm text-gray-400 mb-3">Reduzir estes preços pode atrair mais clientes da região.</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
            {expensive.map((c, i) => (
              <div key={i} className="flex items-center gap-3 p-3 bg-red-50/50 rounded-xl">
                <span className="text-lg">{c.emoji}</span>
                <span className="text-sm text-gray-700 flex-1 truncate">{c.product_name} {c.variant_name}</span>
                <span className="text-xs text-red-500 font-bold">+{c.diff_percent.toFixed(1)}%</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

function PromosTab({ promotions, marketName, showForm, onToggleForm, promoProduct, onPromoProductChange, promoOrigPrice, onPromoOrigPriceChange, promoNewPrice, onPromoNewPriceChange, promoValidUntil, onPromoValidUntilChange, onCreatePromo }: {
  promotions: PromoData[]; marketName: string; showForm: boolean
  onToggleForm: () => void
  promoProduct: string; onPromoProductChange: (v: string) => void
  promoOrigPrice: string; onPromoOrigPriceChange: (v: string) => void
  promoNewPrice: string; onPromoNewPriceChange: (v: string) => void
  promoValidUntil: string; onPromoValidUntilChange: (v: string) => void
  onCreatePromo: () => void
}) {
  return (
    <div className="space-y-4">
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-semibold text-gray-800 flex items-center gap-2">
            <Percent size={18} /> Promoções de {marketName}
          </h3>
          <button onClick={onToggleForm}
            className="flex items-center gap-2 px-4 py-2 bg-[#FC5931] text-white rounded-xl text-sm font-medium hover:bg-[#e04e28] transition-colors">
            + Nova Promoção
          </button>
        </div>

        {showForm && (
          <div className="bg-gray-50 rounded-xl p-4 mb-4 space-y-3">
            <input placeholder="Produto (ex: Arroz Camil 5kg)" value={promoProduct} onChange={e => onPromoProductChange(e.target.value)}
              className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931] outline-none text-sm" />
            <div className="grid grid-cols-3 gap-3">
              <input placeholder="Preço original" type="number" step="0.01" value={promoOrigPrice} onChange={e => onPromoOrigPriceChange(e.target.value)}
                className="px-4 py-2.5 rounded-xl border border-gray-200 focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931] outline-none text-sm" />
              <input placeholder="Preço promo" type="number" step="0.01" value={promoNewPrice} onChange={e => onPromoNewPriceChange(e.target.value)}
                className="px-4 py-2.5 rounded-xl border border-gray-200 focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931] outline-none text-sm" />
              <input placeholder="Válido até" type="date" value={promoValidUntil} onChange={e => onPromoValidUntilChange(e.target.value)}
                className="px-4 py-2.5 rounded-xl border border-gray-200 focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931] outline-none text-sm" />
            </div>
            <button onClick={onCreatePromo}
              className="px-6 py-2.5 bg-[#FC5931] text-white rounded-xl text-sm font-medium hover:bg-[#e04e28] transition-colors">
              Criar Promoção
            </button>
          </div>
        )}

        {promotions.length > 0 ? (
          <div className="space-y-2">
            {promotions.map(p => (
              <div key={p.id} className="flex items-center gap-4 p-4 bg-gray-50 rounded-xl">
                <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center text-green-700 font-bold text-sm">
                  {p.discount_pct > 0 ? `-${p.discount_pct}%` : '🏷️'}
                </div>
                <div className="flex-1">
                  <p className="text-sm font-medium text-gray-700">{p.product_name}</p>
                  <div className="flex items-center gap-2 mt-0.5">
                    {p.original_price > 0 && (
                      <span className="text-xs text-gray-400 line-through">R$ {p.original_price.toFixed(2)}</span>
                    )}
                    <span className="text-sm font-bold text-green-600">R$ {p.promo_price.toFixed(2)}</span>
                  </div>
                </div>
                {p.valid_until && (
                  <span className="text-xs text-gray-400">até {new Date(p.valid_until).toLocaleDateString('pt-BR')}</span>
                )}
              </div>
            ))}
          </div>
        ) : (
          <p className="text-center py-8 text-gray-400 text-sm">Nenhuma promoção ativa para {marketName}</p>
        )}
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import {
  Users, TrendingUp, ShoppingCart, Bell, Package,
  Store, PlusCircle, Send, RefreshCw, Trash2, Search,
  Award, Eye, BarChart3, HelpCircle, X, Route, CheckCircle2
} from 'lucide-react'

type Stats = {
  total_contributors: number
  total_prices: number
  total_alerts: number
  total_products: number
  total_variants: number
  total_skus: number
  total_supermarkets: number
  total_lists: number
}

type TopUser = {
  user_id: string
  total_points: number
  weekly_points: number
  reports_count: number
  rank_title: string
  confirmations_given: number
  name?: string
}

type RecentPrice = {
  id: string
  price: number
  source: string
  confidence_score: number
  confirmations: number
  created_at: string
  product_name?: string
  variant_name?: string
  emoji?: string
  supermarket_name?: string
}

type Supermarket = {
  id: string
  name: string
  cnpj?: string
  address?: string
}

export default function ListaInteligenteClient() {
  const supabase = createClient()
  const [stats, setStats] = useState<Stats | null>(null)
  const [topUsers, setTopUsers] = useState<TopUser[]>([])
  const [recentPrices, setRecentPrices] = useState<RecentPrice[]>([])
  const [supermarkets, setSupermarkets] = useState<Supermarket[]>([])
  const [loading, setLoading] = useState(true)
  const [activeTab, setActiveTab] = useState<'dashboard' | 'users' | 'prices' | 'products' | 'markets' | 'push'>('dashboard')
  const [showGuide, setShowGuide] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('lista_admin_guide_dismissed') !== 'true'
    }
    return true
  })

  // Modals
  const [showAddMarket, setShowAddMarket] = useState(false)
  const [showAddProduct, setShowAddProduct] = useState(false)
  const [showPush, setShowPush] = useState(false)
  const [pushTitle, setPushTitle] = useState('🛒 Lista Inteligente')
  const [pushBody, setPushBody] = useState('')
  const [pushSending, setPushSending] = useState(false)
  const [newMarketName, setNewMarketName] = useState('')
  const [newMarketCnpj, setNewMarketCnpj] = useState('')
  const [newMarketAddr, setNewMarketAddr] = useState('')
  const [newProdName, setNewProdName] = useState('')
  const [newProdCategory, setNewProdCategory] = useState('')
  const [newProdEmoji, setNewProdEmoji] = useState('📦')

  const loadData = useCallback(async () => {
    setLoading(true)
    try {
      // Stats
      const [prices, users, alerts, products, variants, skus, markets, lists] = await Promise.all([
        supabase.from('lista_prices_raw').select('id').limit(10000),
        supabase.from('lista_user_points').select('user_id').limit(10000),
        supabase.from('lista_price_alerts').select('id').limit(10000),
        supabase.from('lista_products_base').select('id').limit(10000),
        supabase.from('lista_product_variants').select('id').limit(10000),
        supabase.from('lista_products_sku').select('id').limit(10000),
        supabase.from('lista_supermarkets').select('*').order('name'),
        supabase.from('lista_shopping_lists').select('id').limit(10000),
      ])

      setStats({
        total_contributors: users.data?.length ?? 0,
        total_prices: prices.data?.length ?? 0,
        total_alerts: alerts.data?.length ?? 0,
        total_products: products.data?.length ?? 0,
        total_variants: variants.data?.length ?? 0,
        total_skus: skus.data?.length ?? 0,
        total_supermarkets: markets.data?.length ?? 0,
        total_lists: lists.data?.length ?? 0,
      })

      setSupermarkets((markets.data ?? []) as Supermarket[])

      // Top users
      const { data: topData } = await supabase
        .from('lista_user_points')
        .select('user_id, total_points, weekly_points, reports_count, rank_title, confirmations_given')
        .order('total_points', { ascending: false })
        .limit(20)

      if (topData?.length) {
        const userIds = topData.map(u => u.user_id)
        const { data: profiles } = await supabase
          .from('perfil')
          .select('id, nome_completo')
          .in('id', userIds)

        const nameMap: Record<string, string> = {}
        profiles?.forEach(p => { nameMap[p.id] = p.nome_completo || 'Anônimo' })

        setTopUsers(topData.map(u => ({ ...u, name: nameMap[u.user_id] || 'Anônimo' })))
      }

      // Recent prices
      const { data: priceData } = await supabase
        .from('lista_prices_raw')
        .select('id, price, source, confidence_score, confirmations, created_at, lista_products_sku(brand, weight_label, lista_product_variants(variant_name, lista_products_base(name, icon_emoji))), lista_supermarkets(name)')
        .order('created_at', { ascending: false })
        .limit(20)

      if (priceData) {
        setRecentPrices(priceData.map((p: any) => ({
          id: p.id,
          price: p.price,
          source: p.source,
          confidence_score: p.confidence_score,
          confirmations: p.confirmations,
          created_at: p.created_at,
          product_name: p.lista_products_sku?.lista_product_variants?.lista_products_base?.name,
          variant_name: p.lista_products_sku?.lista_product_variants?.variant_name,
          emoji: p.lista_products_sku?.lista_product_variants?.lista_products_base?.icon_emoji,
          supermarket_name: p.lista_supermarkets?.name,
        })))
      }
    } catch (e) {
      console.error('Load error:', e)
    }
    setLoading(false)
  }, [])

  useEffect(() => { ;(async () => { await loadData() })() }, [loadData])

  const handleAddMarket = async () => {
    if (!newMarketName.trim()) return
    await supabase.from('lista_supermarkets').insert({
      name: newMarketName.trim(),
      cnpj: newMarketCnpj.trim() || null,
      address: newMarketAddr.trim() || null,
    })
    setShowAddMarket(false)
    setNewMarketName('')
    setNewMarketCnpj('')
    setNewMarketAddr('')
    loadData()
  }

  const handleAddProduct = async () => {
    if (!newProdName.trim()) return
    await supabase.from('lista_products_base').insert({
      name: newProdName.trim(),
      category: newProdCategory.trim() || 'outros',
      icon_emoji: newProdEmoji,
    })
    setShowAddProduct(false)
    setNewProdName('')
    setNewProdCategory('')
    setNewProdEmoji('📦')
    loadData()
  }

  const handleDeleteMarket = async (id: string) => {
    if (!confirm('Excluir este mercado?')) return
    await supabase.from('lista_supermarkets').delete().eq('id', id)
    loadData()
  }

  const handleSendPush = async () => {
    if (!pushBody.trim()) return
    setPushSending(true)
    try {
      const { data: users } = await supabase.from('lista_user_points').select('user_id')
      const userIds = (users ?? []).map(u => u.user_id)
      if (!userIds.length) { alert('Nenhum usuário ativo'); setPushSending(false); return }

      await supabase.functions.invoke('parcel-push-notify', {
        body: { user_ids: userIds, title: pushTitle, body: pushBody, data: { type: 'lista_mercado_promo' } }
      })
      alert(`✅ Push enviado para ${userIds.length} usuários!`)
      setShowPush(false)
      setPushBody('')
    } catch (e) {
      alert('Erro: ' + e)
    }
    setPushSending(false)
  }

  const emojis = ['🍚', '🫘', '🥛', '🍖', '🍗', '🥩', '🧀', '🍞', '🥚', '🍝', '🥫', '🧈', '☕', '🍺', '🧃', '🧹', '🧼', '📦', '🥬', '🍎', '🍌', '🥕', '🫒']

  const tabs = [
    { id: 'dashboard' as const, label: 'Dashboard', icon: <BarChart3 size={16} /> },
    { id: 'users' as const, label: 'Colaboradores', icon: <Users size={16} /> },
    { id: 'prices' as const, label: 'Preços', icon: <TrendingUp size={16} /> },
    { id: 'products' as const, label: 'Produtos', icon: <Package size={16} /> },
    { id: 'markets' as const, label: 'Mercados', icon: <Store size={16} /> },
    { id: 'push' as const, label: 'Push', icon: <Send size={16} /> },
  ]

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#FC5931]" />
      </div>
    )
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
            🛒 Lista Inteligente
            <span className="text-sm font-normal bg-green-100 text-green-700 px-2 py-0.5 rounded-full">Admin</span>
          </h1>
          <p className="text-gray-500 text-sm mt-1">Gerenciamento do módulo de comparação de preços</p>
        </div>
        <button onClick={loadData} className="flex items-center gap-2 px-4 py-2 bg-white rounded-xl border border-gray-200 text-gray-600 hover:bg-gray-50 transition-colors text-sm">
          <RefreshCw size={14} /> Atualizar
        </button>
        <button
          onClick={() => {
            localStorage.removeItem('lista_admin_guide_dismissed')
            setShowGuide(true)
          }}
          className="flex items-center gap-1.5 px-3 py-1.5 text-sm text-[#FC5931] hover:bg-orange-50 rounded-lg transition-colors"
        >
          <HelpCircle size={16} /> Como começar
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-white rounded-xl p-1 border border-gray-200">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === tab.id ? 'bg-[#FC5931] text-white shadow-sm' : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {/* Content */}
      {activeTab === 'dashboard' && (
        <div className="space-y-6">
          {/* Step Guide */}
          {showGuide && (
            <div className="bg-gradient-to-r from-orange-50 to-amber-50 border border-orange-200 rounded-xl p-5">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <Route size={18} className="text-[#FC5931]" />
                  <span className="font-semibold text-orange-900 text-sm">Como começar com a Lista Inteligente</span>
                </div>
                <button
                  onClick={() => {
                    localStorage.setItem('lista_admin_guide_dismissed', 'true')
                    setShowGuide(false)
                  }}
                  className="text-gray-400 hover:text-gray-600"
                  title="Fechar guia"
                >
                  <X size={16} />
                </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                {[
                  { step: 1, title: 'Cadastre mercados', desc: 'Adicione os supermercados da região', done: (stats?.total_supermarkets ?? 0) > 0 },
                  { step: 2, title: 'Adicione produtos', desc: 'Cadastre os produtos base para busca', done: (stats?.total_products ?? 0) > 0 },
                  { step: 3, title: 'Acompanhe preços', desc: 'Moradores reportam e você monitora', done: (stats?.total_prices ?? 0) > 0 },
                ].map(s => (
                  <div key={s.step} className={`flex items-start gap-3 p-3 rounded-lg ${s.done ? 'bg-white/60' : 'bg-white'}`}>
                    <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${
                      s.done ? 'bg-green-500 text-white' : 'bg-white border-2 border-orange-300 text-orange-500'
                    }`}>
                      {s.done ? <CheckCircle2 size={16} /> : s.step}
                    </div>
                    <div>
                      <p className={`text-sm font-medium ${s.done ? 'text-gray-400 line-through' : 'text-gray-800'}`}>{s.title}</p>
                      <p className="text-xs text-gray-400">{s.desc}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
          <DashboardTab stats={stats!} />
        </div>
      )}
      {activeTab === 'users' && <UsersTab users={topUsers} />}
      {activeTab === 'prices' && <PricesTab prices={recentPrices} />}
      {activeTab === 'products' && (
        <ProductsTab
          stats={stats!}
          onAdd={() => setShowAddProduct(true)}
        />
      )}
      {activeTab === 'markets' && (
        <MarketsTab
          markets={supermarkets}
          onAdd={() => setShowAddMarket(true)}
          onDelete={handleDeleteMarket}
        />
      )}
      {activeTab === 'push' && (
        <PushTab
          title={pushTitle}
          body={pushBody}
          sending={pushSending}
          userCount={topUsers.length}
          onTitleChange={setPushTitle}
          onBodyChange={setPushBody}
          onSend={handleSendPush}
        />
      )}

      {/* Add Market Modal */}
      {showAddMarket && (
        <Modal onClose={() => setShowAddMarket(false)} title="🏪 Novo Mercado">
          <input placeholder="Nome do mercado" value={newMarketName} onChange={e => setNewMarketName(e.target.value)}
            className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931] outline-none text-sm" />
          <input placeholder="CNPJ (opcional)" value={newMarketCnpj} onChange={e => setNewMarketCnpj(e.target.value)}
            className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931] outline-none text-sm mt-3" />
          <input placeholder="Endereço (opcional)" value={newMarketAddr} onChange={e => setNewMarketAddr(e.target.value)}
            className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931] outline-none text-sm mt-3" />
          <button onClick={handleAddMarket}
            className="w-full mt-4 px-4 py-2.5 bg-[#FC5931] text-white rounded-xl font-medium hover:bg-[#e04e28] transition-colors">
            Salvar
          </button>
        </Modal>
      )}

      {/* Add Product Modal */}
      {showAddProduct && (
