// ── Main List ─────────────────────────────────────────────────────────────────

export default function ParcelList({ initialParcels, isPorter, userId, condoId, tipoEstrutura, allBlocos, allAptosMap }: Props) {
  const supabase = createClient()

  const [parcels, setParcels] = useState<Parcel[]>(initialParcels)
  const [statusFilter, setStatusFilter] = useState<'all' | 'pending' | 'delivered'>('all')
  const [blocoFilter, setBlocoFilter] = useState('')
  const [aptoFilter, setAptoFilter] = useState('')
  const [page, setPage] = useState(1)
  const [photoModal, setPhotoModal] = useState<string | null>(null)
  const [deliveryModal, setDeliveryModal] = useState<Parcel | null>(null)
  const [silentDischargeModal, setSilentDischargeModal] = useState<Parcel | null>(null)
  const [mounted, setMounted] = useState(false)

  // Server-side fetch state (porter/admin mode)
  const [loading, setLoading] = useState(isPorter)
  const [totalFiltered, setTotalFiltered] = useState(0)
  const [pendingStat, setPendingStat] = useState(0)
  const [deliveredStat, setDeliveredStat] = useState(0)
  const fetchIdRef = useRef(0)

  useEffect(() => { requestAnimationFrame(() => setMounted(true)) }, [])

  const PER_PAGE = 10
  const numSort = (a: string, b: string) => a.localeCompare(b, 'pt', { numeric: true })

  // Use server-provided blocos/aptos when available, fallback to parcel-derived
  const uniqueBlocos = allBlocos ?? [...new Set(
    parcels.map(p => p.bloco ?? p.perfil?.bloco_txt).filter(Boolean) as string[]
  )].sort(numSort)
  const uniqueAptos = blocoFilter && allAptosMap?.[blocoFilter]
    ? allAptosMap[blocoFilter]
    : [...new Set(
        parcels
          .filter(p => !blocoFilter || (p.bloco ?? p.perfil?.bloco_txt) === blocoFilter)
          .map(p => p.apto ?? p.perfil?.apto_txt)
          .filter(Boolean) as string[]
      )].sort(numSort)

  // ── Server-side fetch (porter/admin mode) ───────────────────────────────────

  const fetchParcels = useCallback(async (
    status: 'all' | 'pending' | 'delivered',
    bloco: string,
    apto: string,
    pageNum: number
  ) => {
    const fetchId = ++fetchIdRef.current
    setLoading(true)

    try {
      const from = (pageNum - 1) * PER_PAGE
      const to = from + PER_PAGE - 1

      // Main data query with count
      let query = supabase
        .from('encomendas')
        .select(PARCEL_FIELDS, { count: 'exact' })
        .eq('condominio_id', condoId)
        .order('created_at', { ascending: false })

      if (status !== 'all') query = query.eq('status', status)
      if (bloco) query = query.eq('bloco', bloco)
      if (apto) query = query.eq('apto', apto)

      // Stats queries — filtered by bloco/apto but NOT by status
      let pendingQ = supabase.from('encomendas')
        .select('*', { count: 'exact', head: true })
        .eq('condominio_id', condoId)
        .eq('status', 'pending')
      let deliveredQ = supabase.from('encomendas')
        .select('*', { count: 'exact', head: true })
        .eq('condominio_id', condoId)
        .eq('status', 'delivered')

      if (bloco) {
        pendingQ = pendingQ.eq('bloco', bloco)
        deliveredQ = deliveredQ.eq('bloco', bloco)
      }
      if (apto) {
        pendingQ = pendingQ.eq('apto', apto)
        deliveredQ = deliveredQ.eq('apto', apto)
      }

      // Execute all in parallel
      const [dataResult, pendingResult, deliveredResult] = await Promise.all([
        query.range(from, to),
        pendingQ,
        deliveredQ,
      ])

      // Race condition guard
      if (fetchId !== fetchIdRef.current) return

      const { data, count, error } = dataResult
      if (error) console.error('❌ fetch parcels error:', error)

      // Resolve resident names
      const parcelsData = (data ?? []) as Record<string, unknown>[]
      const residentIds = [...new Set(parcelsData.map(p => p.resident_id as string).filter(Boolean))]
      const perfilMap: Record<string, Perfil> = {}

      if (residentIds.length > 0) {
        const { data: perfis } = await supabase
          .from('perfil')
          .select('id, nome_completo, bloco_txt, apto_txt')
          .in('id', residentIds)
        ;(perfis ?? []).forEach((p: Perfil) => { perfilMap[p.id] = p })
      }

      // Race condition guard
      if (fetchId !== fetchIdRef.current) return

      const parcelsWithResident = parcelsData.map(p => ({
        ...p,
        perfil: perfilMap[(p.resident_id as string)] ?? null,
      })) as Parcel[]

      setParcels(parcelsWithResident)
      setTotalFiltered(count ?? 0)
      setPendingStat(pendingResult.count ?? 0)
      setDeliveredStat(deliveredResult.count ?? 0)
    } catch (err) {
      console.error('❌ fetchParcels error:', err)
    } finally {
      if (fetchId === fetchIdRef.current) setLoading(false)
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [condoId])

  // Fetch on mount and filter change (porter/admin mode)
  useEffect(() => {
    if (isPorter) {
      fetchParcels(statusFilter, blocoFilter, aptoFilter, page)
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [statusFilter, blocoFilter, aptoFilter, page, isPorter])

  // ── Compute display data ──────────────────────────────────────────────────

  // Porter mode: parcels state already contains server-filtered + paginated results
  // Resident mode: client-side filtering from initialParcels
  const filtered = isPorter
    ? parcels
    : parcels.filter(p => {
        if (statusFilter === 'pending'   && p.status !== 'pending')   return false
        if (statusFilter === 'delivered' && p.status !== 'delivered') return false
        if (blocoFilter && (p.bloco ?? p.perfil?.bloco_txt) !== blocoFilter) return false
        if (aptoFilter  && (p.apto ?? p.perfil?.apto_txt)  !== aptoFilter)  return false
        return true
      })

  const totalPages = isPorter
    ? Math.max(1, Math.ceil(totalFiltered / PER_PAGE))
    : Math.max(1, Math.ceil(filtered.length / PER_PAGE))

  const paginated = isPorter
    ? filtered  // Already paginated from server
    : filtered.slice((page - 1) * PER_PAGE, page * PER_PAGE)

  const pending   = isPorter ? pendingStat   : parcels.filter(p => p.status === 'pending').length
  const delivered  = isPorter ? deliveredStat : parcels.filter(p => p.status === 'delivered').length
  const total      = isPorter ? (pendingStat + deliveredStat) : parcels.length

  // ── Dar Baixa confirm ──────────────────────────────────────────────────────

  async function handleDeliveryConfirm(
    parcel: Parcel,
    pickedById: string | null,
    pickedByName: string
  ) {
    const now = new Date().toISOString()
    const { error } = await supabase
      .from('encomendas')
      .update({
        status: 'delivered',
        picked_up_by_id: pickedById,
        picked_up_by_name: pickedByName || null,
        discharged_by: userId,
      })
      .eq('id', parcel.id)

    if (error) {
      alert('Erro ao dar baixa: ' + error.message)
      return
    }

    // Optimistic update in local state + refresh from server for porter mode
    setParcels(prev => prev.map(p =>
      p.id === parcel.id
        ? { ...p, status: 'delivered', delivery_time: now, picked_up_by_id: pickedById, picked_up_by_name: pickedByName }
        : p
    ))
    setDeliveryModal(null)

    // Refresh stats from server in porter mode
    if (isPorter) {
      fetchParcels(statusFilter, blocoFilter, aptoFilter, page)
    }
  }

  // ── Silent Discharge (Baixa Silenciosa) ─────────────────────────────────────

  async function handleSilentDischarge(parcel: Parcel) {
    const now = new Date().toISOString()
    const { error } = await supabase
      .from('encomendas')
      .update({
        status: 'delivered',
        silent_discharge: true,
        discharged_by: userId,
      })
      .eq('id', parcel.id)

    if (error) {
      alert('Erro ao dar baixa silenciosa: ' + error.message)
      return
    }

    // Optimistic update
    setParcels(prev => prev.map(p =>
      p.id === parcel.id
        ? { ...p, status: 'delivered', delivery_time: now }
        : p
    ))
    setSilentDischargeModal(null)

    if (isPorter) {
      fetchParcels(statusFilter, blocoFilter, aptoFilter, page)
    }
  }

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <>
      {/* Photo lightbox */}
      {photoModal && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4" onClick={() => setPhotoModal(null)}>
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={photoModal} alt="Foto da encomenda" className="max-w-full max-h-full rounded-2xl shadow-2xl" />
          <button className="absolute top-4 right-4 text-white p-2 bg-white/10 rounded-xl hover:bg-white/20" title="Fechar foto" onClick={() => setPhotoModal(null)}>
            <X size={22} />
          </button>
        </div>
      )}

      {/* Delivery modal */}
      {deliveryModal && (
        <DeliveryModal
          parcel={deliveryModal}
          condoId={condoId}
          tipoEstrutura={tipoEstrutura}
          onClose={() => setDeliveryModal(null)}
          onConfirm={handleDeliveryConfirm}
        />
      )}

      {/* Silent discharge confirmation modal */}
      {silentDischargeModal && (
        <SilentDischargeModal
          parcel={silentDischargeModal}
          tipoEstrutura={tipoEstrutura}
          onClose={() => setSilentDischargeModal(null)}
          onConfirm={handleSilentDischarge}
        />
      )}

      {/* Stats */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        {[
          { label: 'Total', value: total, color: 'text-gray-900' },
          { label: 'Aguardando', value: pending, color: 'text-[#FC5931]' },
          { label: 'Entregues', value: delivered, color: 'text-green-600' },
        ].map(s => (
          <div key={s.label} className="bg-white rounded-2xl border border-gray-100 shadow-sm p-4 text-center">
            <p className="text-xs text-gray-500 mb-1">{s.label}</p>
            <p className={`text-2xl font-bold ${s.color}`}>{s.value}</p>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-3 mb-5">
        <div className="flex rounded-xl border border-gray-200 overflow-hidden bg-white shadow-sm">
          {(['all', 'pending', 'delivered'] as const).map(f => (
            <button
              key={f}
              onClick={() => { setStatusFilter(f); setPage(1) }}
              className={`px-4 py-2 text-sm font-medium transition-colors ${
                statusFilter === f ? 'bg-[#FC5931] text-white' : 'text-gray-500 hover:bg-gray-50'
              }`}
            >
              {f === 'all' ? '• Todos' : f === 'pending' ? 'Aguardando' : 'Entregues'}
            </button>
          ))}
        </div>

        {isPorter && (
          <>
            <select
              value={blocoFilter}
              onChange={e => { setBlocoFilter(e.target.value); setAptoFilter(''); setPage(1) }}
              aria-label="Filtrar por bloco"
              className="px-3 py-2 border border-gray-200 rounded-xl text-sm bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931]"
            >
              <option value="">{getBlocoLabel(tipoEstrutura)}</option>
              {[...uniqueBlocos].sort((a, b) => a.localeCompare(b, 'pt', { numeric: true })).map(b => <option key={b} value={b}>{b}</option>)}
            </select>
            <select
              value={aptoFilter}
              onChange={e => { setAptoFilter(e.target.value); setPage(1) }}
              aria-label="Filtrar por apartamento"
              className="px-3 py-2 border border-gray-200 rounded-xl text-sm bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931]"
            >
              <option value="">{getAptoLabel(tipoEstrutura)}</option>
              {[...uniqueAptos].sort((a, b) => a.localeCompare(b, 'pt', { numeric: true })).map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </>
        )}

        <div className="ml-auto flex items-center gap-2 text-xs text-gray-400">
          {loading ? (
            <Loader2 size={12} className="animate-spin" />
          ) : (
            <RefreshCw size={12} />
          )}
          {isPorter ? totalFiltered : filtered.length} encomenda{(isPorter ? totalFiltered : filtered.length) !== 1 ? 's' : ''}
        </div>
      </div>

      {/* Loading overlay */}
      {loading ? (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-12 text-center">
          <Loader2 size={32} className="text-[#FC5931] mx-auto mb-3 animate-spin" />
          <p className="text-gray-400 text-sm">Carregando encomendas...</p>
        </div>
      ) : paginated.length === 0 ? (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-12 text-center">
          <Package size={40} className="text-gray-200 mx-auto mb-3" />
          <p className="text-gray-400 text-sm">Nenhuma encomenda encontrada.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {paginated.map(p => {
            const info = TIPO_LABELS[p.tipo ?? ''] ?? TIPO_LABELS['pacote']
            const Icon = info.icon
            const isDelivered = p.status === 'delivered'

            return (
              <div
                key={p.id}
                className={`bg-white rounded-2xl border shadow-sm overflow-hidden transition-all ${
                  isDelivered ? 'border-gray-100 opacity-80' : 'border-gray-100 hover:shadow-md'
                }`}
              >
                {/* Card header */}
                <div className={`flex items-center justify-between px-5 py-3 ${
                  isDelivered ? 'bg-green-50' : 'bg-[#FC5931]'
                }`}>
                  <div className="flex items-center gap-3">
                    <div className={`w-9 h-9 rounded-xl flex items-center justify-center ${
                      isDelivered ? 'bg-green-100' : 'bg-white/15'
                    }`}>
                      <Icon size={17} className={isDelivered ? 'text-green-600' : 'text-white'} />
                    </div>
                    <div>
                      <p className={`font-bold text-sm ${isDelivered ? 'text-gray-900' : 'text-white'}`}>
                        {getBlocoLabel(tipoEstrutura)} {p.bloco ?? p.perfil?.bloco_txt ?? '?'} / {getAptoLabel(tipoEstrutura)} {p.apto ?? p.perfil?.apto_txt ?? '?'}
                      </p>
                      <p className={`text-xs ${isDelivered ? 'text-gray-500' : 'text-white/70'}`}>
                        {p.perfil?.nome_completo ?? 'Sem morador'}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`text-xs font-semibold px-2.5 py-1 rounded-full ${info.color}`}>
                      {info.label}
                    </span>
                  </div>
                </div>

                {/* Card body */}
                <div className="px-5 py-4">
                  {/* Top row: info on left, photos on right */}
                  <div className="flex gap-4">
                    {/* Left: arrival info, tracking, obs */}
                    <div className="flex-1 grid grid-cols-2 gap-x-6 gap-y-2 text-sm">
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Chegada</p>
                        <p suppressHydrationWarning className="font-medium text-gray-700">{mounted ? fmt(p.arrival_time) : '—'}</p>
                      </div>
                      {p.tracking_code && (
                        <div>
                          <p className="text-xs text-gray-400 mb-0.5">Rastreio</p>
                          <p className="font-mono text-gray-700 text-xs">{p.tracking_code}</p>
                        </div>
                      )}
                      {p.observacao && (
                        <div className="col-span-2">
                          <p className="text-xs text-gray-400 mb-0.5">Observação</p>
                          <p className="text-gray-700">{p.observacao}</p>
                        </div>
                      )}
                    </div>

                    {/* Right: photo + signature thumbnails – stacked on mobile, side by side on ≥860px */}
                    <div className="flex flex-col min-[860px]:flex-row gap-1.5 shrink-0">
                      {/* Photo thumbnail */}
                      <button
                        onClick={() => p.photo_url ? setPhotoModal(p.photo_url) : null}
                        className={`w-14 h-14 rounded-xl overflow-hidden border-2 transition-colors shadow-sm flex items-center justify-center ${
                          p.photo_url ? 'border-gray-200 hover:border-[#FC5931]' : 'border-dashed border-gray-200 bg-gray-50'
                        }`}
                        title={p.photo_url ? 'Ver foto da encomenda' : 'Sem foto'}
                      >
                        {p.photo_url ? (
                          /* eslint-disable-next-line @next/next/no-img-element */
                          <img src={p.photo_url} alt="Foto" className="w-full h-full object-cover" />
                        ) : (
                          <Camera size={18} className="text-gray-300" />
                        )}
                      </button>

                      {/* Signature thumbnail (only for delivered) */}
                      {isDelivered && (
                        <button
                          onClick={() => p.pickup_proof_url ? setPhotoModal(p.pickup_proof_url) : null}
                          className={`w-14 h-14 rounded-xl overflow-hidden border-2 transition-colors shadow-sm flex items-center justify-center ${
                            p.pickup_proof_url ? 'border-green-200 hover:border-green-500' : 'border-dashed border-gray-200 bg-gray-50'
                          }`}
                          title={p.pickup_proof_url ? 'Ver assinatura' : 'Sem assinatura'}
                        >
                          {p.pickup_proof_url ? (
                            /* eslint-disable-next-line @next/next/no-img-element */
                            <img src={p.pickup_proof_url} alt="Assinatura" className="w-full h-full object-cover" />
                          ) : (
                            <PenTool size={18} className="text-gray-300" />
                          )}
                        </button>
                      )}
                    </div>
                  </div>

                  {/* Bottom row: status + buttons */}
                  <div className="flex items-end justify-between gap-3 mt-3">
                    <div className="flex-1">
                      {isDelivered ? (
                        <div className="space-y-1.5">
                          <div className="flex items-center gap-1.5 text-green-600 text-sm font-medium">
                            <CheckCircle2 size={15} />
                            <span suppressHydrationWarning>Retirado {mounted && p.delivery_time ? fmt(p.delivery_time) : ''}</span>
                          </div>
                          {(p.picked_up_by_name) && (
                            <div className="inline-flex items-center gap-1.5 bg-green-50 border border-green-200 rounded-lg px-2.5 py-1">
                              <UserCheck size={13} className="text-green-600 shrink-0" />
                              <span className="text-xs font-semibold text-green-700">{p.picked_up_by_name}</span>
                            </div>
                          )}
                        </div>
                      ) : (
                        <div className="flex items-center gap-1.5 text-[#FC5931] text-sm font-medium">
                          <Clock size={15} />
                          <span>Aguardando retirada</span>
                        </div>
                      )}
                    </div>

                    {/* Buttons stacked vertically (same width) */}
                    {!isDelivered && isPorter && (
                      <div className="flex flex-col gap-1.5 shrink-0" style={{ minWidth: '140px' }}>
                        <button
                          onClick={() => setDeliveryModal(p)}
                          className="flex items-center justify-center gap-1.5 bg-green-600 hover:bg-green-700 text-white text-xs font-semibold w-full py-2 rounded-xl transition-colors shadow-sm"
                        >
                          <UserCheck size={14} />
                          Dar Baixa
                        </button>
                        <button
                          onClick={() => setSilentDischargeModal(p)}
                          title="Baixa silenciosa (sem notificar morador)"
                          className="flex items-center justify-center gap-1.5 bg-amber-500 hover:bg-amber-600 text-white text-xs font-semibold w-full py-2 rounded-xl transition-colors shadow-sm"
                        >
                          <PackageCheck size={14} />
                          Baixa Silenciosa
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      )}

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-center gap-2 mt-6">
          <button
            disabled={page === 1}
            onClick={() => setPage(p => p - 1)}
            className="px-4 py-2 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50 disabled:opacity-40 transition-colors"
          >
            Anterior
          </button>
          <span className="text-sm text-gray-500">{page} / {totalPages}</span>
          <button
            disabled={page === totalPages}
            onClick={() => setPage(p => p + 1)}
            className="px-4 py-2 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50 disabled:opacity-40 transition-colors"
          >
            Próxima
          </button>
        </div>
      )}
    </>
  )
}

'use client'
import { useState, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { X, ChevronRight, BarChart3, ListOrdered } from 'lucide-react'

/* ================================================================
   Types
   ================================================================ */

interface Opcao {
  id: string
  texto: string
  ordem: number
}

interface Enquete {
  id: string
  pergunta: string
  tipo_resposta: 'unica' | 'multipla'
  validade: string | null
  created_at: string
  enquete_opcoes: Opcao[]
}

interface Props {
  enquetes: Enquete[]
  unitRespostas: { enquete_id: string; opcao_id: string; created_at: string }[]
  allRespostas: { enquete_id: string; opcao_id: string }[]
  userId: string
  bloco: string
  apto: string
}

/* ================================================================
   Component
   ================================================================ */

export default function EnquetesMoradorClient({
  enquetes,
  unitRespostas: initialUnitRespostas,
  allRespostas: initialAllRespostas,
  userId,
  bloco,
  apto,
}: Props) {
  const supabase = createClient()
  const router = useRouter()

  // Track unit responses locally
  const [unitRespostas, setUnitRespostas] = useState(initialUnitRespostas)
  const [allRespostas, setAllRespostas] = useState(initialAllRespostas)

  // Modal state
  const [openEnquete, setOpenEnquete] = useState<Enquete | null>(null)
  const [selected, setSelected] = useState<Set<string>>(new Set())
  const [sending, setSending] = useState(false)
  const [showResult, setShowResult] = useState(false)

  // ── Helpers ──────────────────────────────────────────────
  function isExpired(enquete: Enquete): boolean {
    if (!enquete.validade) return false
    return new Date(enquete.validade) < new Date(new Date().toDateString())
  }

  function unitVotedFor(enqueteId: string): string[] {
    return unitRespostas
      .filter(r => r.enquete_id === enqueteId)
      .map(r => r.opcao_id)
  }

  function hasUnitVoted(enqueteId: string): boolean {
    return unitRespostas.some(r => r.enquete_id === enqueteId)
  }

  function fmtDate(d: string): string {
    try {
      return new Date(d).toLocaleDateString('pt-BR')
    } catch {
      return d
    }
  }

  // ── Chart data for an enquete ────────────────────────────
  function chartDataFor(enquete: Enquete) {
    const opcoes = [...(enquete.enquete_opcoes ?? [])].sort((a, b) => a.ordem - b.ordem)
    const counts: Record<string, number> = {}
    for (const r of allRespostas) {
      if (r.enquete_id === enquete.id) {
        counts[r.opcao_id] = (counts[r.opcao_id] || 0) + 1
      }
    }
    const total = opcoes.reduce((s, o) => s + (counts[o.id] || 0), 0)
    return { opcoes, counts, total }
  }

  // ── Open enquete modal ───────────────────────────────────
  function openModal(enquete: Enquete) {
    const voted = unitVotedFor(enquete.id)
    setOpenEnquete(enquete)
    setSelected(new Set(voted))
    setShowResult(voted.length > 0)
  }

  // ── Handle selection ─────────────────────────────────────
  function handleSelect(opcaoId: string) {
    if (!openEnquete) return
    if (openEnquete.tipo_resposta === 'unica') {
      setSelected(new Set([opcaoId]))
    } else {
      setSelected(prev => {
        const next = new Set(prev)
        if (next.has(opcaoId)) next.delete(opcaoId)
        else next.add(opcaoId)
        return next
      })
    }
  }

  // ── Submit vote ──────────────────────────────────────────
  async function handleSubmit() {
    if (!openEnquete || selected.size === 0) return
    setSending(true)

    try {
      // Delete previous responses for this unit
      await supabase
        .from('enquete_respostas')
        .delete()
        .eq('enquete_id', openEnquete.id)
        .eq('bloco', bloco)
        .eq('apto', apto)

      // Insert new responses
      const rows = Array.from(selected).map(opcaoId => ({
        enquete_id: openEnquete.id,
        opcao_id: opcaoId,
        user_id: userId,
        bloco,
        apto,
      }))

      const { error } = await supabase
        .from('enquete_respostas')
        .insert(rows)

      if (error) {
        alert('Erro ao enviar voto: ' + error.message)
      } else {
        // Update local state
        setUnitRespostas(prev => {
          const filtered = prev.filter(r => r.enquete_id !== openEnquete!.id)
          const newRows = rows.map(r => ({
            enquete_id: r.enquete_id,
            opcao_id: r.opcao_id,
            created_at: new Date().toISOString(),
          }))
          return [...filtered, ...newRows]
        })
        // Update all respostas for chart
        setAllRespostas(prev => {
          const filtered = prev.filter(r =>
            !(r.enquete_id === openEnquete!.id &&
              unitRespostas.some(u => u.enquete_id === openEnquete!.id && u.opcao_id === r.opcao_id))
          )
          const newRows = rows.map(r => ({
            enquete_id: r.enquete_id,
            opcao_id: r.opcao_id,
          }))
          return [...filtered, ...newRows]
        })
        setShowResult(true)
      }
    } catch (e) {
      alert('Erro: ' + e)
    } finally {
      setSending(false)
    }
  }

  // ── Revote ───────────────────────────────────────────────
  function handleRevote() {
    setShowResult(false)
  }

  // ── Enquete numbering ────────────────────────────────────
  const enqueteNumbers = useMemo(() => {
    const map: Record<string, number> = {}
    enquetes.forEach((e, i) => { map[e.id] = enquetes.length - i })
    return map
  }, [enquetes])

  // ════════════════════════════════════════════════════════════
  //  RENDER
  // ════════════════════════════════════════════════════════════

  return (
    <div className="max-w-3xl mx-auto space-y-4">
      <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
        <BarChart3 size={24} className="text-[#FC5931]" />
        Enquetes
      </h1>

      {enquetes.length === 0 && (
        <div className="text-center py-16 text-gray-400">
          <BarChart3 size={48} className="mx-auto mb-3 opacity-30" />
          <p>Nenhuma enquete ativa no momento.</p>
        </div>
      )}

      {/* ── LIST ──────────────────────────────────── */}
      {enquetes.map(enquete => {
        const expired = isExpired(enquete)
        const voted = hasUnitVoted(enquete.id)

        return (
          <div key={enquete.id}>
            {/* Date header */}
            <p className="text-sm text-gray-500 font-medium mb-2">
              Data da enquete: {fmtDate(enquete.created_at)}
            </p>

            {/* Card */}
            <button
              onClick={() => openModal(enquete)}
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all duration-150 text-left ${
                expired
                  ? 'bg-[#FC5931] text-white shadow-md shadow-[#FC5931]/20'
                  : voted
                    ? 'bg-green-50 border-2 border-green-200 text-gray-800 hover:shadow-md'
                    : 'bg-white border border-gray-200 text-gray-800 hover:shadow-md hover:border-gray-300'
              }`}
            >
              <ListOrdered size={28} className={expired ? 'text-white/80' : 'text-[#FC5931]'} />
              <div className="flex-1 min-w-0">
                <p className={`text-xs font-medium ${expired ? 'text-white/70' : 'text-gray-400'}`}>
                  Pergunta:
                </p>
                <p className={`text-sm font-semibold truncate ${expired ? 'text-white' : ''}`}>
                  {enquete.pergunta}
                </p>
              </div>
              <div className="text-right flex-shrink-0">
                <p className={`text-xs font-medium ${expired ? 'text-white/70' : 'text-gray-400'}`}>
                  Validade:
                </p>
                <p className={`text-sm font-semibold ${expired ? 'text-white' : ''}`}>
                  {enquete.validade ? fmtDate(enquete.validade) : '—'}
                </p>
              </div>
              <ChevronRight size={24} className={`flex-shrink-0 ${expired ? 'text-white' : 'text-green-500'}`} />
            </button>
          </div>
        )
      })}

      {/* ── MODAL ─────────────────────────────────── */}
      {openEnquete && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl max-w-lg w-full max-h-[90vh] overflow-y-auto relative">
            {/* Header */}
            <div className="flex justify-between items-start p-6 pb-3 border-b border-gray-100">
              <div>
                <p className="text-sm text-gray-500 font-medium">
                  Enquete de Número:
                </p>
                <p className="text-sm font-bold text-gray-800">
                  {enqueteNumbers[openEnquete.id]}ª enquete
                </p>
              </div>
              <div className="text-right">
                <p className="text-sm text-gray-500 font-medium">
                  Enquete válida até o dia:
                </p>
                <p className="text-sm font-bold text-gray-800">
                  {openEnquete.validade ? fmtDate(openEnquete.validade) : '—'}
                </p>
              </div>
              <button
                onClick={() => { setOpenEnquete(null); setShowResult(false) }}
                className="ml-2 text-red-500 hover:text-red-700 flex-shrink-0"
              >
                <X size={22} />
              </button>
            </div>

            {/* Content */}
            <div className="p-6 space-y-4">
              {/* Pergunta */}
              <div className="bg-gray-50 rounded-xl p-4 border border-gray-100">
                <p className="text-xs font-semibold text-gray-500 mb-1">Pergunta:</p>
                <p className="text-sm text-gray-800 font-medium">{openEnquete.pergunta}</p>
              </div>

              {/* Opções */}
              <div>
                <p className="text-xs font-semibold text-gray-500 mb-2">Opções de respostas:</p>
                <div className="space-y-2">
                  {[...(openEnquete.enquete_opcoes ?? [])].sort((a, b) => a.ordem - b.ordem).map(opcao => {
                    const isSelected = selected.has(opcao.id)
                    const isUnica = openEnquete.tipo_resposta === 'unica'
                    const disabled = showResult && !isExpired(openEnquete)

                    return (
                      <label
                        key={opcao.id}
                        className={`flex items-center gap-3 px-4 py-3 rounded-xl border cursor-pointer transition-all ${
                          isSelected
                            ? 'border-[#FC5931] bg-[#FC5931]/5'
                            : 'border-gray-200 hover:border-gray-300'
                        } ${disabled ? 'opacity-60 pointer-events-none' : ''}`}
                      >
                        <input
                          type={isUnica ? 'radio' : 'checkbox'}
                          name={`enquete-${openEnquete.id}`}
                          checked={isSelected}
                          onChange={() => handleSelect(opcao.id)}
                          className="w-4 h-4 accent-[#FC5931]"
                          disabled={disabled}
                        />
                        <span className="text-sm text-gray-700">{opcao.texto}</span>
                      </label>
                    )
                  })}
                </div>
              </div>

              {/* ── After voting ─────────────────────────── */}
              {showResult ? (
                <div className="space-y-4">
                  {/* Confirmation */}
                  <div className="text-center py-2">
                    <p className="text-base font-bold text-gray-800">Obrigado!</p>
                    <p className="text-sm text-gray-600">
                      Seu apto já respondeu a pesquisa.
                    </p>
                    <p className="text-xs text-gray-400 mt-1">
                      Até a validade da enquete, seu apto poderá responder novamente.
                    </p>
                  </div>

                  {/* Last unit response */}
                  <div className="bg-gray-50 rounded-xl p-3 border border-gray-100">
                    <p className="text-xs font-bold text-gray-600">
                      Última(s) resposta(s) do seu APTO:{' '}
                      <span className="text-gray-800">
                        {(() => {
                          const voted = unitVotedFor(openEnquete.id)
                          const opcoes = openEnquete.enquete_opcoes ?? []
                          return opcoes
                            .filter(o => voted.includes(o.id))
                            .map(o => o.texto)
                            .join(', ')
                        })()}
                      </span>
                    </p>
                  </div>

                  {/* Revote button */}
                  {!isExpired(openEnquete) && (
                    <div className="text-center">
                      <button
                        onClick={handleRevote}
                        className="px-6 py-2.5 bg-gray-600 text-white rounded-xl text-sm font-semibold hover:bg-gray-700 transition-colors"
                      >
                        Responder novamente
                      </button>
                    </div>
                  )}

                  {/* Partial chart */}
                  <div>
                    <p className="text-sm font-bold text-gray-700 text-center mb-3">
                      Resultado parcial da enquete:
                    </p>
                    <EnqueteBarChart enquete={openEnquete} allRespostas={allRespostas} />
                  </div>
                </div>
              ) : (
                /* Submit button */
                <button
                  onClick={handleSubmit}
                  disabled={selected.size === 0 || sending || isExpired(openEnquete)}
                  className="w-full py-3 bg-gray-500 text-white rounded-xl font-semibold text-sm hover:bg-gray-600 disabled:opacity-40 transition-colors"
                >
                  {sending ? 'Enviando...' : isExpired(openEnquete) ? 'Enquete encerrada' : 'Responder'}
                </button>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

/* ================================================================
   Bar Chart Component
   ================================================================ */

function EnqueteBarChart({
  enquete,
  allRespostas,
}: {
  enquete: Enquete
  allRespostas: { enquete_id: string; opcao_id: string }[]
}) {
  const opcoes = [...(enquete.enquete_opcoes ?? [])].sort((a, b) => a.ordem - b.ordem)
  const counts: Record<string, number> = {}
  for (const r of allRespostas) {
    if (r.enquete_id === enquete.id) {
      counts[r.opcao_id] = (counts[r.opcao_id] || 0) + 1
    }
  }
  const maxVal = Math.max(...opcoes.map(o => counts[o.id] || 0), 1)
  const colors = ['#FC5931', '#3B82F6', '#10B981', '#F59E0B', '#8B5CF6', '#EC4899', '#14B8A6', '#F97316']

  return (
    <div className="bg-gray-50 rounded-xl p-4 border border-gray-100">
      {/* Title */}
      <p className="text-xs font-semibold text-gray-600 text-center mb-3 leading-snug">
        {enquete.pergunta}
      </p>
      {/* Bars */}
      <div className="flex items-end gap-3 justify-center" style={{ minHeight: 120 }}>
        {opcoes.map((o, i) => {
          const val = counts[o.id] || 0
          const heightPct = maxVal > 0 ? (val / maxVal) * 100 : 0
          const color = colors[i % colors.length]
          return (
            <div key={o.id} className="flex flex-col items-center gap-1" style={{ flex: 1, maxWidth: 60 }}>
              <span className="text-xs font-bold text-gray-600">{val}</span>
              <div
                className="w-full rounded-t-lg transition-all duration-500"
                style={{
                  height: `${Math.max(heightPct, 4)}px`,
                  minHeight: 4,
                  maxHeight: 100,
                  backgroundColor: color,
                }}
              />
              <span className="text-[10px] font-semibold text-gray-500 mt-1">
                Resp {i + 1}
              </span>
            </div>
          )
        })}
      </div>

      {/* Legend */}
      <div className="mt-4 space-y-1 border-t border-gray-200 pt-3">
        {opcoes.map((o, i) => (
          <div key={o.id} className="flex items-center gap-2 text-xs text-gray-600">
            <div
              className="w-3 h-3 rounded-sm flex-shrink-0"
              style={{ backgroundColor: colors[i % colors.length] }}
            />
            <span className="font-semibold">Resp {i + 1}:</span>
            <span className="truncate">{o.texto}</span>
          </div>
        ))}
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { createClient } from '@/lib/supabase/client'
import { MessageSquare, Plus, ChevronRight, Send, X, ArrowLeft, Paperclip } from 'lucide-react'

// ─── Types ───────────────────────────────────────────────────────────────────

type Thread = {
  id: string
  tipo: string
  assunto: string
  status: string
  ultima_mensagem_em: string
  created_at: string
}

type Mensagem = {
  id: string
  sender_id: string
  is_admin: boolean
  texto: string
  arquivo_url: string | null
  created_at: string
}

// ─── Constants ────────────────────────────────────────────────────────────────

const TIPO_CONFIG: Record<string, { label: string; emoji: string; color: string; bg: string }> = {
  reclamacao: { label: 'Reclamação',  emoji: '⚠️', color: 'text-red-700',    bg: 'bg-red-50 border-red-200' },
  elogio:     { label: 'Elogio',      emoji: '👏', color: 'text-green-700',  bg: 'bg-green-50 border-green-200' },
  pendencia:  { label: 'Pendência',   emoji: '📋', color: 'text-orange-700', bg: 'bg-orange-50 border-orange-200' },
  sugestao:   { label: 'Sugestão',    emoji: '💡', color: 'text-blue-700',   bg: 'bg-blue-50 border-blue-200' },
  duvida:     { label: 'Dúvida',      emoji: '❓', color: 'text-purple-700', bg: 'bg-purple-50 border-purple-200' },
}

const STATUS_CONFIG: Record<string, { label: string; dot: string }> = {
  aberto:     { label: 'Aguardando', dot: 'bg-amber-400' },
  respondido: { label: 'Respondido', dot: 'bg-emerald-500' },
  fechado:    { label: 'Fechado',    dot: 'bg-gray-400' },
}

function formatTime(dateStr: string) {
  const d = new Date(dateStr)
  const now = new Date()
  const diffDays = Math.floor((now.getTime() - d.getTime()) / 86400000)
  if (diffDays === 0) return d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
  if (diffDays === 1) return 'Ontem'
  if (diffDays < 7) return d.toLocaleDateString('pt-BR', { weekday: 'short' })
  return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })
}

function formatFull(dateStr: string) {
  return new Date(dateStr).toLocaleString('pt-BR', {
    day: '2-digit', month: '2-digit', year: '2-digit',
    hour: '2-digit', minute: '2-digit',
  })
}

