// ─── Chat View ────────────────────────────────────────────────────────────────

function ChatView({
  thread,
  userId,
  onBack,
  onStatusUpdate,
}: {
  thread: Thread
  userId: string
  onBack: () => void
  onStatusUpdate: (id: string, status: string) => void
}) {
  const [mensagens, setMensagens] = useState<Mensagem[]>([])
  const [loading, setLoading] = useState(true)
  const [text, setText] = useState('')
  const [sending, setSending] = useState(false)
  const bottomRef = useRef<HTMLDivElement>(null)
  const tipo = TIPO_CONFIG[thread.tipo] ?? TIPO_CONFIG.duvida
  const status = STATUS_CONFIG[thread.status] ?? STATUS_CONFIG.aberto

  useEffect(() => {
    loadMessages()
    const supabase = createClient()
    // Realtime: escuta novas mensagens nesta thread
    const channel = supabase
      .channel(`chat-${thread.id}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'fale_sindico_mensagens',
          filter: `thread_id=eq.${thread.id}`,
        },
        (payload) => {
          const nova = payload.new as Mensagem
          setMensagens(prev => {
            // evita duplicatas (se a msg já foi inserida otimisticamente)
            if (prev.find(m => m.id === nova.id)) return prev
            return [...prev, nova]
          })
        }
      )
      .subscribe()
    return () => { supabase.removeChannel(channel) }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [thread.id])

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [mensagens])

  async function loadMessages() {
    setLoading(true)
    const supabase = createClient()
    const { data } = await supabase
      .from('fale_sindico_mensagens')
      .select('id, sender_id, is_admin, texto, arquivo_url, created_at')
      .eq('thread_id', thread.id)
      .order('created_at', { ascending: true })
    setMensagens(data ?? [])
    setLoading(false)
  }

  async function handleSend() {
    if (!text.trim() || sending) return
    setSending(true)
    const supabase = createClient()
    const { data: { user: cu } } = await supabase.auth.getUser()
    const now = new Date().toISOString()

    const { data: inserted, error } = await supabase
      .from('fale_sindico_mensagens')
      .insert({
        thread_id: thread.id,
        sender_id: cu?.id ?? userId,
        is_admin: false,
        texto: text.trim(),
      })
      .select()
      .single()

    if (!error && inserted) {
      // Update thread ultima_mensagem_at
      await supabase
        .from('fale_sindico_threads')
        .update({ ultima_mensagem_em: now, status: 'aberto' })
        .eq('id', thread.id)

      setMensagens(prev => [...prev, inserted])
      setText('')
    }
    setSending(false)
  }

  return (
    <div className="flex flex-col h-[calc(100vh-12rem)] bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
      {/* Header */}
      <div className="flex items-center gap-3 px-5 py-4 border-b border-gray-100 bg-white">
        <button
          onClick={onBack}
          className="p-1.5 rounded-xl hover:bg-gray-100 transition-colors text-gray-500"
        >
          <ArrowLeft size={18} />
        </button>
        <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg flex-shrink-0 border ${tipo.bg}`}>
          {tipo.emoji}
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-bold text-gray-900 text-sm truncate">{thread.assunto}</p>
          <div className="flex items-center gap-1.5">
            <div className={`w-1.5 h-1.5 rounded-full ${status.dot}`} />
            <span className="text-xs text-gray-500">{tipo.label} · {status.label}</span>
          </div>
        </div>
      </div>

      {/* Messages area */}
      <div className="flex-1 overflow-y-auto px-5 py-4 space-y-3"
        style={{ background: 'linear-gradient(180deg, #f9fafb 0%, #f3f4f6 100%)' }}
      >
        {loading ? (
          <div className="flex items-center justify-center h-full">
            <div className="w-6 h-6 border-2 border-[#FC5931]/30 border-t-[#FC5931] rounded-full animate-spin" />
          </div>
        ) : mensagens.length === 0 ? (
          <div className="text-center py-8">
            <p className="text-4xl mb-3">💬</p>
            <p className="text-sm text-gray-400">Nenhuma mensagem ainda. Inicie a conversa!</p>
          </div>
        ) : (
          mensagens.map((msg) => {
            const isOwn = !msg.is_admin
            return (
              <div key={msg.id} className={`flex ${isOwn ? 'justify-end' : 'justify-start'}`}>
                <div
                  className={`max-w-[75%] rounded-2xl px-4 py-2.5 shadow-sm ${
                    isOwn
                      ? 'bg-[#FC5931] text-white rounded-br-sm'
                      : 'bg-white text-gray-800 rounded-bl-sm border border-gray-100'
                  }`}
                >
                  {msg.is_admin && (
                    <p className="text-xs font-semibold text-[#FC5931] mb-1">Síndico/Adm</p>
                  )}
                  <p className="text-sm leading-relaxed">{msg.texto}</p>
                  <p className={`text-[10px] mt-1 ${isOwn ? 'text-white/60' : 'text-gray-400'}`}>
                    {formatFull(msg.created_at)}
                  </p>
                </div>
              </div>
            )
          })
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div className="px-4 py-3 border-t border-gray-100 bg-white flex items-end gap-2">
        <textarea
          value={text}
          onChange={e => setText(e.target.value)}
          onKeyDown={e => {
            if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend() }
          }}
          placeholder="Digite sua mensagem..."
          rows={1}
          className="flex-1 resize-none border border-gray-200 rounded-2xl px-4 py-2.5 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931] transition-all max-h-32 overflow-y-auto"
          style={{ lineHeight: '1.5' }}
        />
        <button
          onClick={handleSend}
          disabled={sending || !text.trim()}
          className="w-10 h-10 bg-[#FC5931] text-white rounded-2xl flex items-center justify-center hover:bg-[#D42F1D] transition-colors disabled:opacity-40 disabled:cursor-not-allowed flex-shrink-0 shadow-sm shadow-[#FC5931]/30"
        >
          {sending
            ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            : <Send size={16} />
          }
        </button>
      </div>
    </div>
  )
}

// ─── New Thread Modal ─────────────────────────────────────────────────────────

function NewThreadModal({
  onClose,
  onCreated,
  userId,
  condoId,
}: {
  onClose: () => void
  onCreated: (thread: Thread, firstMsg: string) => void
  userId: string
  condoId: string
}) {
  const [tipo, setTipo] = useState('reclamacao')
  const [assunto, setAssunto] = useState('')
  const [mensagem, setMensagem] = useState('')
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit() {
    if (!assunto.trim() || !mensagem.trim()) {
      setError('Preencha o assunto e a mensagem para continuar.')
      return
    }
    setSaving(true)
    setError('')
    const supabase = createClient()
    const { data: { user: cu } } = await supabase.auth.getUser()
    const now = new Date().toISOString()

    // Create thread
    const { data: thread, error: te } = await supabase
      .from('fale_sindico_threads')
      .insert({
        condominio_id: condoId,
        resident_id: cu?.id ?? userId,
        tipo,
        assunto: assunto.trim(),
        status: 'aberto',
        ultima_mensagem_em: now,
      })
      .select()
      .single()

    if (te || !thread) {
      setError('Erro ao criar conversa. Tente novamente.')
      setSaving(false)
      return
    }

    // Create first message
    await supabase.from('fale_sindico_mensagens').insert({
      thread_id: thread.id,
      sender_id: cu?.id ?? userId,
      is_admin: false,
      texto: mensagem.trim(),
    })

    onCreated(thread, mensagem.trim())
  }

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div
        className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden"
        style={{ animation: 'modalIn 0.2s ease-out' }}
      >
        <style>{`@keyframes modalIn { from { opacity:0; transform: scale(0.96) translateY(8px) } to { opacity:1; transform: scale(1) translateY(0) } }`}</style>

        {/* Header */}
        <div className="flex items-center justify-between px-6 py-5 border-b border-gray-100">
          <div>
            <h2 className="text-lg font-bold text-gray-900">Novo Assunto</h2>
            <p className="text-xs text-gray-400 mt-0.5">Envie uma mensagem à administração</p>
          </div>
          <button
            onClick={onClose}
            className="w-8 h-8 rounded-xl flex items-center justify-center text-gray-400 hover:bg-gray-100 hover:text-gray-600 transition-colors"
          >
            <X size={16} />
          </button>
        </div>

        <div className="px-6 py-5 flex flex-col gap-5">
          {/* Tipo */}
          <div>
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider block mb-2">
              Tipo de assunto
            </label>
            <div className="flex flex-wrap gap-2">
              {Object.entries(TIPO_CONFIG).map(([key, cfg]) => (
                <button
                  key={key}
                  onClick={() => setTipo(key)}
                  className={`flex items-center gap-1.5 text-sm px-3 py-1.5 rounded-xl border font-medium transition-all ${
                    tipo === key
                      ? `${cfg.bg} ${cfg.color} border-current`
                      : 'bg-gray-50 text-gray-500 border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <span>{cfg.emoji}</span>
                  <span>{cfg.label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Assunto */}
          <div>
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider block mb-2">
              Assunto
            </label>
            <input
              value={assunto}
              onChange={e => setAssunto(e.target.value)}
              placeholder="Ex: Barulho excessivo no corredor"
              maxLength={120}
              className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931] transition-all"
            />
          </div>

          {/* Mensagem */}
          <div>
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider block mb-2">
              Sua mensagem
            </label>
            <textarea
              value={mensagem}
              onChange={e => setMensagem(e.target.value)}
              rows={4}
              placeholder="Descreva o que aconteceu ou o que você precisa..."
              className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931] transition-all"
            />
          </div>

          {error && <p className="text-sm text-red-600 bg-red-50 px-4 py-2.5 rounded-xl border border-red-100">{error}</p>}
        </div>

        <div className="px-6 py-4 border-t border-gray-100 flex gap-3 justify-end">
          <button
            onClick={onClose}
            className="text-sm font-medium px-5 py-2.5 rounded-xl border border-gray-200 text-gray-600 hover:bg-gray-50 transition-colors"
          >
            Cancelar
          </button>
          <button
            onClick={handleSubmit}
            disabled={saving}
            className="flex items-center gap-2 bg-[#FC5931] text-white text-sm font-semibold px-6 py-2.5 rounded-xl hover:bg-[#D42F1D] transition-colors disabled:opacity-40 shadow-sm shadow-[#FC5931]/30"
          >
            {saving ? (
              <><div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> Enviando...</>
            ) : (
              <><Send size={14} /> Enviar</>
            )}
          </button>
        </div>
      </div>
    </div>
  )
}

// ─── Main Component ───────────────────────────────────────────────────────────

export default function FaleSindicoClient({
  initialThreads,
  userId,
  condoId,
  userName,
}: {
  initialThreads: Thread[]
  userId: string
  condoId: string
  userName: string
}) {
  const [threads, setThreads] = useState<Thread[]>(initialThreads)
  const [selectedThread, setSelectedThread] = useState<Thread | null>(null)
  const [showModal, setShowModal] = useState(false)
  const [filter, setFilter] = useState<'todos' | 'aberto' | 'respondido'>('todos')

  const filtered = threads.filter(t => {
    if (filter === 'aberto') return t.status === 'aberto'
    if (filter === 'respondido') return t.status === 'respondido'
    return true
  })

  const pending = threads.filter(t => t.status === 'aberto').length

  function handleCreated(thread: Thread) {
    setThreads(prev => [thread, ...prev])
    setShowModal(false)
    setSelectedThread(thread)
  }

  if (selectedThread) {
    return (
      <ChatView
        thread={selectedThread}
        userId={userId}
        onBack={() => setSelectedThread(null)}
        onStatusUpdate={(id, status) =>
          setThreads(prev => prev.map(t => t.id === id ? { ...t, status } : t))
        }
      />
    )
  }

  return (
    <div>
      {/* Toolbar */}
      <div className="flex items-center justify-between mb-5 gap-3 flex-wrap">
        <div className="flex items-center gap-2 flex-wrap">
          {[
            { key: 'todos',      label: `Todos (${threads.length})` },
            { key: 'aberto',     label: `Aguardando${pending > 0 ? ` (${pending})` : ''}` },
            { key: 'respondido', label: 'Respondidos' },
          ].map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setFilter(key as typeof filter)}
              className={`text-sm font-medium px-4 py-2 rounded-xl border transition-all ${
                filter === key
                  ? 'bg-[#FC5931] text-white border-[#FC5931] shadow-sm shadow-[#FC5931]/20'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-[#FC5931]/50 hover:text-[#FC5931]'
              }`}
            >
              {label}
            </button>
          ))}
        </div>

        <button
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-[#FC5931] text-white text-sm font-semibold px-5 py-2.5 rounded-xl hover:bg-[#D42F1D] transition-colors shadow-sm shadow-[#FC5931]/30"
        >
          <Plus size={16} />
          Novo Assunto
        </button>
      </div>

      {/* Thread list */}
      {filtered.length === 0 ? (
        <div className="text-center py-20 text-gray-400">
          <MessageSquare size={40} className="mx-auto mb-3 opacity-30" />
          <p className="font-medium text-gray-500 mb-1">Nenhuma conversa aqui</p>
          <p className="text-sm">Clique em &quot;Novo Assunto&quot; para falar com a administração</p>
        </div>
      ) : (
        <div className="flex flex-col gap-3">
          {filtered.map(thread => (
            <ThreadCard
              key={thread.id}
              thread={thread}
              onClick={() => setSelectedThread(thread)}
            />
          ))}
        </div>
      )}

      {/* Modal */}
      {showModal && (
        <NewThreadModal
          onClose={() => setShowModal(false)}
          onCreated={handleCreated}
          userId={userId}
          condoId={condoId}
        />
      )}
    </div>
  )
}

'use client'
import { useState, useRef } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Star, Plus, X, Phone, MessageCircle, MapPin, User, Search, ChevronDown } from 'lucide-react'

const ESPECIALIDADES = [
  'Advocacia', 'Agronomia', 'Arquitetura', 'Chaveiro', 'Dedetização',
  'Eletricista', 'Encanador', 'Estética', 'Fisioterapeuta', 'Jardinagem',
  'Marceneiro', 'Mecânico', 'Médico', 'Nutricionista', 'Pedreiro',
  'Personal Trainer', 'Pintor', 'Psicólogo', 'Serralheiro',
  'TI / Informática', 'Outros',
]

const ESPECIALIDADE_EMOJI: Record<string, string> = {
  'Advocacia': '⚖️', 'Agronomia': '🌱', 'Arquitetura': '🏛️',
  'Chaveiro': '🔑', 'Dedetização': '🪲', 'Eletricista': '⚡',
  'Encanador': '🔧', 'Estética': '💅', 'Fisioterapeuta': '🦴',
  'Jardinagem': '🌿', 'Marceneiro': '🪵', 'Mecânico': '🔩',
  'Médico': '🩺', 'Nutricionista': '🥗', 'Pedreiro': '🧱',
  'Personal Trainer': '🏋️', 'Pintor': '🎨', 'Psicólogo': '🧠',
  'Serralheiro': '⛓️', 'TI / Informática': '💻', 'Outros': '🌟',
}

interface Indicacao {
  id: string
  nome: string
  whatsapp: string | null
  especialidade: string
  uf: string | null
  cidade: string | null
  observacoes: string | null
  foto_url: string | null
  created_at: string
  criador: { nome_completo: string } | null
}

interface Avaliacao {
  id: string
  indicacao_id: string
  usuario_id: string
  nota: number
  comentario: string | null
}

interface Props {
  indicacoes: Indicacao[]
  avaliacoes: Avaliacao[]
  condoId: string
  currentUserId: string
  currentUserName: string
}

function StarRow({ value, onChange, size = 24 }: { value: number; onChange?: (n: number) => void; size?: number }) {
  const [hovered, setHovered] = useState(0)
  return (
    <div className="flex gap-1">
      {[1,2,3,4,5].map(n => (
        <button
          key={n}
          type="button"
          onClick={() => onChange?.(n)}
          onMouseEnter={() => onChange && setHovered(n)}
          onMouseLeave={() => onChange && setHovered(0)}
          className={onChange ? 'cursor-pointer' : 'cursor-default'}
          title={`${n} estrela${n > 1 ? 's' : ''}`}
        >
          <Star
            size={size}
            className={`transition-colors ${(hovered || value) >= n ? 'fill-amber-400 text-amber-400' : 'fill-gray-200 text-gray-200'}`}
          />
        </button>
      ))}
    </div>
  )
}

function openWhatsApp(phone: string) {
  const cleaned = phone.replace(/\D/g, '')
  const num = cleaned.startsWith('55') ? cleaned : `55${cleaned}`
  window.open(`https://wa.me/${num}`, '_blank')
}

export default function IndicacoesClient({
  indicacoes: initialIndicacoes,
  avaliacoes: initialAvaliacoes,
  condoId,
  currentUserId,
  currentUserName,
}: Props) {
  const supabase = createClient()
  const [indicacoes, setIndicacoes] = useState(initialIndicacoes)
  const [avaliacoes, setAvaliacoes] = useState(initialAvaliacoes)

  // ── Filters ──────────────────────────────────────────────────────────────
  const [filterEsp, setFilterEsp] = useState('')
  const [filterSearch, setFilterSearch] = useState('')

  const filtered = indicacoes.filter(i => {
    const matchEsp = !filterEsp || i.especialidade === filterEsp
    const matchSearch = !filterSearch || i.nome.toLowerCase().includes(filterSearch.toLowerCase())
    return matchEsp && matchSearch
  })

  // ── Rating modal ─────────────────────────────────────────────────────────
  const [ratingTarget, setRatingTarget] = useState<Indicacao | null>(null)
  const [ratingStars, setRatingStars] = useState(0)
  const [ratingComment, setRatingComment] = useState('')
  const [ratingLoading, setRatingLoading] = useState(false)

  function openRatingModal(ind: Indicacao) {
    const myAv = avaliacoes.find(a => a.indicacao_id === ind.id && a.usuario_id === currentUserId)
    setRatingStars(myAv?.nota ?? 0)
    setRatingComment(myAv?.comentario ?? '')
    setRatingTarget(ind)
  }

  async function submitRating() {
    if (!ratingTarget || ratingStars === 0) return
    setRatingLoading(true)
    const { error } = await supabase
      .from('indicacoes_avaliacoes')
      .upsert({
        indicacao_id: ratingTarget.id,
        usuario_id: currentUserId,
        nota: ratingStars,
        comentario: ratingComment.trim() || null,
      }, { onConflict: 'indicacao_id,usuario_id' })
    if (!error) {
      // refresh local state
      const { data: fresh } = await supabase
        .from('indicacoes_avaliacoes')
        .select('*')
        .in('indicacao_id', indicacoes.map(i => i.id))
      setAvaliacoes(fresh ?? [])
      setRatingTarget(null)
    }
    setRatingLoading(false)
  }

  // ── New indicação modal ───────────────────────────────────────────────────
  const [showNew, setShowNew] = useState(false)
  const [newNome, setNewNome] = useState('')
  const [newWhatsapp, setNewWhatsapp] = useState('')
  const [newUf, setNewUf] = useState('')
  const [newCidade, setNewCidade] = useState('')
  const [newEsp, setNewEsp] = useState('')
  const [newEspSearch, setNewEspSearch] = useState('')
  const [showEspDropdown, setShowEspDropdown] = useState(false)
  const [newObs, setNewObs] = useState('')
  const [newFotoFile, setNewFotoFile] = useState<File | null>(null)
  const [newFotoPreview, setNewFotoPreview] = useState('')
  const [newLoading, setNewLoading] = useState(false)
  const [newError, setNewError] = useState('')
  const fileRef = useRef<HTMLInputElement>(null)

  const filteredEsps = ESPECIALIDADES.filter(e =>
    e.toLowerCase().includes(newEspSearch.toLowerCase())
  )

  function resetNew() {
    setShowNew(false); setNewNome(''); setNewWhatsapp(''); setNewUf(''); setNewCidade('')
    setNewEsp(''); setNewEspSearch(''); setNewObs(''); setNewFotoFile(null)
    setNewFotoPreview(''); setNewError('')
  }

  async function handleCreate() {
    if (!newNome.trim()) { setNewError('Informe o nome do profissional.'); return }
    if (!newEsp) { setNewError('Selecione a especialidade.'); return }
    setNewError(''); setNewLoading(true)

    let foto_url: string | null = null
    if (newFotoFile) {
      const ext = newFotoFile.name.split('.').pop()
      const path = `indicacoes/${condoId}/${Date.now()}.${ext}`
      const { error: upErr } = await supabase.storage.from('community').upload(path, newFotoFile)
      if (!upErr) {
        const { data: pub } = supabase.storage.from('community').getPublicUrl(path)
        foto_url = pub.publicUrl
      }
    }

    const { data: inserted, error } = await supabase
      .from('indicacoes_servico')
      .insert({
        condominio_id: condoId,
        criado_por: currentUserId,
        nome: newNome.trim(),
        whatsapp: newWhatsapp.trim() || null,
        especialidade: newEsp,
        uf: newUf.trim() || null,
        cidade: newCidade.trim() || null,
        observacoes: newObs.trim() || null,
        foto_url,
      })
      .select('*, criador:perfil!criado_por(nome_completo)')
      .single()

    if (error) { setNewError('Erro: ' + error.message); setNewLoading(false); return }

    // Push notification
    try {
      const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
      const anonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
      if (supabaseUrl && anonKey) {
        fetch(`${supabaseUrl}/functions/v1/indicacoes-notify`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${anonKey}` },
          body: JSON.stringify({ condominio_id: condoId, indicacao_id: inserted.id }),
        }).catch(console.error)
      }
    } catch (_) { /* silent */ }

    setIndicacoes(prev => [inserted, ...prev])
    resetNew()
    setNewLoading(false)
  }

  // ── Helpers ───────────────────────────────────────────────────────────────
  function getAvgRating(id: string) {
    const avs = avaliacoes.filter(a => a.indicacao_id === id)
    if (!avs.length) return null
    return { avg: avs.reduce((s, a) => s + a.nota, 0) / avs.length, count: avs.length }
  }

  function getMyRating(id: string) {
    return avaliacoes.find(a => a.indicacao_id === id && a.usuario_id === currentUserId)
  }

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div className="max-w-4xl mx-auto">
      {/* Header */}
      <div className="mb-6 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            🌟 Indicações de Serviço
          </h1>
          <p className="text-sm text-gray-500 mt-1">Profissionais, lojas e empresas recomendados pelos moradores</p>
        </div>
        <button
          onClick={() => setShowNew(true)}
          className="flex items-center gap-2 bg-[#FC5931] text-white px-5 py-2.5 rounded-xl font-semibold text-sm hover:bg-[#D42F1D] transition-all shadow-lg shadow-[#FC5931]/20"
        >
          <Plus size={18} /> Indicar
        </button>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-3 mb-6">
        <div className="relative flex-1 min-w-[200px]">
          <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            type="text"
            value={filterSearch}
            onChange={e => setFilterSearch(e.target.value)}
            placeholder="Buscar por nome..."
            className="w-full border border-gray-200 rounded-xl pl-9 pr-3 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
          />
        </div>
        <select
          value={filterEsp}
          onChange={e => setFilterEsp(e.target.value)}
          className="border border-gray-200 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] bg-white min-w-[160px]"
          title="Filtrar por especialidade"
        >
          <option value="">Todas especialidades</option>
          {ESPECIALIDADES.map(e => <option key={e} value={e}>{ESPECIALIDADE_EMOJI[e]} {e}</option>)}
        </select>
      </div>

      {/* Cards */}
      <div className="space-y-4">
        {filtered.length === 0 ? (
          <div className="bg-white rounded-2xl border border-gray-100 p-14 text-center shadow-sm">
            <div className="text-5xl mb-3">🌟</div>
            <p className="text-gray-400 font-medium">Nenhuma indicação ainda</p>
            <p className="text-gray-300 text-sm mt-1">Seja o primeiro a indicar um profissional!</p>
          </div>
        ) : (
          filtered.map(ind => {
            const rating = getAvgRating(ind.id)
            const myRating = getMyRating(ind.id)
            const emoji = ESPECIALIDADE_EMOJI[ind.especialidade] ?? '🌟'

            return (
              <div key={ind.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow overflow-hidden">
                <div className="p-5">
                  <div className="flex gap-4">
                    {/* Photo */}
                    <div className="shrink-0">
                      {ind.foto_url ? (
                        <img src={ind.foto_url} alt={ind.nome} className="w-16 h-16 rounded-2xl object-cover border-2 border-gray-100" />
                      ) : (
                        <div className="w-16 h-16 rounded-2xl bg-linear-to-br from-[#FC5931]/10 to-[#FC5931]/20 flex items-center justify-center border-2 border-[#FC5931]/10 text-2xl">
                          {emoji}
                        </div>
                      )}
                    </div>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2 flex-wrap">
                        <div>
                          <h3 className="font-bold text-gray-900 text-base">{ind.nome}</h3>
                          <span className="inline-flex items-center gap-1 text-xs font-semibold px-2.5 py-0.5 rounded-full bg-[#FC5931]/10 text-[#FC5931] mt-1">
                            {emoji} {ind.especialidade}
                          </span>
                        </div>
                        {ind.whatsapp && (
                          <button
                            onClick={() => openWhatsApp(ind.whatsapp!)}
                            className="flex items-center gap-1.5 bg-green-500 hover:bg-green-600 text-white text-xs font-semibold px-3 py-1.5 rounded-xl transition-colors shadow-sm shadow-green-500/30"
                            title="Falar com o indicado via WhatsApp"
                          >
                            <MessageCircle size={14} /> WhatsApp
                          </button>
                        )}
                      </div>

                      {/* Location */}
                      {(ind.uf || ind.cidade) && (
                        <p className="flex items-center gap-1 text-sm text-gray-500 mt-2">
                          <MapPin size={13} className="text-gray-400 shrink-0" />
                          {[ind.uf, ind.cidade].filter(Boolean).join(' / ')}
                        </p>
                      )}

                      {/* Obs */}
                      {ind.observacoes && (
                        <p className="text-sm text-gray-500 mt-1.5 line-clamp-2">{ind.observacoes}</p>
                      )}

                      {/* Who recommended */}
                      <p className="flex items-center gap-1 text-xs text-gray-400 mt-2">
                        <User size={11} />
                        Indicado por <span className="font-medium text-gray-600 ml-0.5">{ind.criador?.nome_completo ?? 'Morador'}</span>
                      </p>
                    </div>
                  </div>

                  {/* Rating section */}
                  <div className="mt-4 pt-4 border-t border-gray-50 flex items-center justify-between flex-wrap gap-3">
                    <div className="space-y-1">
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-gray-400 font-medium w-28">Minha avaliação:</span>
                        <StarRow value={myRating?.nota ?? 0} size={16} />
                      </div>
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-gray-400 font-medium w-28">Avaliação geral:</span>
                        <StarRow value={rating ? Math.round(rating.avg) : 0} size={16} />
                        {rating && (
                          <span className="text-xs text-gray-400">
                            {rating.avg.toFixed(1)} ({rating.count})
                          </span>
                        )}
                      </div>
                    </div>
                    <button
                      onClick={() => openRatingModal(ind)}
                      className="flex items-center gap-1.5 border-2 border-[#FC5931] text-[#FC5931] hover:bg-[#FC5931] hover:text-white text-sm font-semibold px-4 py-1.5 rounded-xl transition-all"
                    >
                      <Star size={14} />
                      {myRating ? 'Reavaliar' : 'Avaliar'}
                    </button>
                  </div>
                </div>
              </div>
            )
          })
        )}
      </div>

      {/* ── Rating Modal ──────────────────────────────────────── */}
      {ratingTarget && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-sm shadow-2xl">
            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
              <h2 className="text-base font-bold text-gray-900">Avaliar indicação</h2>
              <button onClick={() => setRatingTarget(null)} className="text-gray-400 hover:text-gray-600" title="Fechar">
                <X size={20} />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <p className="font-semibold text-gray-700">{ratingTarget.nome}</p>
              <div>
                <p className="text-sm text-gray-500 mb-2">Sua avaliação</p>
                <StarRow value={ratingStars} onChange={setRatingStars} size={32} />
              </div>
              <textarea
                value={ratingComment}
                onChange={e => setRatingComment(e.target.value)}
                placeholder="Opcional: Escreva aqui seu comentário."
                rows={4}
                className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30 resize-none"
              />
              <button
                onClick={submitRating}
                disabled={ratingStars === 0 || ratingLoading}
                className="w-full bg-[#FC5931] hover:bg-[#D42F1D] text-white font-bold py-3 rounded-xl transition-all disabled:opacity-50"
              >
                {ratingLoading ? 'Salvando...' : 'Avaliar'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── New Indicação Modal ───────────────────────────────── */}
      {showNew && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto">
            <div className="bg-[#FC5931] text-white px-6 py-4 rounded-t-2xl flex items-center justify-between">
              <h2 className="text-lg font-bold">Nova Indicação</h2>
              <button onClick={resetNew} className="text-white/80 hover:text-white" title="Fechar"><X size={22} /></button>
            </div>
            <div className="p-6 space-y-4">
              {/* Photo */}
              <div className="flex flex-col items-center">
                <button
                  type="button"
                  onClick={() => fileRef.current?.click()}
                  className="w-24 h-24 rounded-2xl border-2 border-dashed border-gray-300 hover:border-[#FC5931] transition-colors flex flex-col items-center justify-center gap-1 overflow-hidden"
                >
                  {newFotoPreview ? (
                    <img src={newFotoPreview} alt="preview" className="w-full h-full object-cover" />
                  ) : (
                    <>
                      <span className="text-2xl">📷</span>
                      <span className="text-xs text-gray-400">Foto (opcional)</span>
                    </>
                  )}
                </button>
                <input
                  ref={fileRef}
                  type="file"
                  accept="image/*"
                  className="hidden"
                  onChange={e => {
                    const f = e.target.files?.[0] ?? null
                    setNewFotoFile(f)
                    setNewFotoPreview(f ? URL.createObjectURL(f) : '')
                  }}
                />
              </div>

              {/* Nome */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">Nome do profissional / Loja *</label>
                <input
                  type="text"
                  value={newNome}
                  onChange={e => setNewNome(e.target.value)}
                  placeholder="Ex: João Eletricista"
                  className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                />
              </div>

              {/* WhatsApp */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">
                  WhatsApp <span className="font-normal text-gray-400">(para os vizinhos contatarem)</span>
                </label>
                <div className="relative">
                  <Phone size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                  <input
                    type="tel"
                    value={newWhatsapp}
                    onChange={e => setNewWhatsapp(e.target.value)}
                    placeholder="(XX) 9 9999-9999"
                    className="w-full border border-gray-200 rounded-xl pl-9 pr-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                  />
                </div>
              </div>

              {/* UF + Cidade */}
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">UF</label>
                  <input
                    type="text"
                    value={newUf}
                    onChange={e => setNewUf(e.target.value.toUpperCase().slice(0, 2))}
                    placeholder="SP"
                    maxLength={2}
                    className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">Cidade</label>
                  <input
                    type="text"
                    value={newCidade}
                    onChange={e => setNewCidade(e.target.value)}
                    placeholder="São Paulo"
                    className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                  />
                </div>
              </div>

              {/* Especialidade typeahead */}
              <div className="relative">
                <label className="block text-sm font-semibold text-gray-700 mb-1">Especialidade *</label>
                <div className="relative">
                  <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                  <input
                    type="text"
                    value={newEsp || newEspSearch}
                    onChange={e => {
                      setNewEsp('')
                      setNewEspSearch(e.target.value)
                      setShowEspDropdown(true)
                    }}
                    onFocus={() => setShowEspDropdown(true)}
                    placeholder="Escolha ou busque uma especialidade..."
                    className="w-full border border-gray-200 rounded-xl pl-9 pr-9 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                  />
                  <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                </div>
                {showEspDropdown && filteredEsps.length > 0 && (
                  <div className="absolute z-10 w-full mt-1 bg-white border border-gray-200 rounded-xl shadow-lg max-h-48 overflow-y-auto">
                    {filteredEsps.map(e => (
                      <button
                        key={e}
                        type="button"
                        onClick={() => {
                          setNewEsp(e)
                          setNewEspSearch(e)
                          setShowEspDropdown(false)
                        }}
                        className={`w-full text-left px-4 py-2.5 text-sm hover:bg-[#FC5931]/5 transition-colors ${newEsp === e ? 'bg-[#FC5931]/10 text-[#FC5931] font-semibold' : 'text-gray-700'}`}
                      >
                        {ESPECIALIDADE_EMOJI[e]} {e}
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {/* Observações */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">Observações <span className="font-normal text-gray-400">(opcional)</span></label>
                <textarea
                  value={newObs}
                  onChange={e => setNewObs(e.target.value)}
                  placeholder="Conte sua experiência com este profissional..."
                  rows={3}
                  className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30 resize-none"
                />
              </div>

              {newError && (
                <p className="text-sm text-red-600 bg-red-50 px-4 py-2.5 rounded-xl">{newError}</p>
              )}

              <button
                onClick={handleCreate}
                disabled={newLoading}
                className="w-full bg-[#FC5931] hover:bg-[#D42F1D] text-white font-bold py-3.5 rounded-xl transition-all disabled:opacity-60 shadow-lg shadow-[#FC5931]/20"
              >
                {newLoading ? 'Publicando...' : '🌟 Publicar Indicação'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'
import { useState, useTransition } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { Clock, CheckCircle, Users, Search, LogOut } from 'lucide-react'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

interface Visitante {
  id: string
  nome: string
  cpf_rg: string | null
  whatsapp: string | null
  tipo_visitante: string | null
  empresa: string | null
  bloco: string | null
  apto: string | null
  observacao: string | null
  foto_url: string | null
  entrada_at: string
  saida_at: string | null
  registrado_por: string | null
  created_at: string
}

type FilterTab = 'pendente' | 'todos' | 'liberados'

interface Props {
  visitantes: Visitante[]
  condoId: string
  userId: string
  tipoEstrutura?: string
}

export default function LiberarVisitanteClient({
  visitantes: initialVisitantes,
  condoId,
  userId,
  tipoEstrutura,
}: Props) {
  const router = useRouter()
  const supabase = createClient()
  const [isPending, startTransition] = useTransition()
  const [visitantes, setVisitantes] = useState(initialVisitantes)
  const [activeTab, setActiveTab] = useState<FilterTab>('pendente')
  const [search, setSearch] = useState('')

  // Filter by tab
  const filtered = visitantes.filter(v => {
    if (activeTab === 'pendente') return !v.saida_at
    if (activeTab === 'liberados') return !!v.saida_at
    return true // 'todos'
  }).filter(v => {
    if (!search.trim()) return true
    const q = search.toLowerCase()
    return (
      v.nome.toLowerCase().includes(q) ||
      (v.cpf_rg && v.cpf_rg.includes(q)) ||
      (v.bloco && v.bloco.toLowerCase().includes(q)) ||
      (v.apto && v.apto.toLowerCase().includes(q))
    )
  })

  const pendentesCount = visitantes.filter(v => !v.saida_at).length
  const liberadosCount = visitantes.filter(v => !!v.saida_at).length

  // Register exit
  async function handleRegistrarSaida(id: string) {
    startTransition(async () => {
      await supabase
        .from('visitante_registros')
        .update({ saida_at: new Date().toISOString() })
        .eq('id', id)
      setVisitantes(prev =>
        prev.map(v => v.id === id ? { ...v, saida_at: new Date().toISOString() } : v)
      )
    })
  }

  function fmtDate(iso: string) {
    const d = new Date(iso)
    return d.toLocaleDateString('pt-BR') + ' – ' + d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) + 'h'
  }

  const tabs: { key: FilterTab; label: string; count: number; icon: React.ReactNode; color: string }[] = [
    { key: 'pendente', label: 'Pendentes', count: pendentesCount, icon: <Clock size={16} />, color: 'bg-yellow-500' },
    { key: 'todos', label: 'Todos', count: visitantes.length, icon: <Users size={16} />, color: 'bg-blue-500' },
    { key: 'liberados', label: 'Liberados', count: liberadosCount, icon: <CheckCircle size={16} />, color: 'bg-green-500' },
  ]

  return (
    <div>
      {/* Header */}
      <div className="bg-[#FC5931] text-white text-center font-bold py-4 rounded-t-xl text-lg">
        Liberar Visitante Cadastrado
      </div>

      {/* Filter Tabs */}
      <div className="bg-white border-x border-gray-100 px-4 pt-4 pb-2">
        <div className="flex gap-2 mb-3">
          {tabs.map(tab => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold transition-all ${
                activeTab === tab.key
                  ? `${tab.color} text-white shadow-md`
                  : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              {tab.icon}
              {tab.label}
              <span className={`text-xs px-1.5 py-0.5 rounded-full ${
                activeTab === tab.key ? 'bg-white/20' : 'bg-gray-200'
              }`}>
                {tab.count}
              </span>
            </button>
          ))}
        </div>

        {/* Search */}
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            type="text"
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Buscar por nome, CPF/RG, bloco ou apto..."
            className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-lg text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
          />
        </div>
      </div>

      {/* Visitor List */}
      <div className="bg-white rounded-b-xl border border-gray-100 border-t-0 divide-y divide-gray-50">
        {filtered.length === 0 ? (
          <div className="py-16 text-center text-gray-400">
            <Users size={40} className="mx-auto mb-3 opacity-50" />
            <p className="font-medium">Nenhum visitante encontrado</p>
            <p className="text-sm mt-1">
              {activeTab === 'pendente' ? 'Não há visitantes com saída pendente.' :
               activeTab === 'liberados' ? 'Nenhum visitante liberado ainda.' :
               'Nenhum visitante registrado.'}
            </p>
          </div>
        ) : (
          filtered.map(v => (
            <div
              key={v.id}
              className="px-5 py-4 flex items-center gap-4 hover:bg-gray-50/50 transition-colors"
            >
              {/* Photo */}
              <div className="w-16 h-16 rounded-full bg-gray-200 overflow-hidden flex-shrink-0 ring-2 ring-gray-100">
                {v.foto_url ? (
                  <img src={v.foto_url} alt={v.nome} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-gray-400 text-2xl">👤</div>
                )}
              </div>

              {/* Info */}
              <div className="flex-1 min-w-0">
                <p className="font-bold text-gray-800 text-[15px]">
                  Visitante: {v.nome}
                </p>
                {(v.bloco || v.apto) && (
                  <p className="text-sm text-gray-500">
                    {getBlocoLabel(tipoEstrutura)}: {v.bloco || '−'} / {getAptoLabel(tipoEstrutura)}: {v.apto || '−'}
                  </p>
                )}
                <p className="text-sm text-gray-500">
                  <span className="font-medium">Entrada:</span> {fmtDate(v.entrada_at)}
                </p>
                {v.saida_at && (
                  <p className="text-sm text-gray-500">
                    <span className="font-medium">Saída:</span> {fmtDate(v.saida_at)}
                  </p>
                )}
                {v.tipo_visitante && (
                  <span className="inline-block mt-1 text-xs bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full">
                    {v.tipo_visitante}
                  </span>
                )}
              </div>

              {/* Action */}
              <div className="flex-shrink-0">
                {!v.saida_at ? (
                  <button
                    onClick={() => handleRegistrarSaida(v.id)}
                    disabled={isPending}
                    className="bg-red-500 hover:bg-red-600 text-white px-5 py-2.5 rounded-lg font-semibold text-sm transition-colors disabled:opacity-60 flex items-center gap-2 shadow-sm"
                  >
                    <LogOut size={16} />
                    Registrar Saída
                  </button>
                ) : (
                  <div className="bg-green-500 text-white px-5 py-2.5 rounded-lg text-sm font-semibold text-center min-w-[140px]">
                    <div className="flex items-center gap-1.5 justify-center">
                      <CheckCircle size={14} />
                      Saída Registrada
                    </div>
                    <div className="text-xs opacity-90 mt-0.5">
                      {new Date(v.saida_at!).toLocaleDateString('pt-BR')}
                    </div>
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      {/* Footer count */}
      {filtered.length > 0 && (
        <p className="text-center text-sm text-gray-400 mt-3">
          Exibindo {filtered.length} de {visitantes.length} visitante{visitantes.length !== 1 ? 's' : ''}
        </p>
      )}
    </div>
  )
}

'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'

type Perfil = {
  nome_completo: string
  bloco_txt: string | null
  apto_txt: string | null
}

type Occurrence = {
  id: string
  resident_id: string
  assunto: string | null
  description: string
  category: string
  status: string
  photo_url: string | null
  admin_response: string | null
  admin_response_at: string | null
  created_at: string
  perfil: Perfil | null
}

const CATEGORY_LABELS: Record<string, string> = {
  maintenance: 'Manutenção',
  security: 'Segurança',
  noise: 'Barulho',
  others: 'Outros',
}

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  pending: { label: 'Pendente', color: 'text-orange-700', bg: 'bg-orange-50 border-orange-200' },
  open: { label: 'Aberto', color: 'text-blue-700', bg: 'bg-blue-50 border-blue-200' },
  inProgress: { label: 'Em Andamento', color: 'text-yellow-700', bg: 'bg-yellow-50 border-yellow-200' },
  resolved: { label: 'Resolvido', color: 'text-green-700', bg: 'bg-green-50 border-green-200' },
  closed: { label: 'Fechado', color: 'text-gray-700', bg: 'bg-gray-50 border-gray-200' },
}

function formatDate(dateStr: string | null): string {
  if (!dateStr) return '—'
  return new Intl.DateTimeFormat('pt-BR', {
    day: '2-digit', month: '2-digit', year: '2-digit',
    hour: '2-digit', minute: '2-digit',
  }).format(new Date(dateStr))
}

function StatusBadge({ status }: { status: string }) {
  const cfg = STATUS_CONFIG[status] ?? STATUS_CONFIG.pending
  return (
    <span className={`text-xs font-semibold px-2.5 py-1 rounded-full border ${cfg.bg} ${cfg.color}`}>
      {cfg.label}
    </span>
  )
}

function OccurrenceCard({
  occ,
  number,
  isAdmin,
  onRespond,
}: {
  occ: Occurrence
  number: number
  isAdmin: boolean
  onRespond: (id: string, response: string) => Promise<void>
}) {
  const [isExpanded, setIsExpanded] = useState(false)
  const [responseText, setResponseText] = useState(occ.admin_response ?? '')
  const [saving, setSaving] = useState(false)
  const [saved, setSaved] = useState(false)

  const hasResponse = !!occ.admin_response

  const handleSave = async () => {
    if (!responseText.trim()) return
    setSaving(true)
    await onRespond(occ.id, responseText.trim())
    setSaving(false)
    setSaved(true)
    setTimeout(() => setSaved(false), 3000)
  }

  const residentLabel = occ.perfil
    ? `${occ.perfil.nome_completo}${occ.perfil.bloco_txt ? ` · ${occ.perfil.bloco_txt}/${occ.perfil.apto_txt}` : ''}`
    : 'Morador'

  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
      {/* Header */}
      <div
        className="flex items-center justify-between px-5 py-4 cursor-pointer hover:bg-gray-50 transition-colors"
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className="flex items-center gap-3 min-w-0">
          <span className="text-xs font-bold text-gray-400 shrink-0">#{number}</span>
          <div className="min-w-0">
            <p className="font-semibold text-gray-900 truncate">
              {occ.assunto || occ.description.substring(0, 50)}
            </p>
            <p className="text-xs text-gray-400 mt-0.5">
              {isAdmin ? residentLabel + ' · ' : ''}{CATEGORY_LABELS[occ.category] ?? occ.category} · {formatDate(occ.created_at)}
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 shrink-0 ml-3">
          <StatusBadge status={occ.status} />
          <svg
            className={`w-4 h-4 text-gray-400 transition-transform ${isExpanded ? 'rotate-180' : ''}`}
            fill="none" viewBox="0 0 24 24" stroke="currentColor"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        </div>
      </div>

      {/* Expanded Content */}
      {isExpanded && (
        <div className="border-t border-gray-100">
          {/* Descrição + Foto */}
          <div className="px-5 py-4">
            <p className="text-xs font-medium text-gray-500 uppercase tracking-wider mb-2">Ocorrência</p>
            <p className="text-gray-700 text-sm leading-relaxed">{occ.description}</p>

            {occ.photo_url && (
              <div className="mt-4">
                <a href={occ.photo_url} target="_blank" rel="noopener noreferrer">
                  <img
                    src={occ.photo_url}
                    alt="Foto da ocorrência"
                    className="w-full max-h-64 object-cover rounded-xl border border-gray-100 hover:opacity-90 transition-opacity cursor-zoom-in"
                  />
                </a>
                <p className="text-xs text-gray-400 mt-1">Clique para ampliar</p>
              </div>
            )}
          </div>

          {/* Seção de Resposta */}
          <div className={`px-5 pb-5 ${hasResponse ? 'bg-green-50/50' : 'bg-orange-50/30'}`}>
            {hasResponse && !isAdmin ? (
              // Morador lê a resposta
              <div className="border-t border-green-100 pt-4">
                <div className="flex items-center gap-2 mb-2">
                  <span className="text-green-600">✓</span>
                  <p className="text-xs font-medium text-green-700 uppercase tracking-wider">Resposta do Adm/Síndico</p>
                </div>
                <p className="text-gray-700 text-sm">{occ.admin_response}</p>
                <p className="text-xs text-gray-400 mt-2">Respondido em: {formatDate(occ.admin_response_at)}</p>
              </div>
            ) : isAdmin ? (
              // Admin responde
              <div className="border-t border-gray-100 pt-4">
                <p className="text-xs font-medium text-gray-500 uppercase tracking-wider mb-2">
                  {hasResponse ? 'Resposta enviada (editar)' : 'Responder ao morador'}
                </p>
                <textarea
                  value={responseText}
                  onChange={(e) => setResponseText(e.target.value)}
                  rows={3}
                  placeholder="Digite sua resposta para o morador..."
                  className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm text-gray-700 resize-none focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931] transition-all bg-white"
                />
                <div className="flex items-center justify-between mt-3">
                  {saved ? (
                    <span className="text-sm text-green-600 font-medium">✓ Resposta enviada!</span>
                  ) : (
                    <span />
                  )}
                  <button
                    onClick={handleSave}
                    disabled={saving || !responseText.trim()}
                    className="bg-[#FC5931] text-white text-sm font-semibold px-5 py-2 rounded-xl hover:bg-[#D42F1D] transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
                  >
                    {saving ? 'Enviando...' : hasResponse ? 'Atualizar Resposta' : 'Enviar Resposta'}
                  </button>
                </div>
              </div>
            ) : (
              <div className="border-t border-gray-100 pt-4">
                <p className="text-xs text-gray-400 italic">Aguardando resposta da administração...</p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

export default function OcorrenciasClient({
  initialOccurrences,
  isAdmin,
  userId,
  condoId,
}: {
  initialOccurrences: Occurrence[]
  isAdmin: boolean
  userId: string
  condoId: string
}) {
  const [occurrences, setOccurrences] = useState<Occurrence[]>(initialOccurrences)
  const [filter, setFilter] = useState<'all' | 'pending' | 'resolved'>('all')
  const [showModal, setShowModal] = useState(false)
  const [creating, setCreating] = useState(false)
  const [form, setForm] = useState({ assunto: '', description: '', category: 'maintenance' })
  const [photoFile, setPhotoFile] = useState<File | null>(null)
  const [photoPreview, setPhotoPreview] = useState<string | null>(null)

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] ?? null
    setPhotoFile(file)
    if (file) setPhotoPreview(URL.createObjectURL(file))
    else setPhotoPreview(null)
  }

  const handleCreate = async () => {
    if (!form.assunto.trim() || !form.description.trim()) return
    setCreating(true)
    const supabase = createClient()

    // Use browser session's actual auth.uid() to match RLS policy
    const { data: { user: currentUser } } = await supabase.auth.getUser()
    const residentId = currentUser?.id ?? userId

    const now = new Date().toISOString()
    const id = crypto.randomUUID()

    // Upload photo if selected
    let photoUrl: string | null = null
    if (photoFile) {
      const ext = photoFile.name.split('.').pop()
      const path = `${residentId}/${id}.${ext}`
      const { error: uploadError } = await supabase.storage
        .from('ocorrencias-fotos')
        .upload(path, photoFile, { upsert: true })
      if (!uploadError) {
        const { data } = supabase.storage.from('ocorrencias-fotos').getPublicUrl(path)
        photoUrl = data.publicUrl
      }
    }

    const { error } = await supabase.from('ocorrencias').insert({
      id,
      resident_id: residentId,
      condominio_id: condoId,
      assunto: form.assunto.trim(),
      description: form.description.trim(),
      category: form.category,
      status: 'pending',
      photo_url: photoUrl,
      created_at: now,
      updated_at: now,
    })
    setCreating(false)
    if (!error) {
      setOccurrences(prev => [{
        id, resident_id: residentId, assunto: form.assunto.trim(),
        description: form.description.trim(), category: form.category,
        status: 'pending', photo_url: photoUrl, admin_response: null,
        admin_response_at: null, created_at: now, perfil: null,
      }, ...prev])
      setForm({ assunto: '', description: '', category: 'maintenance' })
      setPhotoFile(null)
      setPhotoPreview(null)
      setShowModal(false)
    }
  }

  const handleRespond = async (occurrenceId: string, response: string) => {
    const supabase = createClient()
    const now = new Date().toISOString()
    const { error } = await supabase
      .from('ocorrencias')
      .update({
        admin_response: response,
        admin_response_at: now,
        status: 'resolved',
        updated_at: now,
      })
      .eq('id', occurrenceId)

    if (!error) {
      setOccurrences(prev =>
        prev.map(o =>
          o.id === occurrenceId
            ? { ...o, admin_response: response, admin_response_at: now, status: 'resolved' }
            : o
        )
      )
    }
  }

  const filtered = occurrences.filter(o => {
    if (filter === 'pending') return o.status !== 'resolved' && o.status !== 'closed'
    if (filter === 'resolved') return o.status === 'resolved' || o.status === 'closed'
    return true
  })

  const pendingCount = occurrences.filter(o => o.status !== 'resolved' && o.status !== 'closed').length

  return (
    <div>
      {/* Header com botão */}
      <div className="flex items-center justify-between mb-5 flex-wrap gap-3">
        <div className="flex items-center gap-2 flex-wrap">
          {[
            { key: 'all', label: `Todas (${occurrences.length})` },
            { key: 'pending', label: `Pendentes${pendingCount > 0 ? ` (${pendingCount})` : ''}` },
            { key: 'resolved', label: 'Resolvidas' },
          ].map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setFilter(key as typeof filter)}
              className={`text-sm font-medium px-4 py-2 rounded-xl border transition-all ${
                filter === key
                  ? 'bg-[#FC5931] text-white border-[#FC5931]'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-[#FC5931] hover:text-[#FC5931]'
              }`}
            >
              {label}
            </button>
          ))}
        </div>
        {!isAdmin && (
          <button
            onClick={() => setShowModal(true)}
            className="flex items-center gap-2 bg-[#FC5931] text-white text-sm font-semibold px-5 py-2.5 rounded-xl hover:bg-[#D42F1D] transition-colors shadow-sm"
          >
            + Nova Ocorrência
          </button>
        )}
      </div>

      {/* Lista */}
      {filtered.length === 0 ? (
        <div className="text-center py-16 text-gray-400">
          <p className="text-5xl mb-4">📋</p>
          <p className="font-medium">Nenhuma ocorrência encontrada</p>
        </div>
      ) : (
        <div className="flex flex-col gap-3">
          {filtered.map((occ, index) => (
            <OccurrenceCard
              key={occ.id}
              occ={occ}
              number={filtered.length - index}
              isAdmin={isAdmin}
              onRespond={handleRespond}
            />
          ))}
        </div>
      )}

      {/* Modal Nova Ocorrência */}
      {showModal && (
        <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md">
            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
              <h2 className="text-lg font-bold text-gray-900">Nova Ocorrência</h2>
              <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-600 text-xl">✕</button>
            </div>
            <div className="px-6 py-5 flex flex-col gap-4">
              <div>
                <label className="text-xs font-medium text-gray-500 uppercase tracking-wider block mb-1.5">Assunto</label>
                <input
                  value={form.assunto}
                  onChange={e => setForm(f => ({ ...f, assunto: e.target.value }))}
                  placeholder="Ex: Lâmpada queimada no corredor"
                  className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931]"
                />
              </div>
              <div>
                <label className="text-xs font-medium text-gray-500 uppercase tracking-wider block mb-1.5">Categoria</label>
                <div className="flex gap-2 flex-wrap">
                  {[
                    { key: 'maintenance', label: 'Manutenção' },
                    { key: 'security', label: 'Segurança' },
                    { key: 'noise', label: 'Barulho' },
                    { key: 'others', label: 'Outros' },
                  ].map(({ key, label }) => (
                    <button
                      key={key}
                      onClick={() => setForm(f => ({ ...f, category: key }))}
                      className={`text-sm px-3 py-1.5 rounded-xl border font-medium transition-all ${
                        form.category === key
                          ? 'bg-[#FC5931] text-white border-[#FC5931]'
                          : 'bg-white text-gray-600 border-gray-200 hover:border-[#FC5931]'
                      }`}
                    >
                      {label}
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label className="text-xs font-medium text-gray-500 uppercase tracking-wider block mb-1.5">Descrição</label>
                <textarea
                  value={form.description}
                  onChange={e => setForm(f => ({ ...f, description: e.target.value }))}
                  rows={4}
                  placeholder="Descreva a ocorrência em detalhes..."
                  className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-[#FC5931]/30 focus:border-[#FC5931]"
                />
              </div>
              <div>
                <label className="text-xs font-medium text-gray-500 uppercase tracking-wider block mb-1.5">Foto (Opcional)</label>
                <label className="flex items-center gap-3 border border-dashed border-gray-300 rounded-xl px-4 py-3 cursor-pointer hover:border-[#FC5931] transition-colors">
                  <span className="text-2xl">📎</span>
                  <span className="text-sm text-gray-500">{photoFile ? photoFile.name : 'Clique para selecionar uma foto'}</span>
                  <input type="file" accept="image/*" onChange={handlePhotoChange} className="hidden" />
                </label>
                {photoPreview && (
                  <div className="mt-2 relative">
                    <img src={photoPreview} alt="Preview" className="w-full max-h-40 object-cover rounded-xl border border-gray-100" />
                    <button
                      onClick={() => { setPhotoFile(null); setPhotoPreview(null) }}
                      className="absolute top-2 right-2 bg-white rounded-full w-6 h-6 text-xs text-gray-600 shadow hover:bg-gray-100"
                    >✕</button>
                  </div>
                )}
              </div>
            </div>
            <div className="px-6 py-4 border-t border-gray-100 flex gap-3 justify-end">
              <button
                onClick={() => setShowModal(false)}
                className="text-sm font-medium px-4 py-2 rounded-xl border border-gray-200 text-gray-600 hover:bg-gray-50"
              >
                Cancelar
              </button>
              <button
                onClick={handleCreate}
                disabled={creating || !form.assunto.trim() || !form.description.trim()}
                className="bg-[#FC5931] text-white text-sm font-semibold px-5 py-2 rounded-xl hover:bg-[#D42F1D] transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
              >
                {creating ? 'Salvando...' : 'Registrar Ocorrência'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useRef, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import type { UnitOption } from './page'
import {
  Camera, Package, CheckCircle2, ChevronLeft, Loader2,
  Box, Mail, ShoppingBag, FileText, X, RefreshCw, Video
} from 'lucide-react'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

interface Props {
  condoId: string
  registeredById: string
  units: UnitOption[]
  tipoEstrutura?: string
  allBlocos?: string[]
  allAptos?: string[]
  redirectTo?: string
}

type TipoEncomenda = 'caixa' | 'envelope' | 'pacote' | 'notif_judicial'

const TIPOS: { value: TipoEncomenda; label: string; icon: React.ElementType }[] = [
  { value: 'caixa',          label: 'Caixa',            icon: Box },
  { value: 'envelope',       label: 'Envelope',         icon: Mail },
  { value: 'pacote',         label: 'Pacote',           icon: ShoppingBag },
  { value: 'notif_judicial', label: 'Notif. Judicial', icon: FileText },
]

export default function ParcelRegisterForm({ condoId, registeredById, units, tipoEstrutura, allBlocos, allAptos, redirectTo }: Props) {
  const router = useRouter()
  const supabase = createClient()

  // Form state
  const [tipo, setTipo] = useState<TipoEncomenda>('pacote')
  const [blocoSel, setBlocoSel] = useState('')
  const [aptoSel, setAptoSel] = useState('')
  const [trackingCode, setTrackingCode] = useState('')
  const [observacao, setObservacao] = useState('')
  const [submitting, setSubmitting] = useState(false)
  const [success, setSuccess] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [warning, setWarning] = useState<string | null>(null)

  // Camera state
  const [cameraOpen, setCameraOpen] = useState(false)
  const [photoBlob, setPhotoBlob] = useState<Blob | null>(null)
  const [photoPreview, setPhotoPreview] = useState<string | null>(null)
  const [facingMode, setFacingMode] = useState<'environment' | 'user'>('environment')
  const [cameraError, setCameraError] = useState<string | null>(null)
  const videoRef = useRef<HTMLVideoElement>(null)
  const streamRef = useRef<MediaStream | null>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)

  // Derived lists from units and structural tables
  const blocos = allBlocos && allBlocos.length > 0
    ? [...allBlocos].sort((a, b) => a.localeCompare(b, 'pt', { numeric: true }))
    : [...new Set(units.map(u => u.blocoNome))].sort((a, b) => a.localeCompare(b, 'pt', { numeric: true }))

  const aptosList = allAptos && allAptos.length > 0
    ? allAptos
    : units.filter(u => (!blocoSel || u.blocoNome === blocoSel)).map(u => u.aptoNumero)

  const uniqueAptos = [...new Set(aptosList)].sort((a, b) => a.localeCompare(b, 'pt', { numeric: true }))

  const selectedUnit = units.find(u => u.blocoNome === blocoSel && u.aptoNumero === aptoSel)

  // Reset apto when bloco changes
  useEffect(() => { setAptoSel('') }, [blocoSel])

  // ── Camera helpers ──────────────────────────────────────────────────────────

  const stopStream = useCallback(() => {
    streamRef.current?.getTracks().forEach(t => t.stop())
    streamRef.current = null
  }, [])

  const startCamera = useCallback(async (facing: 'environment' | 'user') => {
    setCameraError(null)
    stopStream()
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: facing, width: { ideal: 1280 }, height: { ideal: 720 } },
        audio: false,
      })
      streamRef.current = stream
      if (videoRef.current) {
        videoRef.current.srcObject = stream
        videoRef.current.play()
      }
    } catch (err) {
      setCameraError('Não foi possível acessar a câmera. Verifique as permissões do navegador.')
    }
  }, [stopStream])

  useEffect(() => {
    if (cameraOpen) startCamera(facingMode)
    else stopStream()
    return () => stopStream()
  }, [cameraOpen, facingMode, startCamera, stopStream])

  const flipCamera = () => {
    const next = facingMode === 'environment' ? 'user' : 'environment'
    setFacingMode(next)
  }

  const takePhoto = () => {
    if (!videoRef.current || !canvasRef.current) return
    const video = videoRef.current
    const canvas = canvasRef.current
    canvas.width = video.videoWidth
    canvas.height = video.videoHeight
    canvas.getContext('2d')?.drawImage(video, 0, 0)
    canvas.toBlob(blob => {
      if (!blob) return
      setPhotoBlob(blob)
      setPhotoPreview(URL.createObjectURL(blob))
      setCameraOpen(false)
    }, 'image/jpeg', 0.92)
  }

  const clearPhoto = () => {
    setPhotoBlob(null)
    setPhotoPreview(null)
  }

  // ── Submit ──────────────────────────────────────────────────────────────────

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)

    if (!blocoSel || !aptoSel) {
      setError(`Selecione o ${getBlocoLabel(tipoEstrutura)} e o ${getAptoLabel(tipoEstrutura)} do destinatário.`)
      return
    }

    setSubmitting(true)

    try {
      let photoUrl: string | null = null
      let photoWarning: string | null = null

      // Upload photo if captured (non-blocking — registration continues even if upload fails)
      if (photoBlob) {
        try {
          const path = `${condoId}/${Date.now()}_${Math.random().toString(36).slice(2)}.jpg`
          const { error: uploadError } = await supabase.storage
            .from('parcel-photos')
            .upload(path, photoBlob, { contentType: 'image/jpeg', upsert: false })

          if (uploadError) {
            photoWarning = `Foto não enviada (bucket não encontrado). Crie o bucket 'parcel-photos' no Supabase.`
          } else {
            const { data: urlData } = supabase.storage.from('parcel-photos').getPublicUrl(path)
            photoUrl = urlData.publicUrl
          }
        } catch {
          photoWarning = 'Foto não enviada, encomenda registrada sem foto.'
        }
      }

      // Insert parcel record
      const { error: insertError } = await supabase
        .from('encomendas')
        .insert({
          resident_id: selectedUnit?.residentId ?? null,
          condominio_id: condoId,
          registered_by: registeredById,
          status: 'pending',
          arrival_time: new Date().toISOString(),
          tipo,
          tracking_code: trackingCode || null,
          observacao: observacao || null,
          photo_url: photoUrl,
          bloco: blocoSel,
          apto: aptoSel,
        })

      if (insertError) throw new Error(`Erro ao registrar: ${insertError.message}`)

      if (photoWarning) setWarning(photoWarning)
      setSuccess(true)
      setTimeout(() => router.push(redirectTo || '/condo/encomendas-admin'), 3500)
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Erro inesperado.')
      setSubmitting(false)
    }
  }

  // ── Success ─────────────────────────────────────────────────────────────────

  if (success) {
    return (
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-12 text-center">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-5">
          <CheckCircle2 className="text-green-500" size={44} />
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Encomenda Registrada!</h2>
        <p className="text-gray-500 text-sm">
          {getBlocoLabel(tipoEstrutura)} {blocoSel} / {getAptoLabel(tipoEstrutura)} {aptoSel}
          {selectedUnit?.residentName && ` — ${selectedUnit.residentName}`}
        </p>
        {warning && (
          <div className="mt-4 bg-amber-50 border border-amber-200 rounded-xl px-4 py-3 text-xs text-amber-700 text-left">
            ⚠️ {warning}
          </div>
        )}
        <p className="text-gray-400 text-xs mt-4">Redirecionando para a lista...</p>
      </div>
    )
  }

  // ── Camera modal ─────────────────────────────────────────────────────────────

  const CameraModal = () => (
    <div className="fixed inset-0 bg-black z-50" style={{ display: 'flex', flexDirection: 'column' }}>

      {/* TOP BAR — fixed height */}
      <div style={{ flexShrink: 0 }} className="flex items-center justify-between px-4 py-3 bg-black/90 border-b border-white/10">
        <button onClick={() => setCameraOpen(false)} className="text-white p-2 rounded-xl hover:bg-white/10 active:bg-white/20">
          <X size={22} />
        </button>
        <p className="text-white font-semibold text-sm tracking-wide">📷 Foto da Encomenda</p>
        <button onClick={flipCamera} className="text-white p-2 rounded-xl hover:bg-white/10 active:bg-white/20" title="Virar câmera">
          <RefreshCw size={20} />
        </button>
      </div>

      {/* VIDEO — fills remaining space */}
      <div style={{ flex: 1, position: 'relative', overflow: 'hidden', background: '#000', minHeight: 0 }}>
        {cameraError ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-center px-8">
            <Video size={48} className="text-white/30 mb-3" />
            <p className="text-white/70 text-sm">{cameraError}</p>
          </div>
        ) : (
          <video
            ref={videoRef}
            autoPlay
            playsInline
            muted
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        )}
        {/* Viewfinder */}
        <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
          <div className="border-2 border-white/50 rounded-2xl" style={{ width: 260, height: 180 }} />
        </div>
      </div>

      {/* Hidden canvas */}
      <canvas ref={canvasRef} className="hidden" />

      {/* SHUTTER BAR — fixed height, always visible */}
      <div
        style={{ flexShrink: 0, height: 120 }}
        className="bg-black/90 flex items-center justify-center border-t border-white/10"
      >
        <button
          onClick={takePhoto}
          disabled={!!cameraError}
          aria-label="Tirar foto"
          style={{ width: 80, height: 80 }}
          className="rounded-full border-[5px] border-white bg-white/20 hover:bg-white/30 active:scale-95 disabled:opacity-40 transition-all flex items-center justify-center shadow-lg"
        >
          <div style={{ width: 60, height: 60 }} className="rounded-full bg-white" />
        </button>
      </div>
    </div>
  )

  // ── Main form ────────────────────────────────────────────────────────────────

  return (
    <>
      {cameraOpen && <CameraModal />}

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Tipo */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-4">
            Tipo da Encomenda
          </p>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {TIPOS.map(t => {
              const Icon = t.icon
              const active = tipo === t.value
              return (
                <button
                  key={t.value}
                  type="button"
                  onClick={() => setTipo(t.value)}
                  className={`flex flex-col items-center gap-2 p-4 rounded-xl border-2 transition-all duration-150 ${
                    active
                      ? 'border-[#FC5931] bg-[#FC5931]/5 text-[#FC5931]'
                      : 'border-gray-100 bg-gray-50 text-gray-500 hover:border-gray-200'
                  }`}
                >
                  <Icon size={22} />
                  <span className="text-xs font-semibold text-center leading-tight">{t.label}</span>
                </button>
              )
            })}
          </div>
        </div>

        {/* Destinatário */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-4">
            Destinatário
          </p>
          <div className="grid grid-cols-2 gap-4 mb-3">
            <div>
              <label className="block text-xs font-medium text-gray-600 mb-1.5">{getBlocoLabel(tipoEstrutura)}</label>
              <select
                value={blocoSel}
                onChange={e => setBlocoSel(e.target.value)}
                required
                className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50"
              >
                <option value="">Selecione o {getBlocoLabel(tipoEstrutura)}</option>
                {blocos.map(b => (
                  <option key={b} value={b}>{b}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-600 mb-1.5">{getAptoLabel(tipoEstrutura)}</label>
              <select
                value={aptoSel}
                onChange={e => setAptoSel(e.target.value)}
                required
                disabled={!blocoSel}
                className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 disabled:opacity-50"
              >
                <option value="">Selecione o {getAptoLabel(tipoEstrutura)}</option>
                {uniqueAptos.map(a => (
                  <option key={a} value={a}>{a}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Resident preview */}
          {selectedUnit?.residentName ? (
            <div className="flex items-center gap-3 bg-[#FC5931]/5 border border-[#FC5931]/20 rounded-xl px-4 py-3">
              <div className="w-9 h-9 rounded-xl bg-[#FC5931]/10 flex items-center justify-center flex-shrink-0">
                <span className="text-[#FC5931] font-bold text-sm">
                  {selectedUnit.residentName[0].toUpperCase()}
                </span>
              </div>
              <p className="text-sm font-medium text-gray-800">{selectedUnit.residentName}</p>
            </div>
          ) : aptoSel ? (
            <div className="flex items-center gap-3 bg-gray-50 border border-gray-200 rounded-xl px-4 py-3">
              <div className="w-9 h-9 rounded-xl bg-gray-200 flex items-center justify-center flex-shrink-0">
                <span className="text-gray-500 font-bold text-sm">?</span>
              </div>
              <p className="text-sm text-gray-500">Não existe morador cadastrado na unidade</p>
            </div>
          ) : null}
        </div>

        {/* Foto via Webcam */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">
            Foto da Encomenda <span className="normal-case text-gray-400 font-normal">(recomendada)</span>
          </p>

          {photoPreview ? (
            <div className="relative">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={photoPreview}
                alt="Foto da encomenda"
                className="w-full h-52 object-cover rounded-xl border border-gray-100"
              />
              <button
                type="button"
                onClick={clearPhoto}
                className="absolute top-2 right-2 w-8 h-8 bg-black/60 hover:bg-black/80 rounded-full flex items-center justify-center transition-colors"
              >
                <X size={14} className="text-white" />
              </button>
            </div>
          ) : (
            <button
              type="button"
              onClick={() => setCameraOpen(true)}
              className="flex flex-col items-center justify-center gap-3 w-full h-40 border-2 border-dashed border-gray-200 rounded-xl cursor-pointer hover:border-[#FC5931] hover:bg-[#FC5931]/5 transition-all group"
            >
              <div className="w-14 h-14 bg-gray-100 group-hover:bg-[#FC5931]/10 rounded-2xl flex items-center justify-center transition-colors">
                <Camera size={26} className="text-gray-400 group-hover:text-[#FC5931] transition-colors" />
              </div>
              <div className="text-center">
                <p className="text-sm font-medium text-gray-600 group-hover:text-[#FC5931] transition-colors">
                  Abrir câmera
                </p>
                <p className="text-xs text-gray-400 mt-0.5">Tire uma foto da encomenda</p>
              </div>
            </button>
          )}
        </div>

        {/* Código de Rastreio */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">
            Código de Rastreio <span className="normal-case text-gray-400 font-normal">(opcional)</span>
          </label>
          <input
            type="text"
            value={trackingCode}
            onChange={e => setTrackingCode(e.target.value)}
            placeholder="Ex: BR123456789BR"
            className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 font-mono tracking-wide"
          />
        </div>

        {/* Observação */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">
            Observação <span className="normal-case text-gray-400 font-normal">(opcional)</span>
          </label>
          <textarea
            value={observacao}
            onChange={e => setObservacao(e.target.value)}
            placeholder="Ex: Pacote danificado, remetente Riachuelo..."
            rows={3}
            className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 resize-none"
          />
        </div>

        {/* Error */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-xl px-4 py-3 text-sm text-red-700">
            {error}
          </div>
        )}

        {/* Actions */}
        <div className="flex gap-3 pb-8">
          <button
            type="button"
            onClick={() => router.back()}
            disabled={submitting}
            className="flex items-center gap-2 px-5 py-3 border border-gray-200 text-gray-600 text-sm font-semibold rounded-xl hover:bg-gray-50 transition-colors disabled:opacity-50"
          >
            <ChevronLeft size={16} />
            Voltar
          </button>
          <button
            type="submit"
            disabled={submitting}
            className="flex-1 flex items-center justify-center gap-2 bg-[#FC5931] text-white text-sm font-semibold py-3 rounded-xl hover:bg-[#D42F1D] transition-colors disabled:opacity-60 shadow-sm"
          >
            {submitting ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                {photoBlob ? 'Enviando foto...' : 'Registrando...'}
              </>
            ) : (
              <>
                <Package size={16} />
                Registrar Encomenda
              </>
            )}
          </button>
        </div>
      </form>
    </>
  )
}

'use client'
import { useState, useTransition, useRef, useCallback, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import {
  Camera, UserPlus, Clock,
  CheckCircle, AlertCircle, ChevronLeft, X, Video
} from 'lucide-react'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

interface Visitante {
  id: string
  nome: string
  cpf_rg: string | null
  whatsapp: string | null
  tipo_visitante: string | null
  empresa: string | null
  bloco: string | null
  apto: string | null
  observacao: string | null
  foto_url: string | null
  entrada_at: string
  saida_at: string | null
  registrado_por: string | null
  created_at: string
}

interface Props {
  visitantes: Visitante[]
  condoId: string
  currentUserId: string
  currentUserName: string
  tipoEstrutura?: string
  blocos: string[]
  aptosMap: Record<string, string[]>
}

const TIPOS_VISITANTE = [
  'Uber ou Taxi',
  'Delivery',
  'Farmácia',
  'Diarista',
  'Visitante',
  'Mat. Obra',
  'Serviços',
  'Hóspedes',
  'Outros',
]

export default function RegistrarVisitanteClient({
  visitantes: initialVisitantes,
  condoId,
  currentUserId,
  currentUserName,
  tipoEstrutura,
  blocos,
  aptosMap,
}: Props) {
  const router = useRouter()
  const supabase = createClient()
  const [isPending, startTransition] = useTransition()

  // View state
  const [view, setView] = useState<'form' | 'history'>('form')

  // Form state
  const [cpfRg, setCpfRg] = useState('')
  const [nome, setNome] = useState('')
  const [whatsapp, setWhatsapp] = useState('')
  const [tipoVisitante, setTipoVisitante] = useState('')
  const [empresa, setEmpresa] = useState('')
  const [bloco, setBloco] = useState('')
  const [apto, setApto] = useState('')
  const [observacao, setObservacao] = useState('')
  const [fotoPreview, setFotoPreview] = useState<string | null>(null)
  const [fotoBlob, setFotoBlob] = useState<Blob | null>(null)
  const [lastVisit, setLastVisit] = useState<Visitante | null>(null)
  const [saved, setSaved] = useState(false)
  const [error, setError] = useState('')

  // CPF auto-search state
  const [cpfSuggestions, setCpfSuggestions] = useState<Visitante[]>([])
  const [showSuggestions, setShowSuggestions] = useState(false)
  const searchTimerRef = useRef<NodeJS.Timeout | null>(null)

  // Webcam state
  const [showWebcam, setShowWebcam] = useState(false)
  const videoRef = useRef<HTMLVideoElement>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const streamRef = useRef<MediaStream | null>(null)

  // Available aptos based on selected bloco
  const availableAptos = bloco ? (aptosMap[bloco] ?? []) : []

  // Visitor list
  const [visitantes, setVisitantes] = useState(initialVisitantes)

  // ── CPF/RG Auto-search (debounced) ─────────────────────────
  const handleCpfChange = useCallback((value: string) => {
    const cleaned = value.replace(/\D/g, '')
    setCpfRg(cleaned)

    if (searchTimerRef.current) clearTimeout(searchTimerRef.current)

    if (cleaned.length >= 3) {
      searchTimerRef.current = setTimeout(async () => {
        const { data } = await supabase
          .from('visitante_registros')
          .select('*')
          .eq('condominio_id', condoId)
          .ilike('cpf_rg', `${cleaned}%`)
          .order('entrada_at', { ascending: false })
          .limit(5)

        // Deduplicate by cpf_rg (keep most recent)
        const seen = new Set<string>()
        const unique = (data ?? []).filter(v => {
          if (!v.cpf_rg || seen.has(v.cpf_rg)) return false
          seen.add(v.cpf_rg)
          return true
        })
        setCpfSuggestions(unique)
        setShowSuggestions(unique.length > 0)
      }, 300)
    } else {
      setCpfSuggestions([])
      setShowSuggestions(false)
      // Clear auto-filled fields when CPF is erased
      if (lastVisit) {
        setNome(''); setWhatsapp(''); setTipoVisitante('')
        setEmpresa(''); setBloco(''); setApto('')
        setFotoPreview(null); setFotoBlob(null); setLastVisit(null)
      }
    }
  }, [condoId, supabase])

  function selectSuggestion(v: Visitante) {
    setCpfRg(v.cpf_rg || '')
    setNome(v.nome || '')
    setWhatsapp(v.whatsapp || '')
    setTipoVisitante(v.tipo_visitante || '')
    setEmpresa(v.empresa || '')
    setBloco(v.bloco || '')
    setApto(v.apto || '')
    setLastVisit(v)
    if (v.foto_url) setFotoPreview(v.foto_url)
    setShowSuggestions(false)
  }

  // ── Webcam capture ─────────────────────────────────────────
  const [videoReady, setVideoReady] = useState(false)

  // Ref callback: assigns stream when video element mounts
  const videoRefCallback = useCallback((node: HTMLVideoElement | null) => {
    (videoRef as React.MutableRefObject<HTMLVideoElement | null>).current = node
    if (node && streamRef.current) {
      node.srcObject = streamRef.current
      node.onloadeddata = () => setVideoReady(true)
    }
  }, [])

  async function startWebcam() {
    setVideoReady(false)
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: 640, height: 480 }
      })
      streamRef.current = stream
      // Show modal AFTER we have the stream
      setShowWebcam(true)
    } catch {
      setError('Não foi possível acessar a câmera.')
    }
  }

  function capturePhoto() {
    if (!videoRef.current || !canvasRef.current) return
    const video = videoRef.current
    const canvas = canvasRef.current
    canvas.width = video.videoWidth
    canvas.height = video.videoHeight
    const ctx = canvas.getContext('2d')
    if (!ctx) return
    ctx.drawImage(video, 0, 0)
    // Wait for blob before stopping webcam
    canvas.toBlob(blob => {
      if (blob) {
        setFotoBlob(blob)
        setFotoPreview(URL.createObjectURL(blob))
      }
      stopWebcam()
    }, 'image/jpeg', 0.85)
  }

  function stopWebcam() {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop())
      streamRef.current = null
    }
    setShowWebcam(false)
    setVideoReady(false)
  }

  // Cleanup webcam on unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(t => t.stop())
      }
    }
  }, [])

  // ── Save visitor ───────────────────────────────────────────
  async function handleSave() {
    if (!nome.trim()) { setError('Informe o nome do visitante.'); return }
    if (!tipoVisitante) { setError('Selecione o tipo de visitante.'); return }
    setError('')

    startTransition(async () => {
      let fotoUrl: string | null = null

      // Upload photo blob (from webcam)
      if (fotoBlob) {
        const path = `${condoId}/${Date.now()}.jpg`
        const { error: uploadError } = await supabase.storage
          .from('visitor-photos')
          .upload(path, fotoBlob, { contentType: 'image/jpeg', upsert: true })

        if (uploadError) {
          console.error('Upload error:', uploadError)
          // Continue without photo — don't block the registration
        } else {
          const { data: urlData } = supabase.storage
            .from('visitor-photos')
            .getPublicUrl(path)
          fotoUrl = urlData.publicUrl
        }
      } else if (fotoPreview && !fotoPreview.startsWith('blob:')) {
        // Reuse existing photo URL from a returning visitor (not a blob)
        fotoUrl = fotoPreview
      }

      const { data: newVisitor, error: insertError } = await supabase
        .from('visitante_registros')
        .insert({
          condominio_id: condoId,
          nome: nome.trim(),
          cpf_rg: cpfRg || null,
          whatsapp: whatsapp.trim() || null,
          tipo_visitante: tipoVisitante,
          empresa: empresa.trim() || null,
          bloco: bloco.trim() || null,
          apto: apto.trim() || null,
          observacao: observacao.trim() || null,
          foto_url: fotoUrl || null,
          registrado_por: currentUserId,
        })
        .select()
        .single()

      if (insertError) { setError('Erro ao salvar: ' + insertError.message); return }

      // Fire-and-forget: send WhatsApp notification to unit residents
      try {
        const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
        const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
        if (supabaseUrl && supabaseAnonKey) {
          fetch(`${supabaseUrl}/functions/v1/visitor-register-whatsapp-notify`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${supabaseAnonKey}`,
            },
            body: JSON.stringify({
              condominio_id: condoId,
              nome: nome.trim(),
              whatsapp: whatsapp.trim() || null,
              tipo_visitante: tipoVisitante,
              empresa: empresa.trim() || null,
              bloco: bloco.trim() || null,
              apto: apto.trim() || null,
              data_visita: new Date().toISOString(),
            }),
          }).catch(err => console.error('WhatsApp notify error:', err))
        }
      } catch (e) {
        console.error('WhatsApp notify error:', e)
      }

      // Add to local state immediately so sidebar updates
      if (newVisitor) {
        setVisitantes(prev => [newVisitor, ...prev])
      }

      setSaved(true)
      setTimeout(() => { setSaved(false); resetForm(); router.refresh() }, 2000)
    })
  }

  function resetForm() {
    setCpfRg(''); setNome(''); setWhatsapp(''); setTipoVisitante('')
    setEmpresa(''); setBloco(''); setApto(''); setObservacao('')
    setFotoPreview(null); setFotoBlob(null); setLastVisit(null)
  }

  // ── Register exit ──────────────────────────────────────────
  async function handleRegistrarSaida(id: string) {
    startTransition(async () => {
      await supabase
        .from('visitante_registros')
        .update({ saida_at: new Date().toISOString() })
        .eq('id', id)
      router.refresh()
      setVisitantes(prev =>
        prev.map(v => v.id === id ? { ...v, saida_at: new Date().toISOString() } : v)
      )
    })
  }

  // ── Helpers ────────────────────────────────────────────────
  function fmtDate(iso: string) {
    const d = new Date(iso)
    return d.toLocaleDateString('pt-BR') + ' – ' + d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) + 'h'
  }

  const pendentes = visitantes.filter(v => !v.saida_at)

  // ══════════════════════════════════════════════════════════
  // HISTORY VIEW
  // ══════════════════════════════════════════════════════════
  if (view === 'history') {
    return (
      <div>
        <div className="flex items-center gap-4 mb-6">
          <button
            onClick={() => setView('form')}
            className="flex items-center gap-1.5 text-[#FC5931] font-semibold hover:underline"
            title="Voltar ao formulário"
          >
            <ChevronLeft size={18} />
            VOLTAR
          </button>
          <h1 className="text-xl font-bold text-gray-800">Histórico dos visitantes</h1>
        </div>

        <div className="space-y-4">
          {visitantes.map(v => (
            <div key={v.id} className="bg-white rounded-xl border border-gray-100 p-5 flex items-start gap-5">
              <div className="w-16 h-16 rounded-full bg-gray-200 overflow-hidden flex-shrink-0">
                {v.foto_url ? (
                  <img src={v.foto_url} alt={v.nome} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-gray-400 text-xl">👤</div>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="font-bold text-gray-800">Visitante: {v.nome}</p>
                {(v.bloco || v.apto) && (
                  <p className="text-sm text-gray-500">{getBlocoLabel(tipoEstrutura)}: {v.bloco || '−'} / {getAptoLabel(tipoEstrutura)}: {v.apto || '−'}</p>
                )}
                <p className="text-sm text-gray-500">
                  <span className="font-medium">Entrada:</span> {fmtDate(v.entrada_at)}
                </p>
                {v.saida_at && (
                  <p className="text-sm text-gray-500">
                    <span className="font-medium">Saída:</span> {fmtDate(v.saida_at)}
                  </p>
                )}
              </div>
              <div className="flex-shrink-0">
                {!v.saida_at ? (
                  <button
                    onClick={() => handleRegistrarSaida(v.id)}
                    disabled={isPending}
                    title="Registrar saída do visitante"
                    className="bg-red-500 hover:bg-red-600 text-white px-4 py-2 rounded-lg font-semibold text-sm transition-colors disabled:opacity-60"
                  >
                    Registrar Saída
                  </button>
                ) : (
                  <div className="bg-green-500 text-white px-4 py-2 rounded-lg text-sm font-semibold text-center">
                    <div>Saída Registrada</div>
                    <div className="text-xs opacity-90">{new Date(v.saida_at).toLocaleDateString('pt-BR')}</div>
                  </div>
                )}
              </div>
            </div>
          ))}
          {visitantes.length === 0 && (
            <p className="text-gray-400 text-center py-12">Nenhum visitante registrado.</p>
          )}
        </div>
      </div>
    )
  }

  // ══════════════════════════════════════════════════════════
  // FORM VIEW
  // ══════════════════════════════════════════════════════════
  return (
    <div className="flex flex-col lg:flex-row gap-6">
      {/* ── LEFT: Registration Form ─────────────────────────── */}
      <div className="flex-1">
        <div className="bg-[#FC5931] text-white text-center font-bold py-3 rounded-t-xl text-lg">
          Registrar Visitante
        </div>
        <div className="bg-white rounded-b-xl border border-gray-100 border-t-0 p-6 space-y-5">

          {/* CPF/RG with auto-search */}
          <div className="relative">
            <label className="block text-sm font-semibold text-gray-700 text-center mb-2">CPF ou RG (Digite somente número)</label>
            <input
              type="text"
              value={cpfRg}
              onChange={e => handleCpfChange(e.target.value)}
              onFocus={() => cpfSuggestions.length > 0 && setShowSuggestions(true)}
              onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
              placeholder="Digite o CPF ou RG"
              className="w-full border border-gray-200 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
            />

            {/* Auto-suggestions dropdown */}
            {showSuggestions && cpfSuggestions.length > 0 && (
              <div className="absolute z-20 top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg max-h-60 overflow-y-auto">
                {cpfSuggestions.map(v => (
                  <button
                    key={v.id}
                    type="button"
                    onMouseDown={() => selectSuggestion(v)}
                    className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors border-b border-gray-50 last:border-0 flex items-center gap-3"
