              <><UserPlus size={20} /> Registrar Entrada</>
            )}
          </button>
        </div>
      </div>

      {/* ── RIGHT: Visitor History Sidebar ───────────────────── */}
      <div className="w-full lg:w-[380px] flex-shrink-0">
        <div className="bg-[#FC5931] text-white text-center font-bold py-3 rounded-t-xl">
          Histórico de visitas
        </div>
        <div className="bg-white rounded-b-xl border border-gray-100 border-t-0 p-4 space-y-3 max-h-[700px] overflow-y-auto">
          {visitantes.slice(0, 20).map(v => (
            <div
              key={v.id}
              className="bg-gray-50 rounded-lg p-3 flex items-start gap-3 hover:bg-gray-100 transition-colors"
            >
              <div className="w-12 h-12 rounded-full bg-gray-200 overflow-hidden flex-shrink-0">
                {v.foto_url ? (
                  <img src={v.foto_url} alt={v.nome} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-gray-400 text-sm">👤</div>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="font-bold text-gray-800 text-sm truncate">{v.nome}</p>
                <p className="text-xs text-gray-500">
                  <span className="font-medium">Entrada:</span> {fmtDate(v.entrada_at)}
                </p>
                {v.saida_at && (
                  <p className="text-xs text-gray-500">
                    <span className="font-medium">Saída:</span> {fmtDate(v.saida_at)}
                  </p>
                )}
                {(v.bloco || v.apto) && (
                  <p className="text-xs text-gray-400">{getBlocoLabel(tipoEstrutura)} {v.bloco || '−'} / {getAptoLabel(tipoEstrutura)}: {v.apto || '−'}</p>
                )}
                {!v.saida_at && (
                  <button
                    onClick={() => handleRegistrarSaida(v.id)}
                    className="mt-1 bg-yellow-400 text-yellow-900 text-xs font-bold px-3 py-1 rounded-md hover:bg-yellow-500 transition-colors"
                  >
                    Saída pendente
                  </button>
                )}
              </div>
            </div>
          ))}
          {visitantes.length === 0 && (
            <p className="text-gray-400 text-center py-8 text-sm">Nenhum visitante registrado.</p>
          )}
        </div>

        {visitantes.length > 0 && (
          <button
            onClick={() => setView('history')}
            className="w-full mt-3 text-[#FC5931] font-semibold text-sm hover:underline py-2"
          >
            Ver histórico completo →
          </button>
        )}

        {pendentes.length > 0 && (
          <div className="mt-3 bg-yellow-50 border border-yellow-200 rounded-lg p-3 text-center">
            <Clock size={18} className="inline mr-1.5 text-yellow-600" />
            <span className="text-sm font-semibold text-yellow-700">
              {pendentes.length} saída{pendentes.length > 1 ? 's' : ''} pendente{pendentes.length > 1 ? 's' : ''}
            </span>
          </div>
        )}
      </div>
    </div>
  )
}

'use client'
import { useState, useTransition, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import {
  LogIn, LogOut as LogOutIcon, Plus, X, Search, Filter,
  CheckCircle, AlertCircle, Clock, Users, ChevronDown
} from 'lucide-react'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

interface Visita {
  id: string
  condominio_id: string
  tipo: 'entrada' | 'saida'
  morador_id: string | null
  nome_morador: string
  bloco: string | null
  apto: string | null
  cracha_referencia: string | null
  registrado_por: string | null
  created_at: string
}

interface Morador {
  id: string
  nome: string
}

interface Props {
  visitas: Visita[]
  condoId: string
  currentUserId: string
  currentUserName: string
  tipoEstrutura?: string
  blocos: string[]
  aptosMap: Record<string, string[]>
  moradoresMap: Record<string, Morador[]>
}

export default function VisitaProprietarioClient({
  visitas: initialVisitas,
  condoId,
  currentUserId,
  currentUserName,
  tipoEstrutura,
  blocos,
  aptosMap,
  moradoresMap,
}: Props) {
  const supabase = createClient()
  const [isPending, startTransition] = useTransition()

  // ── Pagination ──────────────────────────────────────────
  const PAGE_SIZE = 10
  const [page, setPage] = useState(0)
  const [totalCount, setTotalCount] = useState(0)
  const totalPages = Math.max(1, Math.ceil(totalCount / PAGE_SIZE))

  // List state
  const [visitas, setVisitas] = useState(initialVisitas)
  const [loading, setLoading] = useState(false)

  // Filter state — default date = today (local timezone)
  const now = new Date()
  const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`
  const [filterTipo, setFilterTipo] = useState<'todos' | 'entrada' | 'saida'>('todos')
  const [filterBloco, setFilterBloco] = useState('')
  const [filterApto, setFilterApto] = useState('')
  const [filterNome, setFilterNome] = useState('')
  const [nameInput, setNameInput] = useState('')
  const [filterData, setFilterData] = useState(todayStr)
  const [showFilters, setShowFilters] = useState(false)

  // Modal state
  const [showModal, setShowModal] = useState(false)
  const [modalTipo, setModalTipo] = useState<'entrada' | 'saida'>('entrada')
  const [modalBloco, setModalBloco] = useState('')
  const [modalApto, setModalApto] = useState('')
  const [modalMoradorId, setModalMoradorId] = useState<string | null>(null)
  const [modalNome, setModalNome] = useState('')
  const [modalCracha, setModalCracha] = useState('')
  const [saved, setSaved] = useState(false)
  const [error, setError] = useState('')

  // Available aptos based on selected bloco in modal
  const modalAvailableAptos = modalBloco ? (aptosMap[modalBloco] ?? []) : []
  const unitKey = `${modalBloco}|${modalApto}`
  const unitMoradores = moradoresMap[unitKey] ?? []

  // Available aptos for filters
  const filterAvailableAptos = filterBloco ? (aptosMap[filterBloco] ?? []) : []

  // ── Fetch visitas from DB ─────────────────────────────────
  async function fetchVisitas(currentPage = 0) {
    setLoading(true)
    const from = currentPage * PAGE_SIZE
    const to = from + PAGE_SIZE - 1

    let query = supabase
      .from('visita_proprietario')
      .select('*', { count: 'exact' })
      .eq('condominio_id', condoId)
      .order('created_at', { ascending: false })
      .range(from, to)

    if (filterTipo !== 'todos') query = query.eq('tipo', filterTipo)
    if (filterBloco) query = query.eq('bloco', filterBloco)
    if (filterApto) query = query.eq('apto', filterApto)
    if (filterNome) query = query.ilike('nome_morador', `%${filterNome}%`)
    if (filterData) {
      const startOfDay = `${filterData}T00:00:00`
      const endOfDay = `${filterData}T23:59:59`
      query = query.gte('created_at', startOfDay).lte('created_at', endOfDay)
    }

    const { data, count } = await query
    setVisitas(data ?? [])
    setTotalCount(count ?? 0)
    setLoading(false)
  }

  // Re-fetch whenever filters or page change
  useEffect(() => {
    fetchVisitas(page)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filterTipo, filterBloco, filterApto, filterNome, filterData, page])

  // Reset page to 0 when filters change
  function applyFilter<T>(setter: React.Dispatch<React.SetStateAction<T>>, value: T) {
    setPage(0)
    setter(value)
  }
  // Debounce name filter (500ms)
  useEffect(() => {
    const timer = setTimeout(() => {
      if (filterNome !== nameInput) {
        setPage(0)
        setFilterNome(nameInput)
      }
    }, 500)
    return () => clearTimeout(timer)
  }, [nameInput])

  const filteredVisitas = visitas

  // ── Handle save ───────────────────────────────────────────
  async function handleSave() {
    const nome = modalNome.trim()
    if (!nome) { setError('Informe o nome do morador.'); return }
    if (!modalBloco || !modalApto) { setError(`Selecione o ${getBlocoLabel(tipoEstrutura).toLowerCase()} e ${getAptoLabel(tipoEstrutura).toLowerCase()}.`); return }
    setError('')

    startTransition(async () => {
      const { error: insertError } = await supabase
        .from('visita_proprietario')
        .insert({
          condominio_id: condoId,
          tipo: modalTipo,
          morador_id: modalMoradorId,
          nome_morador: nome,
          bloco: modalBloco,
          apto: modalApto,
          cracha_referencia: modalCracha.trim() || null,
          registrado_por: currentUserId,
        })
        .select()
        .single()

      if (insertError) {
        setError('Erro ao registrar: ' + insertError.message)
        return
      }

      // Fire-and-forget: send push notification
      try {
        const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
        const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
        if (supabaseUrl && supabaseAnonKey) {
          fetch(`${supabaseUrl}/functions/v1/visita-proprietario-push-notify`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${supabaseAnonKey}`,
            },
            body: JSON.stringify({
              condominio_id: condoId,
              bloco: modalBloco,
              apto: modalApto,
              tipo: modalTipo,
              nome_morador: nome,
            }),
          }).catch(err => console.error('Push notify error:', err))
        }
      } catch (e) {
        console.error('Push notify error:', e)
      }

      // Re-fetch to update list with pagination
      setSaved(true)
      setTimeout(async () => {
        setSaved(false)
        resetModal()
        await fetchVisitas(page)
      }, 1500)
    })
  }

  function resetModal() {
    setShowModal(false)
    setModalTipo('entrada')
    setModalBloco('')
    setModalApto('')
    setModalMoradorId(null)
    setModalNome('')
    setModalCracha('')
    setError('')
  }

  function selectMorador(m: Morador) {
    setModalMoradorId(m.id)
    setModalNome(m.nome)
  }

  // ── Helpers ────────────────────────────────────────────────
  function fmtDate(iso: string) {
    const d = new Date(iso)
    return d.toLocaleDateString('pt-BR') + ' – ' + d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) + 'h'
  }

  function fmtDateShort(iso: string) {
    const d = new Date(iso)
    return d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) + 'h'
  }

  const countEntrada = visitas.filter(v => v.tipo === 'entrada').length
  const countSaida = visitas.filter(v => v.tipo === 'saida').length

  // ── Render ─────────────────────────────────────────────────
  return (
    <div className="max-w-5xl mx-auto">
      {/* ── Header ─────────────────────────────────────────── */}
      <div className="mb-6 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            🚪 Visita Proprietário
          </h1>
          <p className="text-sm text-gray-500 mt-1">
            Controle de entrada e saída de moradores
          </p>
        </div>
        <button
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-[#FC5931] text-white px-5 py-2.5 rounded-xl font-semibold text-sm hover:bg-[#D42F1D] transition-all shadow-lg shadow-[#FC5931]/20 hover:shadow-[#FC5931]/40"
        >
          <Plus size={18} />
          Registrar
        </button>
      </div>

      {/* ── Stats Cards ───────────────────────────────────── */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="bg-white rounded-2xl border border-gray-100 p-4 text-center shadow-sm">
          <div className="text-2xl font-bold text-gray-800">{totalCount}</div>
          <div className="text-xs text-gray-500 font-medium mt-1">Total</div>
        </div>
        <div className="bg-linear-to-br from-emerald-50 to-emerald-100/50 rounded-2xl border border-emerald-200/50 p-4 text-center">
          <div className="text-2xl font-bold text-emerald-700">{countEntrada}</div>
          <div className="text-xs text-emerald-600 font-medium mt-1 flex items-center justify-center gap-1">
            <LogIn size={12} /> Entradas
          </div>
        </div>
        <div className="bg-linear-to-br from-orange-50 to-orange-100/50 rounded-2xl border border-orange-200/50 p-4 text-center">
          <div className="text-2xl font-bold text-orange-700">{countSaida}</div>
          <div className="text-xs text-orange-600 font-medium mt-1 flex items-center justify-center gap-1">
            <LogOutIcon size={12} /> Saídas
          </div>
        </div>
      </div>

      {/* ── Radio Filter: Entrada / Saída / Todos ─────────── */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm mb-4">
        <div className="flex">
          {(['todos', 'entrada', 'saida'] as const).map(tipo => {
            const isActive = filterTipo === tipo
            const labels = { todos: 'Todos', entrada: 'Entrada', saida: 'Saída' }
            const icons = {
              todos: <Users size={16} />,
              entrada: <LogIn size={16} />,
              saida: <LogOutIcon size={16} />,
            }
            return (
              <button
                key={tipo}
                onClick={() => applyFilter(setFilterTipo, tipo)}
                className={`flex-1 flex items-center justify-center gap-2 py-3 text-sm font-semibold transition-all border-b-2 ${
                  isActive
                    ? 'border-[#FC5931] text-[#FC5931] bg-[#FC5931]/5'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                }`}
              >
                {icons[tipo]}
                {labels[tipo]}
              </button>
            )
          })}
        </div>
      </div>

      {/* ── Expandable Filters ────────────────────────────── */}
      <button
        onClick={() => setShowFilters(!showFilters)}
        className="flex items-center gap-2 text-sm text-gray-500 hover:text-gray-700 mb-3 font-medium transition-colors"
      >
        <Filter size={15} />
        Filtros
        <ChevronDown size={14} className={`transition-transform ${showFilters ? 'rotate-180' : ''}`} />
      </button>

      {showFilters && (
        <div className="bg-white rounded-2xl border border-gray-100 p-4 mb-4 shadow-sm">
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">{getBlocoLabel(tipoEstrutura)}</label>
              <select
                value={filterBloco}
                onChange={e => { applyFilter(setFilterBloco, e.target.value); setFilterApto('') }}
                title={`Filtrar por ${getBlocoLabel(tipoEstrutura).toLowerCase()}`}
                className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30 bg-white"
              >
                <option value="">Todos</option>
                {blocos.map(b => <option key={b} value={b}>{b}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">{getAptoLabel(tipoEstrutura)}</label>
              <select
                value={filterApto}
                onChange={e => applyFilter(setFilterApto, e.target.value)}
                disabled={!filterBloco}
                title={`Filtrar por ${getAptoLabel(tipoEstrutura).toLowerCase()}`}
                className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30 bg-white disabled:bg-gray-50 disabled:text-gray-400"
              >
                <option value="">Todos</option>
                {filterAvailableAptos.map(a => <option key={a} value={a}>{a}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">Nome</label>
              <div className="relative">
                <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type="text"
                  value={nameInput}
                  onChange={e => setNameInput(e.target.value)}
                  placeholder="Buscar nome..."
                  className="w-full border border-gray-200 rounded-lg pl-8 pr-3 py-2 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">Data</label>
              <input
                type="date"
                value={filterData}
                onChange={e => applyFilter(setFilterData, e.target.value)}
                className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
              />
            </div>
          </div>
          {(filterBloco || filterApto || filterNome || filterData !== todayStr) && (
            <button
              onClick={() => { setPage(0); setFilterBloco(''); setFilterApto(''); setNameInput(''); setFilterNome(''); setFilterData(todayStr) }}
              className="mt-3 text-xs text-[#FC5931] hover:underline font-medium"
            >
              Limpar filtros
            </button>
          )}
        </div>
      )}

      {/* ── Visitas List ──────────────────────────────────── */}
      <div className="space-y-3">
        {loading ? (
          <div className="bg-white rounded-2xl border border-gray-100 p-12 text-center shadow-sm">
            <div className="animate-spin text-4xl mb-3">⏳</div>
            <p className="text-gray-400 font-medium">Carregando...</p>
          </div>
        ) : filteredVisitas.length === 0 ? (
          <div className="bg-white rounded-2xl border border-gray-100 p-12 text-center shadow-sm">
            <div className="text-4xl mb-3">🚪</div>
            <p className="text-gray-400 font-medium">Nenhum registro encontrado</p>
            <p className="text-gray-300 text-sm mt-1">Registre a primeira entrada ou saída</p>
          </div>
        ) : (
          filteredVisitas.map(v => {
            const isEntrada = v.tipo === 'entrada'
            return (
              <div
                key={v.id}
                className="bg-white rounded-xl border border-gray-100 p-4 flex items-center gap-4 shadow-sm hover:shadow-md transition-shadow"
              >
                {/* Type badge */}
                <div className={`w-11 h-11 rounded-xl flex items-center justify-center shrink-0 ${
                  isEntrada
                    ? 'bg-emerald-100 text-emerald-600'
                    : 'bg-orange-100 text-orange-600'
                }`}>
                  {isEntrada ? <LogIn size={20} /> : <LogOutIcon size={20} />}
                </div>

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <p className="font-bold text-gray-800 text-sm truncate">{v.nome_morador}</p>
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                      isEntrada
                        ? 'bg-emerald-100 text-emerald-700'
                        : 'bg-orange-100 text-orange-700'
                    }`}>
                      {isEntrada ? 'ENTRADA' : 'SAÍDA'}
                    </span>
                  </div>
                  <div className="flex items-center gap-3 mt-1">
                    {(v.bloco || v.apto) && (
                      <span className="text-xs text-gray-500">
                        {getBlocoLabel(tipoEstrutura)} {v.bloco || '–'} / {getAptoLabel(tipoEstrutura)} {v.apto || '–'}
                      </span>
                    )}
                  </div>
                </div>

                {/* Crachá badge — prominent center */}
                {v.cracha_referencia && (
                  <div className="flex flex-col items-center gap-0.5 shrink-0 px-2">
                    <div className="bg-linear-to-br from-amber-100 to-amber-200 border border-amber-300 rounded-xl px-4 py-2 flex items-center gap-2 shadow-sm">
                      <span className="text-amber-600 text-base">🪪</span>
                      <span className="text-lg font-extrabold text-amber-800 tracking-wide">{v.cracha_referencia}</span>
                    </div>
                    <span className="text-[9px] text-amber-500 font-semibold uppercase tracking-wider">Crachá</span>
                  </div>
                )}

                {/* Time */}
                <div className="text-right shrink-0">
                  <p className="text-sm font-semibold text-gray-700">{fmtDateShort(v.created_at)}</p>
                  <p className="text-[10px] text-gray-400">{new Date(v.created_at).toLocaleDateString('pt-BR')}</p>
                </div>
              </div>
            )
          })
        )}
      </div>

      {/* ── Pagination ────────────────────────────────────── */}
      {totalCount > 0 && (
        <div className="flex items-center justify-between mt-5">
          <p className="text-xs text-gray-400">
            Mostrando {page * PAGE_SIZE + 1}–{Math.min((page + 1) * PAGE_SIZE, totalCount)} de {totalCount} registro{totalCount !== 1 ? 's' : ''}
          </p>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setPage(p => Math.max(0, p - 1))}
              disabled={page === 0}
              className="px-4 py-2 text-sm font-semibold rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
            >
              ← Anterior
            </button>
            <span className="text-sm font-medium text-gray-500">
              {page + 1} / {totalPages}
            </span>
            <button
              onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
              disabled={page >= totalPages - 1}
              className="px-4 py-2 text-sm font-semibold rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
            >
              Próximo →
            </button>
          </div>
        </div>
      )}

      {/* ══════════════════════════════════════════════════════ */}
      {/* ── REGISTRATION MODAL ──────────────────────────────── */}
      {/* ══════════════════════════════════════════════════════ */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto">
            {/* Modal header */}
            <div className="bg-[#FC5931] text-white px-6 py-4 rounded-t-2xl flex items-center justify-between">
              <h2 className="text-lg font-bold">Registrar Visita</h2>
              <button onClick={resetModal} className="text-white/80 hover:text-white transition-colors" title="Fechar">
                <X size={22} />
              </button>
            </div>

            <div className="p-6 space-y-5">
              {/* Tipo: Entrada / Saída */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">Tipo de Registro</label>
                <div className="grid grid-cols-2 gap-3">
                  <button
                    type="button"
                    onClick={() => setModalTipo('entrada')}
                    className={`flex items-center justify-center gap-2 py-3 rounded-xl font-semibold text-sm transition-all border-2 ${
                      modalTipo === 'entrada'
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700 shadow-sm'
                        : 'border-gray-200 text-gray-500 hover:border-gray-300'
                    }`}
                  >
                    <LogIn size={18} /> Entrada
                  </button>
                  <button
                    type="button"
                    onClick={() => setModalTipo('saida')}
                    className={`flex items-center justify-center gap-2 py-3 rounded-xl font-semibold text-sm transition-all border-2 ${
                      modalTipo === 'saida'
                        ? 'border-orange-500 bg-orange-50 text-orange-700 shadow-sm'
                        : 'border-gray-200 text-gray-500 hover:border-gray-300'
                    }`}
                  >
                    <LogOutIcon size={18} /> Saída
                  </button>
                </div>
              </div>

              {/* Bloco / Apto */}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">{getBlocoLabel(tipoEstrutura)} *</label>
                  <select
                    value={modalBloco}
                    onChange={e => { setModalBloco(e.target.value); setModalApto(''); setModalMoradorId(null); setModalNome('') }}
                    title={`Selecione o ${getBlocoLabel(tipoEstrutura).toLowerCase()}`}
                    className="w-full border border-gray-200 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30 bg-white"
                  >
                    <option value="">Selecione</option>
                    {blocos.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">{getAptoLabel(tipoEstrutura)} *</label>
                  <select
                    value={modalApto}
                    onChange={e => { setModalApto(e.target.value); setModalMoradorId(null); setModalNome('') }}
                    disabled={!modalBloco}
                    title={`Selecione o ${getAptoLabel(tipoEstrutura).toLowerCase()}`}
                    className="w-full border border-gray-200 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30 bg-white disabled:bg-gray-50 disabled:text-gray-400"
                  >
                    <option value="">Selecione</option>
                    {modalAvailableAptos.map(a => <option key={a} value={a}>{a}</option>)}
                  </select>
                </div>
              </div>

              {/* Moradores da unidade */}
              {modalBloco && modalApto && unitMoradores.length > 0 && (
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">
                    Moradores desta unidade
                  </label>
                  <div className="grid grid-cols-2 gap-2 max-h-40 overflow-y-auto">
                    {unitMoradores.map(m => (
                      <button
                        key={m.id}
                        type="button"
                        onClick={() => selectMorador(m)}
                        className={`text-left px-3 py-2.5 rounded-lg text-sm transition-all border truncate ${
                          modalMoradorId === m.id
                            ? 'border-[#FC5931] bg-[#FC5931]/5 text-[#FC5931] font-semibold'
                            : 'border-gray-200 text-gray-700 hover:border-gray-300 hover:bg-gray-50'
                        }`}
                      >
                        <span className="mr-1">{modalMoradorId === m.id ? '✅' : '👤'}</span>
                        {m.nome}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Nome manual */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">
                  Nome do morador *
                  {unitMoradores.length > 0 && (
                    <span className="font-normal text-gray-400 ml-1">(ou digite caso não cadastrado)</span>
                  )}
                </label>
                <input
                  type="text"
                  value={modalNome}
                  onChange={e => { setModalNome(e.target.value); setModalMoradorId(null) }}
                  placeholder="Nome do morador"
                  className="w-full border border-gray-200 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                />
              </div>

              {/* Crachá / Referência */}
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">
                  Crachá / Referência
                  <span className="font-normal text-gray-400 ml-1">(opcional)</span>
                </label>
                <input
                  type="text"
                  value={modalCracha}
                  onChange={e => setModalCracha(e.target.value)}
                  placeholder="Nº do crachá ou referência"
                  className="w-full border border-gray-200 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-[#FC5931] focus:ring-1 focus:ring-[#FC5931]/30"
                />
              </div>

              {/* Error */}
              {error && (
                <div className="flex items-center gap-2 text-red-600 text-sm bg-red-50 p-3 rounded-lg">
                  <AlertCircle size={16} /> {error}
                </div>
              )}

              {/* Submit */}
              <button
                onClick={handleSave}
                disabled={isPending || saved}
                className={`w-full py-3.5 rounded-xl font-bold text-base transition-all flex items-center justify-center gap-2 shadow-lg ${
                  modalTipo === 'entrada'
                    ? 'bg-emerald-600 hover:bg-emerald-700 text-white shadow-emerald-600/20'
                    : 'bg-orange-500 hover:bg-orange-600 text-white shadow-orange-500/20'
                } disabled:opacity-60`}
              >
                {isPending ? (
                  <><Clock size={20} className="animate-spin" /> Registrando...</>
                ) : saved ? (
                  <><CheckCircle size={20} /> Registrado com sucesso!</>
                ) : (
                  <>
                    {modalTipo === 'entrada' ? <LogIn size={20} /> : <LogOutIcon size={20} />}
                    Registrar {modalTipo === 'entrada' ? 'Entrada' : 'Saída'}
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'
import { useState, useEffect, useCallback, useTransition } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { RefreshCw, Filter, ChevronLeft, ChevronRight, CheckCircle2 } from 'lucide-react'
import { QRCodeSVG } from 'qrcode.react'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

interface PerfilJoin {
  nome_completo: string
  bloco_txt: string | null
  apto_txt: string | null
}

interface Invitation {
  id: string
  qr_data: string | null
  guest_name: string | null
  visitor_type: string | null
  visitante_compareceu: boolean | number
  validity_date: string
  created_at: string
  liberado_em: string | null
  status: string | null
  perfil: PerfilJoin | null
  criado_por_portaria?: boolean
  bloco_destino?: string | null
  apto_destino?: string | null
  morador_nome_manual?: string | null
}

interface Props {
  initialInvitations: Invitation[]
  initialTotal: number
  condoId: string
  userId: string
  tipoEstrutura?: string
}

const PAGE_SIZE = 10

export default function VisitorList({ initialInvitations, initialTotal, condoId, userId, tipoEstrutura }: Props) {
  const [invitations, setInvitations] = useState<Invitation[]>(initialInvitations)
  const [total, setTotal] = useState(initialTotal)
  const [approving, setApproving] = useState<string | null>(null)
  const [isPending, startTransition] = useTransition()
  const [loading, setLoading] = useState(false)
  const router = useRouter()
  const supabase = createClient()

  // Filters
  const [fCode, setFCode] = useState('')
  const [fBloco, setFBloco] = useState('')
  const [fApto, setFApto] = useState('')
  const [fDate, setFDate] = useState('')
  const [fStatus, setFStatus] = useState<null | boolean>(false)

  // Pagination
  const [page, setPage] = useState(1)
  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE))

  // Fetch from database with filters and pagination
  const fetchData = useCallback(async (currentPage: number) => {
    setLoading(true)
    try {
      // Build count query first
      let countQuery = supabase
        .from('convites')
        .select('id', { count: 'exact', head: true })
        .eq('condominio_id', condoId)

      // Build data query
      let dataQuery = supabase
        .from('convites')
        .select('id, qr_data, guest_name, visitor_type, visitante_compareceu, validity_date, created_at, liberado_em, resident_id, status, criado_por_portaria, bloco_destino, apto_destino, morador_nome_manual')
        .eq('condominio_id', condoId)
        .order('created_at', { ascending: false })
        .range((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE - 1)

      // Apply filters
      if (fCode) {
        countQuery = countQuery.ilike('qr_data', `%${fCode}%`)
        dataQuery = dataQuery.ilike('qr_data', `%${fCode}%`)
      }
      if (fDate) {
        countQuery = countQuery.gte('validity_date', `${fDate}T00:00:00`).lte('validity_date', `${fDate}T23:59:59`)
        dataQuery = dataQuery.gte('validity_date', `${fDate}T00:00:00`).lte('validity_date', `${fDate}T23:59:59`)
      }
      if (fStatus !== null) {
        countQuery = countQuery.eq('visitante_compareceu', fStatus)
        dataQuery = dataQuery.eq('visitante_compareceu', fStatus)
      }

      // Note: bloco/apto filters need special handling since they can be in perfil or bloco_destino
      // We filter by bloco_destino/apto_destino for portaria-created, and join for resident-created
      if (fBloco) {
        countQuery = countQuery.or(`bloco_destino.ilike.%${fBloco}%`)
        dataQuery = dataQuery.or(`bloco_destino.ilike.%${fBloco}%`)
      }
      if (fApto) {
        countQuery = countQuery.or(`apto_destino.ilike.%${fApto}%`)
        dataQuery = dataQuery.or(`apto_destino.ilike.%${fApto}%`)
      }

      const [{ count }, { data: convites }] = await Promise.all([countQuery, dataQuery])

      if (convites) {
        // Fetch perfil for residents
        const residentIds = [...new Set(convites.map((c: { resident_id: string }) => c.resident_id).filter(Boolean))]
        const perfilMap: Record<string, PerfilJoin> = {}
        if (residentIds.length > 0) {
          const { data: perfis } = await supabase
            .from('perfil')
            .select('id, nome_completo, bloco_txt, apto_txt')
            .in('id', residentIds)
          ;(perfis ?? []).forEach((p: { id: string; nome_completo: string; bloco_txt: string | null; apto_txt: string | null }) => { perfilMap[p.id] = p })
        }
        const merged = convites.map((c: Omit<Invitation, 'perfil'> & { resident_id: string }) => ({ ...c, perfil: perfilMap[c.resident_id] ?? null }))

        // Client-side filter by bloco/apto from perfil for non-portaria convites
        let finalResults = merged
        if (fBloco) {
          finalResults = finalResults.filter((i: Invitation) => {
            const b = i.criado_por_portaria ? i.bloco_destino : i.perfil?.bloco_txt
            return b?.toLowerCase().includes(fBloco.toLowerCase()) ?? false
          })
        }
        if (fApto) {
          finalResults = finalResults.filter((i: Invitation) => {
            const a = i.criado_por_portaria ? i.apto_destino : i.perfil?.apto_txt
            return a?.toLowerCase().includes(fApto.toLowerCase()) ?? false
          })
        }

        setInvitations(finalResults)
        setTotal(count ?? finalResults.length)
      }
    } catch (err) {
      console.error('Fetch error:', err)
    } finally {
      setLoading(false)
    }
  }, [condoId, fCode, fBloco, fApto, fDate, fStatus, supabase])

  // Debounced fetch on filter/page change
  useEffect(() => {
    const timer = setTimeout(() => {
      fetchData(page)
    }, 300)
    return () => clearTimeout(timer)
  }, [page, fCode, fBloco, fApto, fDate, fStatus])

  // Reset page when filters change
  useEffect(() => {
    setPage(1)
  }, [fCode, fBloco, fApto, fDate, fStatus])

  // Supabase Realtime: auto-refresh when convites change
  useEffect(() => {
    const channel = supabase
      .channel('realtime_convites_web')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'convites',
          filter: `condominio_id=eq.${condoId}`,
        },
        () => {
          fetchData(page)
        }
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [condoId, page, fCode, fBloco, fApto, fDate, fStatus])

  async function handleApprove(inv: Invitation) {
    if (Boolean(inv.visitante_compareceu)) return
    setApproving(inv.id)
    await supabase
      .from('convites')
      .update({
        visitante_compareceu: 1,
        liberado_por: userId,
        liberado_em: new Date().toISOString(),
      })
      .eq('id', inv.id)
    // Optimistic update local state
    setInvitations(prev =>
      prev.map(i => i.id === inv.id ? { ...i, visitante_compareceu: 1, liberado_em: new Date().toISOString() } : i)
    )
    setApproving(null)
  }

  const handleRefresh = () => {
    fetchData(page)
  }

  const isLiberado = (inv: Invitation) => Boolean(inv.visitante_compareceu)
  const statusOptions: { value: null | boolean; label: string }[] = [
    { value: null, label: '● Todos' },
    { value: false, label: '⏳ Pendentes' },
    { value: true, label: '✓ Liberados' },
  ]
  const hasFilters = fCode || fBloco || fApto || fDate || fStatus !== null
  const clearFilters = () => { setFCode(''); setFBloco(''); setFApto(''); setFDate(''); setFStatus(null) }

  return (
    <>
      <p className="text-gray-500 text-sm mb-4">
        {total} autorização{total !== 1 ? 'ões' : ''} encontrada{total !== 1 ? 's' : ''}
        {loading && <RefreshCw size={12} className="inline-block ml-2 animate-spin text-[#FC5931]" />}
      </p>

      {/* Filter bar */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-4 mb-5">
        <div className="flex flex-wrap gap-2 mb-3">
          {[
            { placeholder: 'Código', value: fCode, set: setFCode, width: 'w-24' },
            { placeholder: getBlocoLabel(tipoEstrutura), value: fBloco, set: setFBloco, width: 'w-24' },
            { placeholder: getAptoLabel(tipoEstrutura), value: fApto, set: setFApto, width: 'w-24' },
          ].map(f => (
            <input
              key={f.placeholder}
              type="text"
              placeholder={f.placeholder}
              value={f.value}
              onChange={e => f.set(e.target.value)}
              className={`${f.width} px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50`}
            />
          ))}
          <input
            type="date"
            value={fDate}
            onChange={e => setFDate(e.target.value)}
            aria-label="Filtrar por data de validade"
            title="Filtrar por data de validade"
            className="px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50"
          />

        </div>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500 font-medium">Status:</span>
            <div className="flex rounded-xl border border-gray-200 overflow-hidden bg-white shadow-sm">
              {statusOptions.map(opt => (
                <button
                  key={String(opt.value)}
                  onClick={() => setFStatus(opt.value)}
                  className={`px-3 py-1.5 text-xs font-semibold transition-colors ${
                    fStatus === opt.value
                      ? opt.value === null
                        ? 'bg-gray-600 text-white'
                        : opt.value === false
                          ? 'bg-orange-500 text-white'
                          : 'bg-green-600 text-white'
                      : 'text-gray-500 hover:bg-gray-50'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>
            {hasFilters && (
              <button onClick={clearFilters} className="text-xs text-gray-400 hover:text-red-500 transition-colors ml-1">
                Limpar
              </button>
            )}
          </div>
          <button
            onClick={handleRefresh}
            disabled={loading}
            className="p-2 text-[#FC5931] hover:bg-[#FC5931]/10 rounded-lg transition-colors"
            title="Atualizar"
          >
            <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
          </button>
        </div>
      </div>

      {/* Cards */}
      {invitations.length === 0 && !loading ? (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm py-16 text-center">
          <Filter size={32} className="mx-auto text-gray-300 mb-3" />
          <p className="text-gray-500 font-medium">Nenhuma autorização encontrada</p>
          {hasFilters && (
            <button onClick={clearFilters} className="text-sm text-[#FC5931] hover:underline mt-2">
              Limpar filtros
            </button>
          )}
        </div>
      ) : (
        <div className="space-y-4">
          {invitations.map(inv => {
            const liberado = isLiberado(inv)
            const isPortaria = inv.criado_por_portaria === true
            const bloco = isPortaria ? (inv.bloco_destino ?? '—') : (inv.perfil?.bloco_txt ?? '—')
            const apto = isPortaria ? (inv.apto_destino ?? '—') : (inv.perfil?.apto_txt ?? '—')
            const residentName = isPortaria
              ? (inv.perfil?.nome_completo ?? inv.morador_nome_manual ?? 'Não identificado')
              : (inv.perfil?.nome_completo ?? '—')
            const solicitadoPor = isPortaria ? 'Portaria' : residentName
            return (
              <div
                key={inv.id}
                className={`bg-white rounded-2xl border shadow-sm overflow-hidden ${
                  liberado ? 'border-green-200' : 'border-orange-100'
                }`}
              >
                {/* Header */}
                <div className={`px-5 py-3 flex items-center justify-between ${liberado ? 'bg-green-500' : 'bg-[#FC5931]'}`}>
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center flex-shrink-0">
                      <span className="text-white font-bold text-xs leading-tight text-center">
                        {inv.qr_data ? inv.qr_data.slice(-4).toUpperCase() : '—'}
                      </span>
                    </div>
                    <div>
                      <p className="text-white font-semibold text-sm">
                        {getBlocoLabel(tipoEstrutura)}: {bloco} / {getAptoLabel(tipoEstrutura)}: {apto}
                      </p>
                      <p className="text-white/80 text-xs">
                        {isPortaria ? `Solicitado por: ${solicitadoPor}` : `Morador(a): ${residentName}`}
                      </p>
                    </div>
                  </div>
                  <span className="text-xs font-bold px-3 py-1 rounded-full bg-white/20 text-white">
                    {isPortaria ? 'Registrado via Portaria' : 'Acesso para Unidade'}
                  </span>
                </div>

                {/* Body */}
                <div className="px-5 py-4">
                  <div className="flex gap-4">
                    <div className="flex-1 grid grid-cols-2 gap-x-8 gap-y-2 mb-4 text-sm">
                      <div>
                        <span className="text-xs text-gray-400 block">Data da visita</span>
                        <span className="font-medium text-gray-800">
                          {inv.validity_date ? new Date((inv.validity_date.includes('T') ? inv.validity_date.split('T')[0] : inv.validity_date) + 'T00:00:00').toLocaleDateString('pt-BR') : '—'}
                        </span>
                      </div>
                      <div>
                        <span className="text-xs text-gray-400 block">Tipo de visitante</span>
                        <span className="font-medium text-gray-800">{inv.visitor_type || '—'}</span>
                      </div>
                      <div className="col-span-2">
                        <span className="text-xs text-gray-400 block">Nome Visitante</span>
                        <span className="font-medium text-gray-800">{inv.guest_name || 'Nome não preenchido'}</span>
                      </div>
                    </div>
                    {/* QR Code */}
                    {inv.qr_data && (
                      <div className="flex flex-col items-center justify-center flex-shrink-0">
                        <div className="bg-white border border-gray-200 rounded-xl p-2 shadow-sm">
                          <QRCodeSVG value={inv.qr_data} size={80} />
                        </div>
                        <span className="text-[10px] text-gray-400 mt-1 font-mono tracking-wider">
                          {inv.qr_data.length > 6 ? inv.qr_data.slice(-3).toUpperCase() : inv.qr_data.toUpperCase()}
                        </span>
                      </div>
                    )}
                  </div>

                  {/* Approve row */}
                  <div className="flex items-center justify-between border-t border-gray-100 pt-3">
                    <div className="flex items-center gap-3">
                      <span className="text-sm text-gray-600">Visitante compareceu</span>
                      {liberado ? (
                        <span className="flex items-center gap-1.5 text-green-600 text-sm font-semibold">
                          <CheckCircle2 size={15} />
                          Confirmado
                        </span>
                      ) : (
                        <button
                          onClick={() => handleApprove(inv)}
                          disabled={approving === inv.id}
                          className="flex items-center gap-2 px-4 py-1.5 bg-[#FC5931] text-white text-sm font-semibold rounded-xl hover:bg-[#D42F1D] transition-colors disabled:opacity-60"
                        >
                          {approving === inv.id && <RefreshCw size={13} className="animate-spin" />}
                          Confirmar Entrada
                        </button>
                      )}
                    </div>
                    <div className="text-right text-xs text-gray-400 space-y-0.5">
                      <p>
                        Criado em: {new Date(inv.created_at).toLocaleDateString('pt-BR')} – {new Date(inv.created_at).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                      </p>
                      <p>Solicitado por: {residentName}</p>
                    </div>
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      )}

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-center gap-4 mt-6">
          <button
            onClick={() => setPage(p => Math.max(1, p - 1))}
            disabled={page === 1 || loading}
            aria-label="Página anterior"
            title="Página anterior"
            className="p-2 rounded-xl border border-gray-200 text-gray-500 hover:bg-gray-50 disabled:opacity-40 transition-colors"
          >
            <ChevronLeft size={16} />
          </button>
          <span className="text-sm text-gray-600 font-medium">{page} de {totalPages}</span>
          <button
            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
            disabled={page === totalPages || loading}
            aria-label="Próxima página"
            title="Próxima página"
            className="p-2 rounded-xl border border-gray-200 text-gray-500 hover:bg-gray-50 disabled:opacity-40 transition-colors"
          >
            <ChevronRight size={16} />
          </button>
        </div>
      )}
    </>
  )
}

'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { UserCheck, Plus, X, CheckCircle2, Clock, QrCode, ChevronDown } from 'lucide-react'
import { QRCodeSVG } from 'qrcode.react'
import { getBlocoLabel, getAptoLabel } from '@/lib/labels'

type Convite = {
  id: string
  qr_data: string | null
  guest_name: string | null
  visitor_type: string | null
  visitante_compareceu: boolean | number
  validity_date: string
  created_at: string
  liberado_em: string | null
  status: string | null
}

const VISITOR_TYPES = ['Uber ou Taxi', 'Delivery', 'Farmácia', 'Diarista', 'Visitante', 'Mat. Obra', 'Serviços', 'Hóspedes', 'Outros']

function formatDate(dateStr: string) {
  if (!dateStr) return '—'
  try {
    // Handle both 'YYYY-MM-DD' and full ISO timestamps like '2026-03-15T11:12:39.062659+00:00'
    const dateOnly = dateStr.includes('T') ? dateStr.split('T')[0] : dateStr
    const d = new Date(dateOnly + 'T00:00:00')
    if (isNaN(d.getTime())) return dateStr
    return d.toLocaleDateString('pt-BR', {
      day: '2-digit', month: '2-digit', year: 'numeric',
    })
  } catch {
    return dateStr
  }
}

function ConviteCard({ convite }: { convite: Convite }) {
  const chegou = Boolean(convite.visitante_compareceu)
  const dateOnly = convite.validity_date?.includes('T') ? convite.validity_date.split('T')[0] : convite.validity_date
  const validDate = new Date(dateOnly + 'T00:00:00')
  const isExpired = validDate < new Date() && !chegou
  // Show short code: for long codes like CONDOMEET_INV_xxx, show last 3 chars
  const rawCode = convite.qr_data ? convite.qr_data.toUpperCase() : '—'
  const code = rawCode.length > 6 ? rawCode.slice(-3) : rawCode

  return (
    <div className={`bg-white rounded-2xl border shadow-sm overflow-hidden ${
      chegou ? 'border-green-200' : isExpired ? 'border-gray-200' : 'border-orange-100'
    }`}>
      <div className={`px-5 py-3 flex items-center justify-between ${
        chegou ? 'bg-emerald-500' : isExpired ? 'bg-gray-400' : 'bg-[#FC5931]'
      }`}>
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-white/20 rounded-xl flex items-center justify-center">
            <span className="text-white font-bold text-xs">{code}</span>
          </div>
          <div>
            <p className="text-white font-semibold text-sm">{convite.guest_name || 'Visitante'}</p>
            <p className="text-white/70 text-xs">{convite.visitor_type || 'Tipo não informado'}</p>
          </div>
        </div>
        <div className="text-right">
          {chegou ? (
            <span className="flex items-center gap-1 text-white text-xs font-bold">
              <CheckCircle2 size={14} /> Entrou
            </span>
          ) : isExpired ? (
            <span className="text-white text-xs font-bold">Expirado</span>
          ) : (
            <span className="flex items-center gap-1 text-white text-xs font-bold">
              <Clock size={14} /> Aguardando
            </span>
          )}
        </div>
      </div>

      <div className="px-5 py-4 flex items-center justify-between">
        <div className="text-sm">
          <p className="text-gray-400 text-xs mb-0.5">Data da visita</p>
          <p className="font-semibold text-gray-800">{formatDate(convite.validity_date)}</p>
        </div>
        {convite.qr_data && (
          <div className="flex flex-col items-center">
            <div className="bg-white border border-gray-200 rounded-xl p-1.5 shadow-sm">
              <QRCodeSVG value={convite.qr_data} size={64} />
            </div>
            <span className="text-[10px] text-gray-400 mt-0.5 font-mono tracking-widest">{code}</span>
          </div>
        )}
      </div>
    </div>
  )
}

export default function VisitantesResidentClient({
  initialConvites,
  userId,
  condoId,
  residentName,
  bloco,
  apto,
  tipoEstrutura,
}: {
  initialConvites: Convite[]
  userId: string
  condoId: string
  residentName: string
  bloco: string
  apto: string
  tipoEstrutura?: string
}) {
  const [convites, setConvites] = useState<Convite[]>(initialConvites)
  const [showModal, setShowModal] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [filter, setFilter] = useState<'todos' | 'pendente' | 'entrou'>('todos')
  const [loadedAll, setLoadedAll] = useState(initialConvites.length < 5)
  const [loadingMore, setLoadingMore] = useState(false)

  const todayStr = new Date().toISOString().split('T')[0]
  const [form, setForm] = useState({
    guest_name: '',
    visitor_type: '',
    validity_date: todayStr,
    whatsapp: '',
    observacao: '',
    documento: '',
    placa: '',
    cracha_referencia: '',
  })

  const filtered = convites.filter(c => {
    if (filter === 'pendente') return !Boolean(c.visitante_compareceu)
    if (filter === 'entrou') return Boolean(c.visitante_compareceu)
    return true
  })

  async function handleCreate() {
    if (!form.visitor_type || !form.validity_date) {
      setError('Escolha o tipo de visitante e a data de validade.')
      return
    }
    setSaving(true)
    setError('')
    const supabase = createClient()
    const { data: { user: cu } } = await supabase.auth.getUser()

    // Generate 3-char random alphanumeric code
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
    const code = Array.from({ length: 3 }, () => chars[Math.floor(Math.random() * chars.length)]).join('')
    const now = new Date().toISOString()

    const { data: inserted, error: insertError } = await supabase
      .from('convites')
      .insert({
        resident_id: cu?.id ?? userId,
        condominio_id: condoId,
        guest_name: form.guest_name.trim() || '',
        visitor_type: form.visitor_type,
        validity_date: form.validity_date,
        qr_data: code,
        visitante_compareceu: false,
        status: 'active',
        created_at: now,
        whatsapp: form.whatsapp.trim() || null,
        observacao: form.observacao.trim() || null,
        documento: form.documento.trim() || null,
        placa: form.placa.trim() || null,
        cracha_referencia: form.cracha_referencia.trim() || null,
      })
      .select()
      .single()

    if (insertError) {
      setError('Erro ao criar autorização. Tente novamente.')
    } else if (inserted) {
      setConvites(prev => [inserted, ...prev])
      setShowModal(false)
      setForm({ guest_name: '', visitor_type: '', validity_date: todayStr, whatsapp: '', observacao: '', documento: '', placa: '', cracha_referencia: '' })
    }
    setSaving(false)
  }

  // Min date = today
  const today = new Date().toISOString().split('T')[0]

  async function handleLoadMore() {
    setLoadingMore(true)
    const supabase = createClient()
    const { data } = await supabase
      .from('convites')
      .select('id, qr_data, guest_name, visitor_type, visitante_compareceu, validity_date, created_at, liberado_em, status')
      .eq('resident_id', userId)
      .eq('condominio_id', condoId)
      .order('created_at', { ascending: false })
    if (data) setConvites(data)
    setLoadedAll(true)
    setLoadingMore(false)
  }

  return (
    <div>
      {/* Toolbar */}
      <div className="flex items-center justify-between mb-5 gap-3 flex-wrap">
        <div className="flex items-center gap-2">
          {[
            { key: 'todos',    label: `Todos (${convites.length})` },
            { key: 'pendente', label: 'Aguardando' },
            { key: 'entrou',   label: 'Entraram' },
          ].map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setFilter(key as typeof filter)}
              className={`text-sm font-medium px-4 py-2 rounded-xl border transition-all ${
                filter === key
                  ? 'bg-[#FC5931] text-white border-[#FC5931] shadow-sm'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-[#FC5931]/50 hover:text-[#FC5931]'
