'use client'
import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Mail, ArrowLeft } from 'lucide-react'

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState('')
  const [loading, setLoading] = useState(false)
  const [sent, setSent] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit() {
    const supabase = createClient()
    const normalizedEmail = email.trim().toLowerCase()
    if (!normalizedEmail || !normalizedEmail.includes('@')) {
      setError('Digite um email válido')
      return
    }
    setLoading(true)
    setError('')
    try {
      const { error: resetError } = await supabase.auth.resetPasswordForEmail(normalizedEmail, {
        redirectTo: `${window.location.origin}/reset-password`
      })
      if (resetError) throw resetError
      setSent(true)
    } catch (e) {
      setError('Erro ao enviar email. Verifique e tente novamente.')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-[#f4f6f9] flex items-center justify-center p-6">
      <div className="bg-white rounded-3xl shadow-xl w-full max-w-sm p-8">
        <a href="/login" className="flex items-center gap-2 text-sm text-gray-500 hover:text-[#FC5931] mb-6 transition-colors">
          <ArrowLeft size={16} /> Voltar ao login
        </a>

        {sent ? (
          <div className="text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-3xl">✉️</span>
            </div>
            <h2 className="text-xl font-bold text-gray-900 mb-2">Email enviado!</h2>
            <p className="text-sm text-gray-500 mb-6">
              Verifique sua caixa de entrada e clique no link para redefinir sua senha.
            </p>
            <p className="text-xs text-gray-400">
              Enviado para <strong>{email}</strong>
            </p>
          </div>
        ) : (
          <>
            <div className="flex flex-col items-center mb-6">
              <div className="w-14 h-14 bg-[#FC5931]/10 rounded-full flex items-center justify-center mb-3">
                <Mail size={28} className="text-[#FC5931]" />
              </div>
              <h2 className="text-xl font-bold text-gray-900">Esqueci a senha</h2>
              <p className="text-sm text-gray-500 text-center mt-1">
                Digite seu email e enviaremos um link para redefinir sua senha.
              </p>
            </div>

            <div className="space-y-3">
              <div className="relative">
                <Mail size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type="email"
                  placeholder="Digite seu email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleSubmit()}
                  className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
                />
              </div>

              {error && <p className="text-red-500 text-xs text-center">{error}</p>}

              <button
                onClick={handleSubmit}
                disabled={loading || !email}
                className="w-full py-3 bg-[#FC5931] text-white rounded-xl font-bold text-sm hover:bg-[#D42F1D] transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {loading ? 'Enviando...' : 'Enviar Link de Redefinição'}
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  )
}

'use client'
import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { Eye, EyeOff, Mail, Lock } from 'lucide-react'

export default function LoginPage() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [remember, setRemember] = useState(true)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const router = useRouter()
  const supabase = createClient()

  // Estado para o modal de atualização de senha
  const [showPasswordSetup, setShowPasswordSetup] = useState(false)
  const [setupEmail, setSetupEmail] = useState('')
  const [newPassword, setNewPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [setupLoading, setSetupLoading] = useState(false)
  const [setupError, setSetupError] = useState('')
  const [showNewPwd, setShowNewPwd] = useState(false)
  const [showConfirmPwd, setShowConfirmPwd] = useState(false)

  // Estado para tela de bloqueio
  const [showBlocked, setShowBlocked] = useState(false)
  const [blockedMessage, setBlockedMessage] = useState('')

  async function handleLogin() {
    setLoading(true)
    setError('')
    const normalizedEmail = email.trim().toLowerCase()
    const { data: loginData, error: loginError } = await supabase.auth.signInWithPassword({ email: normalizedEmail, password })
    if (loginError) {
      // Verifica se é morador migrado que precisa configurar senha
      if (loginError.message?.includes('Invalid login credentials') || loginError.message?.includes('invalid_credentials')) {
        const { data: needsSetup } = await supabase.rpc('check_needs_password_setup', { user_email: normalizedEmail })
        if (needsSetup === true) {
          setSetupEmail(normalizedEmail)
          setShowPasswordSetup(true)
          setLoading(false)
          return
        }
      }
      setError('E-mail ou senha incorretos. Verifique seus dados.')
      setLoading(false)
      return
    }

    // Login OK — verifica se está bloqueado/pendente
    if (loginData?.user) {
      const { data: perfil } = await supabase
        .from('perfil')
        .select('status_aprovacao')
        .eq('id', loginData.user.id)
        .single()

      if (perfil?.status_aprovacao === 'bloqueado' || perfil?.status_aprovacao === 'pendente') {
        setShowBlocked(true)
        setBlockedMessage(
          perfil.status_aprovacao === 'bloqueado'
            ? 'Seu acesso está bloqueado. Aguarde a liberação do síndico.'
            : 'Seu cadastro está pendente de aprovação pelo síndico.'
        )
        setLoading(false)
        return
      }
    }

    router.push('/condo')
    router.refresh()
  }

  async function handlePasswordSetup() {
    if (newPassword.length < 4) { setSetupError('Mínimo de 4 dígitos'); return }
    if (newPassword !== confirmPassword) { setSetupError('As senhas não coincidem'); return }
    setSetupLoading(true)
    setSetupError('')
    try {
      await supabase.rpc('setup_user_password', { user_email: setupEmail, new_password: newPassword })
      const { data: loginData, error: loginError } = await supabase.auth.signInWithPassword({ email: setupEmail, password: newPassword })
      if (loginError) throw loginError

      // Verifica se está bloqueado/pendente após configurar senha
      if (loginData?.user) {
        const { data: perfil } = await supabase
          .from('perfil')
          .select('status_aprovacao')
          .eq('id', loginData.user.id)
          .single()

        if (perfil?.status_aprovacao === 'bloqueado' || perfil?.status_aprovacao === 'pendente') {
          setShowPasswordSetup(false)
          setShowBlocked(true)
          setBlockedMessage(
            perfil.status_aprovacao === 'bloqueado'
              ? 'Seu acesso está bloqueado. Aguarde a liberação do síndico.'
              : 'Seu cadastro está pendente de aprovação pelo síndico.'
          )
          setSetupLoading(false)
          return
        }
      }

      router.push('/condo')
      router.refresh()
    } catch (e) {
      setSetupError('Erro ao definir senha. Tente novamente.')
      setSetupLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-[#f4f6f9] flex">
      {/* Left brand panel */}
      <div className="hidden lg:flex flex-col items-center justify-center w-96 bg-gradient-to-b from-[#FC5931] to-[#D42F1D] p-10 text-white">
        <img src="/logo.png" alt="Condomeet" className="w-24 h-24 rounded-3xl object-cover mb-6 shadow-lg" />
        <h1 className="text-3xl font-bold mb-2">Condomeet</h1>
        <p className="text-white/70 text-center text-sm leading-relaxed">
          Seu condomínio digital.<br/>Simples, seguro e conectado.
        </p>
        <div className="mt-10 space-y-3 w-full">
          {['Autorizar visitantes', 'Gerenciar encomendas', 'Comunicação com moradores'].map(f => (
            <div key={f} className="flex items-center gap-3 text-sm text-white/80">
              <div className="w-5 h-5 rounded-full bg-white/20 flex items-center justify-center flex-shrink-0">
                <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
                  <path d="M2 5l2 2 4-4" stroke="white" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
              </div>
              {f}
            </div>
          ))}
        </div>
      </div>

      {/* Right login panel */}
      <div className="flex-1 flex items-center justify-center p-6">
        <div className="bg-white rounded-3xl shadow-xl w-full max-w-sm p-8">
          {/* Mobile logo */}
          <div className="lg:hidden flex flex-col items-center mb-6">
            <img src="/logo.png" alt="Condomeet" className="w-16 h-16 rounded-2xl object-cover mb-3 shadow-md" />
            <h1 className="text-xl font-bold text-gray-900">Condomeet</h1>
            <p className="text-xs text-[#FC5931] font-medium mt-0.5">seu Condomínio Digital</p>
          </div>

          {/* Register banner */}
          <a href="/register" className="block w-full mb-6 py-3 bg-[#FC5931] text-white rounded-xl text-sm font-semibold text-center hover:bg-[#D42F1D] transition-colors">
            Ainda não tem cadastro? Clique aqui!
          </a>

          <div className="text-center mb-5">
            <p className="text-sm font-semibold text-gray-700">Já é cadastrado?</p>
            <p className="text-xs text-gray-400">Digite E-mail e Senha</p>
          </div>

          {/* Form */}
          <div className="space-y-3">
            <div className="relative">
              <Mail size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
              <input
                type="email"
                placeholder="Digite seu email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleLogin()}
                className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
              />
            </div>

            <div className="relative">
              <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
              <input
                type={showPassword ? 'text' : 'password'}
                inputMode="numeric"
                placeholder="Senha (somente números)"
                value={password}
                onChange={e => setPassword(e.target.value.replace(/\D/g, ''))}
                onKeyDown={e => e.key === 'Enter' && handleLogin()}
                className="w-full pl-10 pr-11 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>

            <div className="flex items-center justify-between text-sm">
              <label className="flex items-center gap-2 cursor-pointer">
                <input
                  type="checkbox"
                  checked={remember}
                  onChange={e => setRemember(e.target.checked)}
                  className="w-4 h-4 rounded accent-[#FC5931]"
                />
                <span className="text-gray-600 text-xs">Lembrar Senha</span>
              </label>
              <a href="/forgot-password" className="text-xs text-[#FC5931] hover:underline">Esqueci a senha</a>
            </div>

            {error && <p className="text-red-500 text-xs text-center">{error}</p>}

            <button
              onClick={handleLogin}
              disabled={loading || !email || !password}
              className="w-full py-3 border-2 border-[#FC5931] text-[#FC5931] rounded-xl font-bold text-sm hover:bg-[#FC5931] hover:text-white transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? 'Acessando...' : 'Acessar'}
            </button>
          </div>

          <div className="mt-5 text-center">
            <a href="/sindico-register" className="text-xs text-gray-500 hover:text-[#FC5931] transition-colors">
              Sou Síndico e quero registrar meu condomínio
            </a>
          </div>

          <p className="mt-6 text-center text-[10px] text-gray-400">
            Todos os direitos reservados à @2SCapital @2026<br/>
            <a href="/privacidade" className="hover:underline">Política de Privacidade</a>
          </p>
        </div>
      </div>

      {/* Modal: Atualize sua senha */}
      {showPasswordSetup && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm p-8">
            <div className="flex flex-col items-center mb-6">
              <div className="w-14 h-14 bg-[#FC5931]/10 rounded-full flex items-center justify-center mb-3">
                <Lock size={28} className="text-[#FC5931]" />
              </div>
              <h2 className="text-xl font-bold text-gray-900">Atualize sua senha</h2>
              <p className="text-sm text-gray-500 text-center mt-1">
                Crie uma senha numérica para acessar o app.
              </p>
            </div>

            <div className="space-y-3">
              {/* Nova senha */}
              <div className="relative">
                <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type={showNewPwd ? 'text' : 'password'}
                  inputMode="numeric"
                  placeholder="Nova senha (somente números)"
                  value={newPassword}
                  onChange={e => setNewPassword(e.target.value.replace(/\D/g, ''))}
                  className="w-full pl-10 pr-11 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
                />
                <button type="button" onClick={() => setShowNewPwd(!showNewPwd)}
                  className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400">
                  {showNewPwd ? <EyeOff size={16}/> : <Eye size={16}/>}
                </button>
              </div>

              {/* Confirmar senha */}
              <div className="relative">
                <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type={showConfirmPwd ? 'text' : 'password'}
                  inputMode="numeric"
                  placeholder="Confirmar senha"
                  value={confirmPassword}
                  onChange={e => setConfirmPassword(e.target.value.replace(/\D/g, ''))}
                  className="w-full pl-10 pr-11 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
                />
                <button type="button" onClick={() => setShowConfirmPwd(!showConfirmPwd)}
                  className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400">
                  {showConfirmPwd ? <EyeOff size={16}/> : <Eye size={16}/>}
                </button>
              </div>

              {setupError && <p className="text-red-500 text-xs text-center">{setupError}</p>}

              <button
                onClick={handlePasswordSetup}
                disabled={setupLoading || !newPassword || !confirmPassword}
                className="w-full py-3 bg-[#FC5931] text-white rounded-xl font-bold text-sm hover:bg-[#D42F1D] transition-all disabled:opacity-50"
              >
                {setupLoading ? 'Salvando...' : 'Confirmar'}
              </button>

              <button onClick={() => setShowPasswordSetup(false)}
                className="w-full py-2 text-gray-400 text-xs hover:text-gray-600 transition-colors">
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Acesso Bloqueado */}
      {showBlocked && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm p-8 text-center">
            <div className="w-20 h-20 bg-orange-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-4xl">📞</span>
            </div>
            <h2 className="text-xl font-bold text-gray-900 mb-2">Solicitação Enviada!</h2>
            <p className="text-sm text-gray-500 mb-6">{blockedMessage}</p>
            <div className="bg-gray-50 rounded-xl p-4 mb-6">
              <p className="text-xs text-gray-500">💡 <strong>Dica:</strong> O síndico costuma analisar solicitações em horários comerciais.</p>
            </div>
            <button
              onClick={() => {
                setShowBlocked(false)
                supabase.auth.signOut()
              }}
              className="w-full py-3 bg-[#FC5931] text-white rounded-xl font-bold text-sm hover:bg-[#D42F1D] transition-all"
            >
              Voltar ao Início
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'
import { useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { Search, ChevronLeft, Building2, Mail, Lock, User, Phone, Eye, EyeOff, Check, Loader2, AlertTriangle } from 'lucide-react'
import { fetchAll } from '@/lib/supabase/utils'

const TIPO_USUARIO_OPTIONS = [
  'Proprietário (a)',
  'Inquilino (a)',
  'Cônjuge',
  'Dependente',
  'Família',
  'Funcionário (a)',
  'Terceirizado (a)',
]

const PERFIL_USUARIO_OPTIONS = [
  'Morador(a)',
  'Proprietário não morador',
  'Locatário (a)',
  'Locador',
  'Funcionário (a)',
  'Porteiro (a)',
  'Zelador (a)',
  'Síndico (a)',
  'Sub Síndico (a)',
  'Afiliado (a)',
  'Terceirizado (a)',
  'Financeiro',
  'Serviços',
]
type Condominio = { id: string; nome: string; endereco?: string; tipo_estrutura?: string; cidade?: string; estado?: string }
type Bloco = { id: string; nome_ou_numero: string }
type Apartamento = { id: string; numero: string }

function getNivel1Label(tipo: string) {
  if (tipo === 'casa_rua') return 'Rua'
  if (tipo === 'casa_quadra') return 'Quadra'
  return 'Bloco'
}

function getNivel2Label(tipo: string) {
  if (tipo === 'casa_rua') return 'Número'
  if (tipo === 'casa_quadra') return 'Lote'
  return 'Apartamento'
}

export default function RegisterPage() {
  const router = useRouter()
  const supabase = createClient()
  const [currentStep, setCurrentStep] = useState(0)
  const [loading, setLoading] = useState(false)
  const [globalError, setGlobalError] = useState('')

  // Step 1: Condomínio
  const [searchQuery, setSearchQuery] = useState('')
  const [isSearching, setIsSearching] = useState(false)
  const [condominios, setCondominios] = useState<Condominio[]>([])
  const [selectedCondo, setSelectedCondo] = useState<Condominio | null>(null)
  const [tipoEstrutura, setTipoEstrutura] = useState('predio')

  // Step 2: Conta
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [emailError, setEmailError] = useState('')
  const [isCheckingEmail, setIsCheckingEmail] = useState(false)
  const [showPwd, setShowPwd] = useState(false)
  const [showConfirmPwd, setShowConfirmPwd] = useState(false)

  // Step 3: Dados
  const [nome, setNome] = useState('')
  const [whatsapp, setWhatsapp] = useState('')
  const [tipoUsuario, setTipoUsuario] = useState('Proprietário (a)')
  const [perfilUsuario, setPerfilUsuario] = useState('Morador(a)')
  const [consentimentoWhatsapp, setConsentimentoWhatsapp] = useState(true)

  // Step 4: Unidade
  const [blocos, setBlocos] = useState<Bloco[]>([])
  const [apartamentos, setApartamentos] = useState<Apartamento[]>([])
  const [selectedBlocoId, setSelectedBlocoId] = useState('')
  const [selectedAptoId, setSelectedAptoId] = useState('')
  const [unitLimitReached, setUnitLimitReached] = useState(false)
  const [unitLimitMsg, setUnitLimitMsg] = useState('')
  const [isCheckingUnit, setIsCheckingUnit] = useState(false)

  // Success modal
  const [showSuccess, setShowSuccess] = useState(false)

  // Debounced search
  const searchCondominios = useCallback(
    (() => {
      let timer: ReturnType<typeof setTimeout>
      return (query: string) => {
        clearTimeout(timer)
        if (query.length < 3) {
          setCondominios([])
          return
        }
        timer = setTimeout(async () => {
          setIsSearching(true)
          try {
            const { data } = await supabase
              .from('condominios')
              .select('id, nome, cidade, estado, tipo_estrutura')
              .ilike('nome', `%${query}%`)
              .order('nome')
              .limit(10)
            setCondominios(data || [])
          } catch { /* ignore */ }
          setIsSearching(false)
        }, 500)
      }
    })(),
    [supabase]
  )

  async function fetchBlocos(condoId: string) {
    const data = await fetchAll(
      supabase
        .from('blocos')
        .select('id, nome_ou_numero')
        .eq('condominio_id', condoId)
        .order('nome_ou_numero')
    )
    setBlocos((data || []).filter((b: Bloco) => b.nome_ou_numero !== '0'))
    setSelectedBlocoId('')
    setSelectedAptoId('')
    setApartamentos([])
  }

  async function fetchApartamentos(condoId: string, blocoId: string) {
    const data = await fetchAll(
      supabase
        .from('unidades')
        .select('apartamento_id, apartamentos(numero)')
        .eq('condominio_id', condoId)
        .eq('bloco_id', blocoId)
        .order('apartamentos(numero)')
    )

    const aptos = (data || []).map((e: { apartamento_id: string; apartamentos: { numero: string } | { numero: string }[] | null }) => {
      const aptoData = e.apartamentos
      let numero = '0'
      if (Array.isArray(aptoData) && aptoData.length > 0) {
        numero = String(aptoData[0].numero)
      } else if (aptoData && typeof aptoData === 'object' && !Array.isArray(aptoData)) {
        numero = String((aptoData as { numero: string }).numero)
      }
      return { id: e.apartamento_id, numero }
    }).filter((e: Apartamento) => e.numero !== '0')

    setApartamentos(aptos)
    setSelectedAptoId('')
    setUnitLimitReached(false)
    setUnitLimitMsg('')
  }

  async function checkUnitLimit(condoId: string, blocoId: string, aptoId: string) {
    if (!condoId || !blocoId || !aptoId) return
    setIsCheckingUnit(true)
    setUnitLimitReached(false)
    setUnitLimitMsg('')
    try {
      const { data, error } = await supabase.rpc('check_unit_user_limit', {
        p_condominio_id: condoId,
        p_bloco_id: blocoId,
        p_apartamento_id: aptoId,
      })
      if (error) {
        console.warn('Erro ao verificar limite da unidade:', error)
      } else if (data && !data.allowed) {
        setUnitLimitReached(true)
        const blocoData = blocos.find((b) => b.id === blocoId)
        const aptoData = apartamentos.find((a) => a.id === aptoId)
        setUnitLimitMsg(
          `Esta unidade (${getNivel1Label(tipoEstrutura)} ${blocoData?.nome_ou_numero || ''} / ${getNivel2Label(tipoEstrutura)} ${aptoData?.numero || ''}) já possui ${data.count} usuário(s) aprovado(s), atingindo o limite máximo de ${data.limit}. Não é possível realizar o cadastro nesta unidade.`
        )
      }
    } catch (err) {
      console.warn('Erro ao verificar limite da unidade:', err)
    } finally {
      setIsCheckingUnit(false)
    }
  }

  function selectCondo(condo: Condominio) {
    setSelectedCondo(condo)
    setTipoEstrutura(condo.tipo_estrutura || 'predio')
    setCondominios([])
    setSearchQuery('')
    fetchBlocos(condo.id)
  }

  async function handleNext() {
    setGlobalError('')

    if (currentStep === 0) {
      if (!selectedCondo) {
        setGlobalError('Selecione seu condomínio primeiro')
        return
      }
      setCurrentStep(1)
    } else if (currentStep === 1) {
      // Validate email
      if (!email || !email.includes('@')) {
        setGlobalError('E-mail inválido')
        return
      }
      // Check email availability
      setIsCheckingEmail(true)
      try {
        const { data: exists } = await supabase.rpc('check_email_exists', { email_to_check: email.trim() })
        if (exists === true) {
          setEmailError('Este e-mail já existe. Tente fazer login.')
          setIsCheckingEmail(false)
          return
        }
      } catch {
        setEmailError('Erro ao verificar e-mail.')
        setIsCheckingEmail(false)
        return
      }
      setIsCheckingEmail(false)
      setEmailError('')

      if (!password || !/^\d+$/.test(password)) {
        setGlobalError('A senha deve conter apenas números')
        return
      }
      if (password !== confirmPassword) {
        setGlobalError('As senhas não coincidem')
        return
      }
      setCurrentStep(2)
    } else if (currentStep === 2) {
      if (!nome.trim()) { setGlobalError('Nome é obrigatório'); return }
      if (!whatsapp || whatsapp.length < 10) { setGlobalError('WhatsApp inválido (mínimo 10 dígitos)'); return }
      setCurrentStep(3)
    } else if (currentStep === 3) {
      if (!selectedBlocoId || !selectedAptoId) {
        setGlobalError(`Selecione ${getNivel1Label(tipoEstrutura)} e ${getNivel2Label(tipoEstrutura)}`)
        return
      }
      if (unitLimitReached) {
        setGlobalError('Não é possível cadastrar nesta unidade. O limite de moradores aprovados foi atingido.')
        return
      }
      await submitRegistration()
    }
  }

  async function submitRegistration() {
    setLoading(true)
    setGlobalError('')
    try {
      // Get unidade_id
      const { data: unidade } = await supabase
        .from('unidades')
        .select('id')
        .eq('condominio_id', selectedCondo.id)
        .eq('bloco_id', selectedBlocoId)
        .eq('apartamento_id', selectedAptoId)
        .maybeSingle()

      if (!unidade) {
        setGlobalError('Unidade não encontrada. Tente novamente.')
        setLoading(false)
        return
      }

      // Resolve bloco/apto text
      const blocoData = blocos.find((b) => b.id === selectedBlocoId)
      const aptoData = apartamentos.find((a) => a.id === selectedAptoId)

      // 1. Create auth user
      const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
        email: email.trim().toLowerCase(),
        password,
      })
      if (signUpError) throw signUpError
      const userId = signUpData.user?.id
      if (!userId) throw new Error('Falha ao criar conta')

      // 2. Insert perfil
      const { error: perfilError } = await supabase.from('perfil').insert({
        id: userId,
        condominio_id: selectedCondo.id,
        nome_completo: nome.trim(),
        email: email.trim().toLowerCase(),
        whatsapp: whatsapp.trim(),
        whatsapp_msg_consent: consentimentoWhatsapp,
        status_aprovacao: 'pendente',
        tipo_morador: tipoUsuario,
        papel_sistema: perfilUsuario,
        bloco_txt: blocoData?.nome_ou_numero || null,
        apto_txt: aptoData?.numero || null,
      })
      if (perfilError) throw perfilError

      // 3. Link unit
      const { error: linkError } = await supabase.from('unidade_perfil').insert({
        perfil_id: userId,
        unidade_id: unidade.id,
      })
      if (linkError) throw linkError

      // 4. Auto-login
      await supabase.auth.signInWithPassword({
        email: email.trim().toLowerCase(),
        password,
      })

      // Show success / pending approval
      setShowSuccess(true)
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e)
      if (msg.includes('already') || msg.includes('duplicate')) {
        setGlobalError('Este e-mail já existe. Tente fazer login.')
      } else {
        setGlobalError(`Erro no cadastro: ${msg}`)
      }
    } finally {
      setLoading(false)
    }
  }

  const steps = [
    { label: 'Condomínio', num: 1 },
    { label: 'Conta', num: 2 },
    { label: 'Dados', num: 3 },
    { label: 'Unidade', num: 4 },
  ]

  if (showSuccess) {
    return (
      <div className="min-h-screen bg-[#f4f6f9] flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-xl w-full max-w-md p-8 text-center">
          <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <Check size={40} className="text-green-600" />
          </div>
          <h2 className="text-xl font-bold text-gray-900 mb-2">Cadastro Realizado!</h2>
          <p className="text-sm text-gray-500 mb-6">
            Seu cadastro foi enviado para aprovação do Síndico ou Administradora responsável pelo condomínio.
          </p>
          <div className="bg-gray-50 rounded-xl p-4 mb-6">
            <p className="text-xs text-gray-500">
              💡 <strong>Dica:</strong> O síndico costuma analisar solicitações em horários comerciais.
            </p>
          </div>
          <button
            onClick={() => router.push('/login')}
            className="w-full py-3 bg-[#FC5931] text-white rounded-xl font-bold text-sm hover:bg-[#D42F1D] transition-all"
          >
            Voltar ao Início
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-[#f4f6f9] flex items-center justify-center p-4">
      <div className="bg-white rounded-3xl shadow-xl w-full max-w-lg overflow-hidden">
        {/* Header */}
        <div className="bg-linear-to-r from-[#FC5931] to-[#D42F1D] px-6 py-4 flex items-center gap-3">
          <button onClick={() => currentStep > 0 ? setCurrentStep(currentStep - 1) : router.push('/login')} className="text-white hover:bg-white/20 rounded-full p-1 transition-colors" title="Voltar">
            <ChevronLeft size={22} />
          </button>
          <h1 className="text-white font-bold text-lg">Cadastro de Morador</h1>
        </div>

        {/* Stepper indicators */}
        <div className="px-6 pt-6 pb-2">
          <div className="flex gap-2">
            {steps.map((step, i) => (
              <div key={i} className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold shrink-0 transition-all ${
                    i < currentStep ? 'bg-green-500 text-white' :
                    i === currentStep ? 'bg-[#FC5931] text-white' :
                    'bg-gray-200 text-gray-400'
                  }`}>
                    {i < currentStep ? <Check size={12} /> : step.num}
                  </div>
                  <span className={`text-xs truncate ${i === currentStep ? 'text-gray-800 font-semibold' : 'text-gray-400'}`}>
                    {step.label}
                  </span>
                </div>
                <div className={`h-1 rounded-full transition-all ${
                  i < currentStep ? 'bg-green-500' :
                  i === currentStep ? 'bg-[#FC5931]' :
                  'bg-gray-200'
                }`} />
              </div>
            ))}
          </div>
        </div>

        {/* Step content */}
        <div className="px-6 py-4 min-h-[340px]">
          {/* Step 1: Condomínio */}
          {currentStep === 0 && (
            <div className="space-y-4">
              <p className="text-base font-bold text-gray-800">Qual é o seu condomínio?</p>

              {selectedCondo ? (
                <div className="flex items-center justify-between p-4 bg-[#FC5931]/10 border border-[#FC5931] rounded-xl">
                  <div className="flex items-center gap-3">
                    <Building2 size={18} className="text-[#FC5931]" />
                    <span className="font-semibold text-sm text-gray-800">{selectedCondo.nome}</span>
                  </div>
                  <button onClick={() => { setSelectedCondo(null); setBlocos([]); setApartamentos([]) }} className="text-red-500 hover:text-red-700 text-xs font-medium" title="Remover seleção">
                    ✕
                  </button>
                </div>
              ) : (
                <>
                  <div className="relative">
                    <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input
                      type="text"
                      placeholder="Digite o nome do condomínio"
                      value={searchQuery}
                      onChange={e => { setSearchQuery(e.target.value); searchCondominios(e.target.value) }}
                      className="w-full pl-10 pr-10 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
                    />
                    {isSearching && <Loader2 size={16} className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400 animate-spin" />}
                  </div>

                  {condominios.length > 0 && (
                    <div className="border border-gray-200 rounded-xl overflow-hidden max-h-60 overflow-y-auto">
                      {condominios.map(c => (
                        <button
                          key={c.id}
                          onClick={() => selectCondo(c)}
                          className="w-full text-left px-4 py-3 hover:bg-[#FC5931]/5 border-b border-gray-100 last:border-0 transition-colors"
                        >
                          <div className="flex items-center gap-3">
                            <Building2 size={16} className="text-[#FC5931] shrink-0" />
                            <div>
                              <p className="text-sm font-medium text-gray-800">{c.nome}</p>
                              <p className="text-xs text-gray-400">{c.cidade} - {c.estado}</p>
                            </div>
                          </div>
                        </button>
                      ))}
                    </div>
                  )}
                </>
              )}
            </div>
          )}

          {/* Step 2: Conta */}
          {currentStep === 1 && (
            <div className="space-y-4">
              <div>
                <label className="text-xs font-medium text-gray-500 mb-1 block">Seu melhor e-mail</label>
                <div className="relative">
