              <div>
                <label className="text-xs font-medium text-gray-500 mb-1 block">Perfil de Usuário</label>
                <select
                  value={perfilUsuario}
                  onChange={e => setPerfilUsuario(e.target.value)}
                  className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm appearance-none"
                  title="Perfil de Usuário"
                >
                  {PERFIL_USUARIO_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}
                </select>
              </div>
              <label className="flex items-start gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={consentimentoWhatsapp}
                  onChange={e => setConsentimentoWhatsapp(e.target.checked)}
                  className="w-4 h-4 mt-0.5 rounded accent-[#FC5931]"
                />
                <span className="text-xs text-gray-600">Aceito receber notificações importantes pelo WhatsApp</span>
              </label>
            </div>
          )}

          {/* Step 4: Unidade */}
          {currentStep === 3 && (
            <div className="space-y-4">
              <p className="text-base font-bold text-gray-800">Selecione onde você mora:</p>
              <div>
                <label className="text-xs font-medium text-gray-500 mb-1 block">
                  Qual seu(sua) {getNivel1Label(tipoEstrutura)}?
                </label>
                <select
                  value={selectedBlocoId}
                  onChange={e => {
                    setSelectedBlocoId(e.target.value)
                    if (e.target.value) fetchApartamentos(selectedCondo.id, e.target.value)
                  }}
                  className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm appearance-none"
                  title={getNivel1Label(tipoEstrutura)}
                >
                  <option value="">Selecionar...</option>
                  {blocos.map((b) => (
                    <option key={b.id} value={b.id}>{getNivel1Label(tipoEstrutura)} {b.nome_ou_numero}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="text-xs font-medium text-gray-500 mb-1 block">
                  Qual seu(sua) {getNivel2Label(tipoEstrutura)}?
                </label>
                <select
                  value={selectedAptoId}
                  onChange={e => {
                    setSelectedAptoId(e.target.value)
                    if (e.target.value) {
                      checkUnitLimit(selectedCondo.id, selectedBlocoId, e.target.value)
                    } else {
                      setUnitLimitReached(false)
                      setUnitLimitMsg('')
                    }
                  }}
                  disabled={!selectedBlocoId}
                  className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm appearance-none disabled:opacity-50"
                  title={getNivel2Label(tipoEstrutura)}
                >
                  <option value="">Selecionar...</option>
                  {apartamentos.map((a) => (
                    <option key={a.id} value={a.id}>{getNivel2Label(tipoEstrutura)} {a.numero}</option>
                  ))}
                </select>
              </div>

              {/* Verificando limite da unidade */}
              {isCheckingUnit && (
                <div className="flex items-center gap-2 text-xs text-gray-400 mt-2">
                  <Loader2 size={14} className="animate-spin" /> Verificando disponibilidade da unidade...
                </div>
              )}

              {/* Alerta: unidade lotada */}
              {unitLimitReached && (
                <div className="mt-3 p-4 bg-amber-50 border border-amber-300 rounded-xl flex items-start gap-3">
                  <AlertTriangle size={20} className="text-amber-500 shrink-0 mt-0.5" />
                  <div>
                    <p className="text-sm font-semibold text-amber-700 mb-1">Limite atingido</p>
                    <p className="text-xs text-amber-600">{unitLimitMsg}</p>
                  </div>
                </div>
              )}

              {!unitLimitReached && !isCheckingUnit && (
                <p className="text-xs text-gray-400 text-center mt-4">
                  Ao clicar em finalizar, seu cadastro será enviado para aprovação do Síndico ou Administradora responsável pelo condomínio.
                </p>
              )}
            </div>
          )}

          {/* Error */}
          {globalError && (
            <div className="mt-4 p-3 bg-red-50 border border-red-200 rounded-xl">
              <p className="text-red-600 text-xs text-center">{globalError}</p>
            </div>
          )}
        </div>

        {/* Footer buttons */}
        <div className="px-6 pb-6 space-y-3">
          <button
            onClick={handleNext}
            disabled={loading || (currentStep === 3 && (unitLimitReached || isCheckingUnit))}
            className="w-full py-3 bg-[#FC5931] text-white rounded-xl font-bold text-sm hover:bg-[#D42F1D] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            {loading ? (
              <><Loader2 size={16} className="animate-spin" /> Processando...</>
            ) : (
              currentStep === 3 ? 'Finalizar Cadastro' : 'Avançar'
            )}
          </button>
          {currentStep > 0 && (
            <button
              onClick={() => setCurrentStep(currentStep - 1)}
              className="w-full py-3 border-2 border-gray-200 text-gray-500 rounded-xl font-semibold text-sm hover:bg-gray-50 transition-all"
            >
              Voltar
            </button>
          )}
        </div>

        <p className="text-center text-[10px] text-gray-400 pb-4">
          Todos os direitos reservados à @2SCapital @2026
        </p>
      </div>
    </div>
  )
}

'use client'
import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter } from 'next/navigation'
import { Lock, Eye, EyeOff } from 'lucide-react'

export default function ResetPasswordPage() {
  const [newPassword, setNewPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [showNew, setShowNew] = useState(false)
  const [showConfirm, setShowConfirm] = useState(false)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState(false)
  const [sessionReady, setSessionReady] = useState(false)
  const supabase = createClient()
  const router = useRouter()

  useEffect(() => {
    // Supabase processes the hash fragment automatically when the page loads
    // We need to wait for the auth state to settle
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
      if (event === 'PASSWORD_RECOVERY') {
        setSessionReady(true)
      }
    })
    // Also check if user is already logged in (e.g. token already processed)
    supabase.auth.getUser().then(({ data: { user } }) => {
      if (user) setSessionReady(true)
    })
    return () => subscription.unsubscribe()
  }, [supabase.auth])

  async function handleReset() {
    if (newPassword.length < 4) { setError('Mínimo de 4 dígitos'); return }
    if (newPassword !== confirmPassword) { setError('As senhas não coincidem'); return }
    setLoading(true)
    setError('')
    try {
      const { error: updateError } = await supabase.auth.updateUser({ password: newPassword })
      if (updateError) throw updateError
      setSuccess(true)
      setTimeout(() => router.push('/login'), 3000)
    } catch (e) {
      setError('Erro ao redefinir senha. Tente novamente.')
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-[#f4f6f9] flex items-center justify-center p-6">
      <div className="bg-white rounded-3xl shadow-xl w-full max-w-sm p-8">
        {success ? (
          <div className="text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-3xl">✅</span>
            </div>
            <h2 className="text-xl font-bold text-gray-900 mb-2">Senha redefinida!</h2>
            <p className="text-sm text-gray-500">
              Redirecionando para o login...
            </p>
          </div>
        ) : !sessionReady ? (
          <div className="text-center">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4 animate-pulse">
              <Lock size={28} className="text-gray-400" />
            </div>
            <h2 className="text-lg font-bold text-gray-900 mb-2">Processando...</h2>
            <p className="text-sm text-gray-500">Verificando o link de redefinição.</p>
          </div>
        ) : (
          <>
            <div className="flex flex-col items-center mb-6">
              <div className="w-14 h-14 bg-[#FC5931]/10 rounded-full flex items-center justify-center mb-3">
                <Lock size={28} className="text-[#FC5931]" />
              </div>
              <h2 className="text-xl font-bold text-gray-900">Redefinir Senha</h2>
              <p className="text-sm text-gray-500 text-center mt-1">
                Crie uma nova senha numérica.
              </p>
            </div>

            <div className="space-y-3">
              <div className="relative">
                <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type={showNew ? 'text' : 'password'}
                  inputMode="numeric"
                  placeholder="Nova senha (somente números)"
                  value={newPassword}
                  onChange={e => setNewPassword(e.target.value.replace(/\D/g, ''))}
                  className="w-full pl-10 pr-11 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
                />
                <button type="button" onClick={() => setShowNew(!showNew)}
                  className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400">
                  {showNew ? <EyeOff size={16}/> : <Eye size={16}/>}
                </button>
              </div>

              <div className="relative">
                <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type={showConfirm ? 'text' : 'password'}
                  inputMode="numeric"
                  placeholder="Confirmar nova senha"
                  value={confirmPassword}
                  onChange={e => setConfirmPassword(e.target.value.replace(/\D/g, ''))}
                  onKeyDown={e => e.key === 'Enter' && handleReset()}
                  className="w-full pl-10 pr-11 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#FC5931] bg-gray-50 text-sm"
                />
                <button type="button" onClick={() => setShowConfirm(!showConfirm)}
                  className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-400">
                  {showConfirm ? <EyeOff size={16}/> : <Eye size={16}/>}
                </button>
              </div>

              {error && <p className="text-red-500 text-xs text-center">{error}</p>}

              <button
                onClick={handleReset}
                disabled={loading || !newPassword || !confirmPassword}
                className="w-full py-3 bg-[#FC5931] text-white rounded-xl font-bold text-sm hover:bg-[#D42F1D] transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {loading ? 'Salvando...' : 'Redefinir Senha'}
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { createClient } from '@/lib/supabase/client'

interface Condominio { id: string; nome: string }
interface PropagandaFoto { id: string; foto_url: string; ordem: number }
interface Propaganda {
  id: string
  condominio_id: string
  nome: string
  especialidade: string | null
  endereco: string | null
  whatsapp: string | null
  celular: string | null
  site: string | null
  email: string | null
  logo_url: string | null
  instagram: string | null
  facebook: string | null
  youtube: string | null
  tiktok: string | null
  twitter: string | null
  linkedin: string | null
  ordem: number
  ativo: boolean
  fotos?: PropagandaFoto[]
}

const EMPTY_FORM: Omit<Propaganda, 'id' | 'fotos'> = {
  condominio_id: '',
  nome: '',
  especialidade: '',
  endereco: '',
  whatsapp: '',
  celular: '',
  site: '',
  email: '',
  logo_url: '',
  instagram: '',
  facebook: '',
  youtube: '',
  tiktok: '',
  twitter: '',
  linkedin: '',
  ordem: 0,
  ativo: true,
}

export default function PropagandaClient({ condominios }: { condominios: Condominio[]; superAdminEmail: string }) {
  const supabase = createClient()
  const [selectedCondo, setSelectedCondo] = useState(condominios[0]?.id ?? '')
  const [list, setList] = useState<Propaganda[]>([])
  const [loading, setLoading] = useState(false)
  const [showForm, setShowForm] = useState(false)
  const [editing, setEditing] = useState<Propaganda | null>(null)
  const [form, setForm] = useState(EMPTY_FORM)
  const [saving, setSaving] = useState(false)
  const [uploadingLogo, setUploadingLogo] = useState(false)
  const [uploadingFoto, setUploadingFoto] = useState(false)
  const [fotos, setFotos] = useState<PropagandaFoto[]>([])
  const logoInputRef = useRef<HTMLInputElement>(null)
  const fotoInputRef = useRef<HTMLInputElement>(null)

  const loadList = async () => {
    setLoading(true)
    const { data } = await supabase
      .from('propaganda')
      .select('*, propaganda_fotos(*)')
      .eq('condominio_id', selectedCondo)
      .order('ordem')
    setList((data ?? []).map(d => ({ ...d, fotos: d.propaganda_fotos ?? [] })))
    setLoading(false)
  }

  useEffect(() => { if (selectedCondo) { ;(async () => { await loadList() })() } }, [selectedCondo])

  function openNew() {
    setEditing(null)
    setForm({ ...EMPTY_FORM, condominio_id: selectedCondo })
    setFotos([])
    setShowForm(true)
  }

  function openEdit(p: Propaganda) {
    setEditing(p)
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { fotos: _fotos, ...rest } = p
    setForm(rest)
    setFotos(p.fotos ?? [])
    setShowForm(true)
  }

  async function uploadFile(file: File, folder: string): Promise<string | null> {
    const ext = file.name.split('.').pop()
    const path = `${folder}/${Date.now()}.${ext}`
    const { error } = await supabase.storage.from('propaganda').upload(path, file, { upsert: true })
    if (error) { alert('Erro no upload: ' + error.message); return null }
    const { data } = supabase.storage.from('propaganda').getPublicUrl(path)
    return data.publicUrl
  }

  async function handleLogoUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    setUploadingLogo(true)
    const url = await uploadFile(file, 'logos')
    if (url) setForm(f => ({ ...f, logo_url: url }))
    setUploadingLogo(false)
  }

  async function handleFotoUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    setUploadingFoto(true)
    const url = await uploadFile(file, 'fotos')
    if (url) {
      if (editing) {
        // save immediately
        const { data } = await supabase.from('propaganda_fotos').insert({
          propaganda_id: editing.id, foto_url: url, ordem: fotos.length
        }).select().single()
        if (data) setFotos(f => [...f, data])
      } else {
        setFotos(f => [...f, { id: crypto.randomUUID(), foto_url: url, ordem: f.length }])
      }
    }
    setUploadingFoto(false)
  }

  async function deleteFoto(foto: PropagandaFoto) {
    if (editing) {
      await supabase.from('propaganda_fotos').delete().eq('id', foto.id)
    }
    setFotos(f => f.filter(x => x.id !== foto.id))
  }

  async function handleSave() {
    if (!form.nome.trim()) { alert('Nome é obrigatório'); return }
    setSaving(true)
    if (editing) {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { fotos: _f, ...update } = form as typeof form & { fotos?: unknown }
      await supabase.from('propaganda').update(update).eq('id', editing.id)
    } else {
      const { data: newP } = await supabase.from('propaganda').insert(form).select().single()
      if (newP && fotos.length > 0) {
        await supabase.from('propaganda_fotos').insert(
          fotos.map((f, i) => ({ propaganda_id: newP.id, foto_url: f.foto_url, ordem: i }))
        )
      }
    }
    setSaving(false)
    setShowForm(false)
    loadList()
  }

  async function handleDelete(id: string) {
    if (!confirm('Excluir este anunciante?')) return
    await supabase.from('propaganda').delete().eq('id', id)
    loadList()
  }

  async function toggleAtivo(p: Propaganda) {
    await supabase.from('propaganda').update({ ativo: !p.ativo }).eq('id', p.id)
    loadList()
  }

  const f = (k: keyof typeof form) => (e: React.ChangeEvent<HTMLInputElement>) =>
    setForm(prev => ({ ...prev, [k]: e.target.value }))

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-5xl mx-auto p-6">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">📢 Empresas Parceiras</h1>
            <p className="text-sm text-gray-500 mt-1">Gerencie os anunciantes por condomínio</p>
          </div>
          <button onClick={openNew}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium transition">
            + Novo Anunciante
          </button>
        </div>

        {/* Condomínio selector */}
        <div className="mb-6">
          <label className="block text-sm font-medium text-gray-700 mb-1">Condomínio</label>
          <select value={selectedCondo} onChange={e => setSelectedCondo(e.target.value)}
            className="border border-gray-300 rounded-lg px-3 py-2 w-72 focus:outline-none focus:ring-2 focus:ring-blue-500">
            {condominios.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
          </select>
        </div>

        {/* List */}
        {loading ? (
          <div className="text-center py-12 text-gray-400">Carregando...</div>
